insert into curriculum.course_version_graphemes (
  course_version_id,
  grapheme_id,
  romanization,
  pronunciation_hint,
  mnemonic,
  position,
  pedagogical_group_key,
  pedagogical_group_label,
  details,
  tags
)
values
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '155d0198-aac0-5a9d-a8ab-fb839ccab4f9'::uuid, 'm', 'm as in "mother"', 'ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'f9127074-00ba-5295-aac0-01022b890b89'::uuid, 'aa', 'long "aa" as in "father"', 'า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.', 'right', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '0323b564-2380-5449-aa92-cc5f6772a1a0'::uuid, 'g/k', 'hard g/k sound; final ก closes like "k"', 'ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '4cd66937-cf81-571b-ae18-6ae1055dd3ae'::uuid, 'd/t', 'd as in "dog" at the start; clipped t at the end', 'ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'ee1f3cf4-8315-510e-a613-dfc5ec42d2f5'::uuid, 'ii', 'long "ee" as in "see"', 'ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '02613447-13c2-5348-aad7-857e5e6ae103'::uuid, 'n', 'n as in "no"', 'น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553'::uuid, 'i', 'short "i" as in "sit"', 'ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '5b347f02-b891-5f29-ad35-11da91e7b87c'::uuid, 't', 't as in "stop" (unaspirated)', 'ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '50ada581-79e7-5549-a9a8-77693569d9b8'::uuid, 'l', 'l as in "love"', 'ล is ล ลิง (lor ling, monkey). Let the long lower curve be the monkey''s tail, and connect ลิง to the l sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'dddb2e02-9aa3-5dde-a2ab-25524fc96559'::uuid, 'b/p', 'b as in "bat" at the start; clipped p at the end', 'บ is บ ใบไม้ (bor bai mai, leaf). The open bowl shape can hold a leaf, and ใบไม้ gives you the b sound at the start.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '1684cb46-8524-51a4-ad84-8dd2fe3b46be'::uuid, 'ae', 'long "ae" as in the vowel of "care"', 'แ is a double left-side vowel. The two front posts tell your eye to look left first, then come back to the consonant for ae.', 'left', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '13e7c7cd-283c-5d0b-a9cc-ce5b3831e495'::uuid, 'mai ek', 'first tone mark written above the consonant', '่ is mai ek, the first tone mark. It is one small stroke above the consonant, so read it as a compact tone cue.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '76e47267-9161-5fee-a1e7-f698d88554f8'::uuid, 'r', 'r as in "run" at the start; n at the end in some words', 'ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '56d6049c-5c20-5436-a5d0-37ea5d73fe05'::uuid, 'mai tho', 'second tone mark written above the consonant', '้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '9593d6a6-13bb-563d-a33d-b01dd74e3528'::uuid, 'ch', 'ch as in "check"', 'ช is ช ช้าง (chor chaang, elephant). Picture the long dropping stroke as an elephant trunk, and use ช้าง for the ch sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'a57ca296-4754-50f0-aad0-9856fff5c81d'::uuid, 'u', 'short "u" as in "put"', 'ุ is the short u mark tucked under the consonant. Low on the page and short in sound: use it for the quick u in ชุด.', 'below', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'ae26196d-7a39-57e3-a8c4-061567bf9167'::uuid, 's', 's as in "sun"', 'ส is ส เสือ (sor suea, tiger). The pointed, striped-looking shape can cue a tiger, and เสือ starts with the crisp s sound.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad'::uuid, 'kh', 'kh with a puff of air, like the start of "khaki"', 'ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '5e1b543b-6be0-5279-a812-4ec61ce2b1dc'::uuid, 'w', 'w as in "water"; can help form vowel glides', 'ว is ว แหวน (wor waen, ring). The rounded curl looks like a ring, and แหวน gives you the w sound.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '98079396-6adf-5409-a63c-121764a3840e'::uuid, 'h', 'h as in "hello"; often used as a leading tone helper', 'ห is ห หีบ (hor hiip, chest). Picture the tall shape as a chest with a lid; in words like หมู, this h-letter can also guide the tone.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '6cbd6547-63c8-52cd-a2e5-378aa42e3e46'::uuid, 'uu', 'long "oo" as in "food"', 'ู is the long uu mark below the consonant. It is like ุ with a longer lower tail, so let the oo sound run longer.', 'below', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd6388a97-b0cb-5594-af90-48fd4c770e0f'::uuid, 'silent carrier', 'placeholder consonant used when a syllable begins with a vowel sound', 'อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'da8975d2-f60a-59f9-a1d2-f55df44b6bfa'::uuid, 'ph', 'ph with a puff of air, like the start of "photo" without the f sound', 'ผ is ผ ผึ้ง (phor phueng, bee). Picture the open shape as wings and body; ผึ้ง starts with the puffed ph sound.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '6655bad5-f432-5868-aa67-e7247253802f'::uuid, 'a', 'short "a" as in "cut"', 'ั is the short a cap above the consonant. It sits close and quick, just like the clipped a in ผัด and ผัก.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'bda65912-fa0a-5328-a7d4-302245d61c3e'::uuid, 'ng', 'ng as in "singer"; used at the start or end of a syllable', 'ง is ง งู (ngor nguu, snake). Picture the curving body of a snake; ง makes the ng sound that English only uses at the ends of words.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'cf8eaddc-cd8e-55ca-a652-237794f23e8b'::uuid, 'th', 'th with a puff of air, like the "t" in "top" (not the th in "the")', 'ท is ท ทหาร (thor thahaan, soldier). Picture a soldier standing tall; ท gives the aspirated th sound with a clear puff of air.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'e4575690-2031-5d02-a9ed-227f99686432'::uuid, 'j', 'j as in "jar", but lighter and unaspirated', 'จ is จ จาน (jor jaan, plate). Picture a round dinner plate; จ gives a light, crisp j sound.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'f4bda34e-a00e-53ac-a756-196e4fd86dcb'::uuid, 'a', 'short "a" cut off by a quick glottal stop, like a clipped "ah!"', 'ะ is the two-dot short-a written to the right of the consonant. It ends the syllable abruptly, like catching your breath after ''ah''.', 'right', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd930649b-b987-5148-a7d1-8aaabef44060'::uuid, 'e', 'long "e" as in "they"', 'เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.', 'left', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd636b36c-e319-5414-ad3e-8657562bd576'::uuid, 'ai', 'the "ai" sound as in "Thai"', 'ไ (ไม้มลาย, mai malai) is the common ai vowel, written before the consonant. Note the small flag curling off the top.', 'left', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '54ee9c51-1ccc-59bb-a95d-2e6f8d66ecf1'::uuid, 'ai', 'the same "ai" sound as ไ', 'ใ (ไม้ม้วน, mai muan) sounds identical to ไ but appears in only about 20 specific words you memorize. Note the curled-in top.', 'left', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '6450d4bf-a0e5-5f34-aaad-6b404ea92b59'::uuid, 'o', 'long "o" as in "go"', 'โ is the long-o vowel with a tall vertical stroke, written before the consonant. Like เ and ไ, read the consonant after it first.', 'left', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '1468f8a2-d91f-5127-ac8d-e40de6f54950'::uuid, 'bp', 'a tight, unaspirated p, like the p in "spin" (between English b and p)', 'ป is ป ปลา (bpor bplaa, fish). Picture a tall fish standing on its tail; ป is the unaspirated p that pairs with the dt sound of ต.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'f08f3ab4-ea11-53cf-a8b5-c3ea310041b1'::uuid, 'y', 'y as in "yes"; at the end of a syllable it forms a glide like the "y" in "boy"', 'ย is ย ยักษ์ (yor yak, giant). Picture a towering giant; ย gives the y sound at the start and a y-glide at the end.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'c40165fd-c08b-5e06-a932-28747ec7490c'::uuid, 'kh', 'kh with a puff of air, like the "c" in "cat"', 'ค is ค ควาย (khaw khwaai, buffalo). Picture a broad water buffalo; ค gives the same breathy kh as ข but belongs to the low class.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '0abef0b2-0c0d-5a3b-a853-11eddd2dd366'::uuid, 'ph', 'ph with a puff of air, like the "p" in "pin"', 'พ is พ พาน (phaw phaan, a footed offering tray). Picture the tall pedestal tray; พ gives the aspirated ph sound in the low class.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '6dcb5f4d-ee45-5907-ae15-26739f104438'::uuid, 'am', 'short "am", like the "um" in "hum"', 'ำ is sara am: a little circle rides above and a tail hooks down on the right. It always ends in an m, so you never add a separate final.', 'right', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'a9e18bf6-2166-534c-a309-cd195f0f2ddc'::uuid, 'ao', 'short "ao", like the "ow" in "cow"', 'เ leads on the left and า trails on the right, wrapping the consonant. Read the consonant first, then the ao that surrounds it.', 'around', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '2b7b4a4e-8970-5752-ac27-3975c5537981'::uuid, 's', 's as in "sun"', 'ซ is ซ โซ่ (saw sôo, a chain). Picture the links of a chain; ซ gives a plain s in the low class.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '27b2ee31-e73d-533a-adfd-5b8a76f0c39f'::uuid, 'f', 'f as in "fan"', 'ฟ is ฟ ฟัน (faw fan, teeth). Picture a row of teeth; ฟ gives a plain f in the low class.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '12f624a3-8cc9-55e5-a9c2-f3e6dd779f77'::uuid, 'th', 'th with a puff of air, like the "t" in "top"', 'ถ is ถ ถุง (thǎw thǔng, a bag). Picture a drawstring sack; ถ gives an aspirated th in the high class.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '82b5708a-99b4-5f49-a31b-973bdb32ad2f'::uuid, 'ue', 'long "ue" — say "ee" with your lips relaxed and pulled back', '◌ื is the long ue vowel; the two marks above stretch the sound. Say a long ee but unround your lips.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd380ce7e-121b-5bd7-a536-14332e4a8d91'::uuid, 'ue', 'short "ue" — a quick, clipped version of the long ◌ื', '◌ึ is the short ue; a single hook above gives one short beat of the same unrounded sound.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '4055d86a-8285-53d8-aa77-d270e4fdbe5d'::uuid, 'ia', 'the "ia" glide, like "ea" in "ear"', 'เ leads on the left, ◌ี rides above, and ย trails on the right. Together they glide from ee into a, the ia diphthong.', 'around', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'f601a10f-6f2f-5e36-a707-4bf62de8b382'::uuid, '(silent)', 'karan — it silences the consonant it sits above', '◌์ is the karan (thanthakhat). Think of it crossing out the consonant beneath it, so you do not pronounce that letter.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '7f75ad3a-91f1-533b-a0fc-74edb84c7173'::uuid, 'ua', 'the "ua" glide, like "oo-a" said quickly', '◌ั sits above the consonant and ว trails after it. Together they glide from oo into a — the ua diphthong.', 'around', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'fa5b3ce8-7853-5bec-ac17-d54c455cc2c5'::uuid, 'er', 'long "er", like "her" without the r', 'เ leads on the left and อ trails on the right, giving a long er. Before a final it shrinks into เ◌ิ◌.', 'around', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'be58124c-1745-501b-ac43-404a370ffad5'::uuid, '(tone)', 'mai tri — the third tone mark; on a mid consonant it gives a high tone', '◌๊ mai tri stacks like a small figure that tops out high. It rides mostly on mid-class letters in loan and food words, pushing the tone high.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '51e0f7f8-6987-502a-a7d2-e3e87c237050'::uuid, '(tone)', 'mai chattawa — the fourth tone mark; on a mid consonant it gives a rising tone', '◌๋ mai chattawa is the plus-shaped fourth mark. On a mid-class letter it lifts the syllable into a rising tone.', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '3938b960-b537-5dfd-a32e-04b2f7e4bf10'::uuid, '(shortener)', 'mai taikhu — it shortens the vowel and carries no sound of its own', '◌็ mai taikhu is a tiny hook that clips the vowel short, mostly on เ and แ before a final, as in เด็ก (dèk).', 'above', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '2a6e28e3-6f00-5ff3-ac11-656202db2c03'::uuid, '(repeat)', 'mai yamok — read the word before it a second time', '◌ๆ maiyamok is written after a word with a space; it means ''say that again'', so ช้าๆ is read cháa-cháa.', 'right', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'be7afb92-f599-5cbe-a66c-a6ac5a86d389'::uuid, 'aw', 'short "aw", a clipped version of เ-า', 'เ◌าะ ends in ◌ะ, the short marker. It is the quick, clipped cousin of the long aw, as in เกาะ (gàw).', 'around', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'e8d95abf-de87-5098-ad39-281eb1b15dee'::uuid, 'e', 'short "e", a clipped version of เ', 'เ◌ะ is the short e: the ◌ะ on the right clips the long เ short, as in เตะ (dtè).', 'around', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '995166e9-7e6d-5c17-acae-4e9afefd86d4'::uuid, 'ae', 'short "ae", a clipped version of แ', 'แ◌ะ is the short ae: ◌ะ shortens the long แ, as in แกะ (gàe).', 'around', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '313f81af-f95a-53f2-aa21-c5faa9818f3e'::uuid, 'o', 'short "o", a clipped version of โ', 'โ◌ะ is the short o: ◌ะ shortens the long โ, as in โต๊ะ (dtó).', 'around', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'fcb5dbae-7c0a-5974-a3c1-2523534b0b79'::uuid, '0', 'sǔun (zero)', '๐ is a small oval, like a 0. It is sǔun, zero.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '1379e866-aa33-5f4f-aa27-4714cefee8d7'::uuid, '1', 'nùeng (one)', '๑ has a single curl on top — one loop for the number one (nùeng).', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'dd70b46e-2d38-588d-a87c-9b0249a80bd8'::uuid, '2', 'sǎwng (two)', '๒ opens to the right with one belly. Watch it against ๓ — say sǎwng for two.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '1ee8a853-0b37-5712-aa79-1012c3b808a2'::uuid, '3', 'sǎam (three)', '๓ has two humps, like a rounded 3. It is sǎam, three.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'f3205fff-c7a5-54a8-a097-789e336d24f2'::uuid, '4', 'sìi (four)', '๔ curls twice and tucks under. It is sìi, four.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'df876fba-b992-5e1d-a3be-0e25119a3eef'::uuid, '5', 'hâa (five)', '๕ looks like a little cursive g. It is hâa, five.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '480ec029-9e5a-50d0-ac86-3a5d79407ea5'::uuid, '6', 'hòk (six)', '๖ has a big loop swinging up. It is hòk, six.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '97dbbd1f-f52d-5609-a416-9231ab63e6c6'::uuid, '7', 'jèt (seven)', '๗ has a tail that trails to the right. It is jèt, seven.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '53d08831-65bc-500b-acae-0dfafce8ebe8'::uuid, '8', 'bpàet (eight)', '๘ is an open curl, like a broken 8. It is bpàet, eight.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '2f93e8dd-da16-573c-a6dc-c2e6baea7c09'::uuid, '9', 'gâo (nine)', '๙ loops around like a 9. It is gâo, nine — an auspicious number in Thailand.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '54d7d08f-8ae4-5005-a2a7-d0a23aa4b3a2'::uuid, '(abbrev.)', 'paiyannoi — it marks a shortened well-known name', 'ฯ paiyannoi is an abbreviation mark: it stands in for the long tail of a formal name, as in กรุงเทพฯ.', 'right', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '25e2dc08-80ed-5b1f-a658-ee7c5905aae6'::uuid, 'ch', 'ch as in "chair", with a puff of air', 'ฉ is ฉ ฉิ่ง (chǎw chìng, small hand cymbals). Picture the tiny cymbals; ฉ is a high-class ch.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '9ae43c0f-f815-5d37-a9e8-a495d5a54892'::uuid, 'f', 'f as in "fan"', 'ฝ is ฝ ฝา (fǎw fǎa, a lid). Picture a pot lid; ฝ is a high-class f, the partner of low-class ฟ.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'cd8cb0f8-87c5-5145-ad3e-47325f6ccdba'::uuid, 'y', 'y as in "yes" at the start; an n sound as a final', 'ญ is ญ หญิง (yaw yǐng, woman). It is a low-class y at the start and an n at the end of a syllable.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'eda04af2-dea4-5629-a5a4-b26369ba3658'::uuid, 'th', 'th with a puff of air, like ท', 'ธ is ธ ธง (thaw thong, flag). Picture a flag; ธ is a low-class th, a partner of ท.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '20a68aca-32ed-5400-a1dd-28072315ba4f'::uuid, 'ph', 'ph with a puff of air, like พ', 'ภ is ภ สำเภา (phaw sǎm-phao, a junk boat). Picture the sailing junk; ภ is a low-class ph, a partner of พ.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'b72cd389-7885-5b96-a519-bf5840f42a86'::uuid, 'h', 'h as in "hat"', 'ฮ is ฮ นกฮูก (haw nók-hûuk, an owl). Picture the owl; ฮ is a low-class h, the partner of high-class ห.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '45f208ad-fa0a-5ef1-a688-45d53befa404'::uuid, 's', 's as in "sun" at the start; a t sound as a final', 'ศ is ศ ศาลา (sǎw sǎa-laa, a pavilion). It is a high-class s, common in Sanskrit-derived words.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '992ee0aa-73c0-5d68-a91c-25c3de274a95'::uuid, 's', 's at the start; a t sound as a final', 'ษ is ษ ฤๅษี (sǎw ruee-sǐi, a hermit). It is another high-class s from Sanskrit spellings.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'fbdb6ea3-ac5d-5caf-a47a-16bcca75c751'::uuid, 'n', 'n as in "no"', 'ณ is ณ เณร (naw neen, a novice monk). It is a low-class n, a formal partner of น.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '79c9bd2a-a5ce-5a56-a13a-4da3aa51a277'::uuid, 'th', 'a th sound, like ถ', 'ฐ is ฐ ฐาน (thǎw thǎan, a base/pedestal). A rare high-class th.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '91dcaa7b-ee9c-5ff6-ad11-affe2be851ee'::uuid, 'th', 'a th sound, like ท', 'ฑ is ฑ มณโฑ (thaw mon-thoo, a character''s name). A rare low-class th.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '3d206919-dbc2-52a0-a076-71a619f56cbc'::uuid, 'th', 'a th sound, like ท', 'ฒ is ฒ ผู้เฒ่า (thaw phûu-thâo, an elder). A rare low-class th.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '75317e70-ff4a-5f5f-af55-14b3f747c477'::uuid, 'd', 'a d sound, like ด', 'ฎ is ฎ ชฎา (daw chá-daa, a headdress). A rare mid-class d.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '7015572b-a896-55b4-aab6-06572b716d6a'::uuid, 'dt', 'a tight t sound, like ต', 'ฏ is ฏ ปฏัก (dtaw bpà-dtàk, a goad). A rare mid-class t.', 'standalone', null, null, '{"class":"mid"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '4c5e3966-7aee-550d-a0c3-f66233a8a045'::uuid, 'kh', 'a kh sound, like ค', 'ฆ is ฆ ระฆัง (khaw rá-khang, a bell). A rare low-class kh.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '8b7a6f67-7592-5da4-a113-b3de46bf4d04'::uuid, 'l', 'an l sound, like ล', 'ฬ is ฬ จุฬา (law jù-laa, a kite). A rare low-class l, as in กีฬา.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'b5a720ea-1ec7-5c36-ad95-1e4913ccbd3e'::uuid, 'ch', 'a ch sound, like ช', 'ฌ is ฌ เฌอ (chaw choee, a tree). A rare low-class ch.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'd1fe60d4-1647-588d-a179-af64625a3b34'::uuid, 'rue', 'read as "ri", "rue", or "rer" depending on the word', 'ฤ (sara rue) bundles an r with a vowel. Its reading is lexical: ri in อังกฤษ, rue in ฤดู. Learn it word by word.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '9eca2c85-3646-5906-ab78-b6021420ca84'::uuid, 'kh', 'obsolete high-class kh; modern Thai uses ข', 'ฃ (khǎw khùuat, bottle) is obsolete. No modern words use it — ข took its place. Recognition only.', 'standalone', null, null, '{"class":"high"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '68dc0b9d-7a4b-5ece-ad9c-9cafadbe0c14'::uuid, 'kh', 'obsolete low-class kh; modern Thai uses ค', 'ฅ (khaw khon, person) is obsolete. No modern words use it — ค took its place. Recognition only.', 'standalone', null, null, '{"class":"low"}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '81961b84-428a-54d1-ab21-a1ff5fb2590d'::uuid, 'ruee', 'archaic long form of ฤ, read "ruee"', 'ฤๅ is a rare long ฤ, seen in old literary words like ฤๅษี (ruee-sǐi, hermit). Recognition only.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'fc0403c2-5687-50cf-af07-c6812351422d'::uuid, 'lue', 'obsolete lue; modern words use ลึ', 'ฦ (lue) is obsolete. Modern words use ลึ instead (ลึก, deep). Recognition only.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'fc527aca-3764-523c-a8e3-331740672ce0'::uuid, 'luee', 'obsolete long luee; modern words use ลือ', 'ฦๅ (luee) is obsolete. Modern words use ลือ instead. Recognition only.', 'standalone', null, null, '{}'::jsonb, array[]::text[]),
  ('92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, '45c40f8f-fced-5ca7-a994-9805ac723344'::uuid, '(lengthener)', 'lakkhangyao — lengthens ฤ or ฦ only; not a sound on its own', 'ๅ (lakkhangyao) only stretches ฤ or ฦ into their long forms. It is never a sound by itself.', 'right', null, null, '{}'::jsonb, array[]::text[]);

insert into curriculum.tips (
  id,
  course_version_id,
  key,
  title,
  body,
  display,
  sections,
  metadata,
  created_at
)
values
  ('32886e36-2a9f-527e-a390-d7b1f4af98a8'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'sound-romanization', 'Romanization', 'This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('03ce635f-04a2-5bf9-a778-bfdb1e47f142'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'pronunciation-by-position', 'Sound changes by position', 'Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('8c88971c-0b65-50b9-aef3-15a3a67a6231'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'consonant-class-tones', 'Consonant class & tone', 'Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.', 'modal', '[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('775872e7-e41b-58b3-a76c-891615eb8c51'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'letter-type-vowel', 'Vowel', 'Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('735caac2-4569-5f75-a419-a391fbce94e3'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'letter-type-tone-mark', 'Tone mark', 'Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('cc05fef4-edd2-5152-ae1b-11d7a9ca3b3c'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'letter-type-numeral', 'Thai numeral', 'Thai has its own set of digits (๐–๙) that work exactly like 0–9. You''ll still see Arabic numerals everywhere in Thailand, but Thai numerals appear on signs, prices, documents, and license plates, so it''s worth being able to read both.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('b02b5a9b-cb9e-5c1f-a398-122a917eb968'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'letter-type-mark', 'Written mark', 'This is a written symbol that isn''t a consonant, vowel, or tone mark. Thai uses a few of these — for example ๆ repeats the preceding word, and ์ silences the consonant it sits above. Each one changes how you read the syllable rather than adding a sound of its own.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz),
  ('012f7a10-4d51-547b-a575-429ba601b104'::uuid, '92c6b63e-6aab-5f26-af3d-30738bdaaf37'::uuid, 'vowel-position', 'Vowel position', 'Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position.', 'popover', '[]'::jsonb, '{}'::jsonb, '2026-04-30T00:00:00+00:00'::timestamptz);

