  ('5a17f704-8e6f-5e05-a52f-4edf3bd1a7cf'::uuid, '2c8c4d23-e143-50fe-ad2f-9839f946df1d'::uuid, 'practice_core', 8, false, '{"sourceType":"real"}'::jsonb),
  ('5a17f704-8e6f-5e05-a52f-4edf3bd1a7cf'::uuid, '5aa66285-91ee-5dfa-a589-cfd07ecfd896'::uuid, 'practice_core', 9, false, '{"sourceType":"phrase"}'::jsonb),
