  ('2b08fe9f-7330-561e-a49c-f0e155dbdd71'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'b248fb0f-5294-57b4-af76-9938cb3f905c'::uuid, 'maak', 1, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"b248fb0f-5294-57b4-af76-9938cb3f905c","slug":"maak","lessonOrdinal":1,"stage":1,"title":"มาก — Your First High-Payoff Word","anchor":{"id":"1369806e-4ea8-5225-af4b-53d528e72fd4","slug":"maak","text":"มาก","meaning":"very / a lot","pronunciation":"mâak","categoryKey":"daily","contextNote":"You''ll hear and read มาก everywhere: ดีมาก (very good), เผ็ดมาก (very spicy), and discount copy that promises a lot.","segments":[{"text":"มา","sound":"maa"},{"text":"ก","sound":"k"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"c3faa381-054e-5dd0-a64b-fe084d0afe2e","key":"word-0e21-0e32","text":"มา","meaning":"to come","pronunciation":"maa","categoryKey":"daily","contextNote":"A basic movement verb you will hear in invitations, directions, and casual conversation.","segments":[{"text":"มา","sound":"maa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"c8d1b913-736c-5dcd-a387-f779532f980e","key":"word-0e01-0e32","text":"กา","meaning":"crow / kettle / mark","pronunciation":"gaa","categoryKey":"daily","contextNote":"A compact real word that reuses the same long-aa frame with no extra letters added.","segments":[{"text":"กา","sound":"gaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"ce562b04-9b18-5992-ac11-bfbbfe9c6ab9","key":"word-0e01-0e32-0e21","text":"กาม","meaning":"sensuality","pronunciation":"gaam","categoryKey":"daily","contextNote":"A low-frequency but fully decodable real word that stretches the same letters into a longer frame.","segments":[{"text":"กาม","sound":"gaam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"d548bc58-bb46-5e64-a208-ccd84400c5b7","key":"word-0e01-0e32-0e01","text":"กาก","meaning":"residue / trashy (casual)","pronunciation":"gaak","categoryKey":"daily","contextNote":"A real word that also appears as casual slang online, so it is useful to recognize even if it is not polite.","segments":[{"text":"กาก","sound":"gaak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"59e269c1-c70f-5386-a188-a27539cb7200","key":"word-0e01-0e01","text":"กก","meaning":"reeds; to cuddle","pronunciation":"kok","categoryKey":"daily","contextNote":"This one introduces the implied short o pattern with a real dictionary word.","segments":[{"text":"กก","sound":"kok"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"a36c5e2f-f7a0-5279-ad05-2f091cdd2599","key":"word-0e01-0e32-0e01-0e21-0e32-0e01","text":"กากมาก","meaning":"really trashy (casual)","pronunciation":"gaak maak","categoryKey":"daily","contextNote":"A common casual online insult. Useful to recognize, but definitely not polite speech.","segments":[{"text":"กาก","sound":"gaak"},{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"4649ff70-39c9-51f7-ac15-b691cdd2d207","key":"word-0e21-0e32-0e21-0e32-0e01","text":"มามาก","meaning":"comes a lot / heavy","pronunciation":"maa maak","categoryKey":"daily","contextNote":"A short everyday phrase built from the same two visible chunks repeating back to back.","segments":[{"text":"มา","sound":"maa"},{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"a4b9c143-87d1-599b-abbd-43b9cbc80c1f","key":"word-0e01-0e32-0e21-0e32","text":"กามา","meaning":"sensual matters","pronunciation":"gaa maa","categoryKey":"daily","contextNote":"A formal compound that is low-frequency but cleanly decodable from this lesson alone.","segments":[{"text":"กา","sound":"gaa"},{"text":"มา","sound":"maa"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"526be089-819d-5e6c-a5fe-ce4902853d6d","key":"word-0e01-0e21","text":"กม","meaning":"sound-only practice","pronunciation":"gom","categoryKey":"daily","contextNote":"This one is here just to train the implied short o pattern. It is not a normal dictionary word.","segments":[{"text":"กม","sound":"gom"}],"metadata":{"sourceType":"nonsense"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"0b391f90-a689-532b-a60e-0800fedec9f8","key":"word-0e21-0e01","text":"มก","meaning":"sound-only practice","pronunciation":"mok","categoryKey":"daily","contextNote":"A second sound-only target so you can rehearse the same hidden-vowel move from the other direction.","segments":[{"text":"มก","sound":"mok"}],"metadata":{"sourceType":"nonsense"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[],"rules":[{"id":"671ddf5e-f429-5a7b-a9a1-f88d61020189","key":"long-aa-right","name":"Long า Stretches Right","shortDescription":"า is written after the consonant and gives you a long aa sound","explanation":"Thai often places vowels around a consonant instead of in a straight line like English. The long vowel า sits to the right of the consonant and stretches the syllable into a clear aa sound.","examples":[{"text":"มาก = mâak"},{"text":"ตา = taa"}]},{"id":"884e5d37-78f3-5c0d-abda-be4ea9b3b8a5","key":"final-k-stop","name":"Final ก Ends in a Stop","shortDescription":"At the end of a syllable, ก closes sharply as a k sound","explanation":"Thai final consonants are often clipped. In มาก, the last ก does not open into a full English g. It closes the syllable with a short unreleased k sound.","examples":[{"text":"มาก = mâak"}]},{"id":"4438b9e5-0dad-5fb9-a65e-f29a4cc6a62a","key":"implied-short-o","name":"Two Bare Consonants Often Add a Short \"o\"","shortDescription":"When Thai stacks two consonants with no written vowel, a short o often appears between them","explanation":"Once you know a few consonants, you can read more than long-vowel forms. In many short Thai syllables, two consonants written together with no vowel sign are read with an implied short o sound between them.","examples":[{"text":"นก = nok"},{"text":"รถ = rot"}]}],"drills":[{"id":"b0af3b43-477d-5797-a482-fc941bb4fbbb","key":"maak-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"m\" sound?","payload":{},"options":[{"text":"ก"},{"text":"ม","isCorrect":true},{"text":"น"},{"text":"ด"}]},{"id":"a0aec10d-b933-52ac-ae60-d65d2f0db0a4","key":"maak-drill-02-recognize","type":"recognize","prompt":"Which symbol makes the long \"aa\" sound?","payload":{},"options":[{"text":"า","isCorrect":true},{"text":"ิ"},{"text":"ี"},{"text":"ั"}]},{"id":"b5470778-c016-50d4-a379-30ba09788aae","key":"maak-drill-03-match","type":"match","prompt":"What does มาก mean?","payload":{},"options":[{"text":"mother"},{"text":"very / a lot","isCorrect":true},{"text":"shop"},{"text":"rice"}]},{"id":"d6132d4b-1e57-5b24-a79c-d02969f8deab","key":"maak-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"very / a lot\"?","payload":{},"options":[{"text":"มาก","isCorrect":true},{"text":"กาม"},{"text":"มกา"},{"text":"ดาก"}]},{"id":"cb5ae9af-f16f-5910-a61b-6723a6b8426c","key":"maak-drill-05-sound","type":"sound","prompt":"How does the final ก sound in มาก?","payload":{},"options":[{"text":"m"},{"text":"k","isCorrect":true},{"text":"g"},{"text":"n"}]},{"id":"15c40127-56bf-5ed3-ab07-b320a84892c8","key":"maak-drill-06-sound","type":"sound","prompt":"If two consonants appear together with no written vowel, what sound often shows up between them?","payload":{},"options":[{"text":"long \"aa\""},{"text":"long \"ee\""},{"text":"short \"o\"","isCorrect":true},{"text":"long \"oo\""}]}]}}'::jsonb, '3097d392abd5a979e365619a4bc747126d99aa921fb559222b45bf61b2c5e528', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('2858cfe0-23c6-5ef7-ab75-58205949476e'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '4497309f-83d5-5cfd-ae20-98d182c44e7a'::uuid, 'dii', 2, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"4497309f-83d5-5cfd-ae20-98d182c44e7a","slug":"dii","lessonOrdinal":2,"stage":1,"title":"ดี — A Core Word for Good Things","anchor":{"id":"134aa101-deb6-53f4-ab45-73b08ff1f542","slug":"dii","text":"ดี","meaning":"good","pronunciation":"dii","categoryKey":"daily","contextNote":"You''ll see ดี inside greetings, reviews, and product copy. It is one of the most reusable positive words in beginner Thai.","segments":[{"text":"ดี","sound":"dii"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"da9766d5-9cc7-5389-a981-8f9306e6b805","key":"word-0e14-0e35-0e14","text":"ดีด","meaning":"to flick / pluck","pronunciation":"diit","categoryKey":"daily","segments":[{"text":"ดีด","sound":"diit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"d0ef507d-f79d-5a6e-af15-15389b449c25","key":"word-0e21-0e35","text":"มี","meaning":"to have","pronunciation":"mii","categoryKey":"daily","segments":[{"text":"มี","sound":"mii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"2fb0d7d0-e813-5ed3-a01c-11e7b9cb22cd","key":"word-0e21-0e35-0e14","text":"มีด","meaning":"knife","pronunciation":"miit","categoryKey":"food","segments":[{"text":"มีด","sound":"miit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"f932c1d2-de4f-5a71-a5c9-aa0acbd6f665","key":"word-0e14-0e35-0e21-0e32-0e01","text":"ดีมาก","meaning":"very good","pronunciation":"dii maak","categoryKey":"daily","segments":[{"text":"ดี","sound":"dii"},{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"c3faa381-054e-5dd0-a64b-fe084d0afe2e","key":"word-0e21-0e32","text":"มา","meaning":"to come","pronunciation":"maa","categoryKey":"daily","segments":[{"text":"มา","sound":"maa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"ed1aa82b-1c19-59de-ad16-fcc1669fd68b","key":"word-0e21-0e32-0e01","text":"มาก","meaning":"very / a lot","pronunciation":"maak","categoryKey":"daily","segments":[{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"c8d1b913-736c-5dcd-a387-f779532f980e","key":"word-0e01-0e32","text":"กา","meaning":"crow / kettle / mark","pronunciation":"gaa","categoryKey":"daily","segments":[{"text":"กา","sound":"gaa"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"08d94ec2-a20e-5de1-a856-70fd4d44ffe2","key":"long-ii-above","name":"Long ี Sits Above","shortDescription":"ี is written above the consonant and gives you a long ee sound","explanation":"Thai vowels are often placed above, below, or around the consonant. In ดี, the consonant comes first and the long vowel ี sits above it, so you read ด then stretch into ee.","examples":[{"text":"ดี = dii"},{"text":"สี = sii"}]},{"id":"6d95fd8f-f8f2-57a9-a0e0-6895baa2f935","key":"initial-d-sound","name":"Initial ด Starts Cleanly","shortDescription":"At the start of a syllable, ด gives you a plain d sound","explanation":"Thai consonants can behave differently at the start and the end of a syllable. In ดี, ด is initial, so you read it as a straightforward d sound before the vowel.","examples":[{"text":"ดี = dii"},{"text":"ดา = daa"}]}],"drills":[{"id":"e8605038-8125-5bf0-a42d-a92a76a6065d","key":"dii-drill-01-recognize","type":"recognize","prompt":"Which letter starts with the \"d\" sound?","payload":{},"options":[{"text":"ก"},{"text":"ด","isCorrect":true},{"text":"ม"},{"text":"น"}]},{"id":"c511cbcf-61d9-5c02-a71c-24ca1cfd5e33","key":"dii-drill-02-recognize","type":"recognize","prompt":"Which vowel gives the long \"ee\" sound?","payload":{},"options":[{"text":"ี","isCorrect":true},{"text":"า"},{"text":"ิ"},{"text":"ั"}]},{"id":"44769f12-1ed6-5a6d-afa4-1279fd796379","key":"dii-drill-03-match","type":"match","prompt":"What does ดี mean?","payload":{},"options":[{"text":"good","isCorrect":true},{"text":"road"},{"text":"eat"},{"text":"shop"}]},{"id":"0917c93d-dc41-5020-af12-5b2ec5e09d5d","key":"dii-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"good\"?","payload":{},"options":[{"text":"ดี","isCorrect":true},{"text":"ดิ"},{"text":"ดา"},{"text":"มี"}]},{"id":"a33c2908-8601-5a15-aa02-1d63eeadeb59","key":"dii-drill-05-sound","type":"sound","prompt":"In ดี, where is the vowel written?","payload":{},"options":[{"text":"before the consonant"},{"text":"after the consonant"},{"text":"above the consonant","isCorrect":true},{"text":"below the consonant"}]}]}}'::jsonb, '97bb35216e44032a0e87315ebe15c1fa7f3bd0df055db8082867c84ad92be08e', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('9fd4f5c2-b819-551c-ad9a-c00d4ba7b65d'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '3be425cd-ea3e-5f8a-ab88-b1efae8eb80f'::uuid, 'gin', 3, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"3be425cd-ea3e-5f8a-ab88-b1efae8eb80f","slug":"gin","lessonOrdinal":3,"stage":1,"title":"กิน — The Everyday Food Verb","anchor":{"id":"9aa0d234-007d-5705-abe6-013ec5322296","slug":"gin","text":"กิน","meaning":"to eat","pronunciation":"gin","categoryKey":"food","contextNote":"กิน appears everywhere in daily life, from restaurant invitations to questions about what you want to eat.","segments":[{"text":"กิ","sound":"gi"},{"text":"น","sound":"n"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"d7782977-ee79-5e00-ae86-265f4b4e9034","key":"word-0e19-0e34-0e14","text":"นิด","meaning":"a little bit","pronunciation":"nit","categoryKey":"daily","segments":[{"text":"นิด","sound":"nit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"142df77a-2c8f-5948-af3f-26e5778ff982","key":"word-0e14-0e34-0e19","text":"ดิน","meaning":"soil / earth","pronunciation":"din","categoryKey":"daily","segments":[{"text":"ดิน","sound":"din"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"86538398-e5ca-5917-a618-e7586d124894","key":"word-0e19-0e32","text":"นา","meaning":"rice field","pronunciation":"naa","categoryKey":"place","segments":[{"text":"นา","sound":"naa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"d23e29b9-adb5-5ff0-a665-1a2096af5bc1","key":"word-0e19-0e32-0e21","text":"นาม","meaning":"name / noun","pronunciation":"naam","categoryKey":"sign","segments":[{"text":"นาม","sound":"naam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"d0ef507d-f79d-5a6e-af15-15389b449c25","key":"word-0e21-0e35","text":"มี","meaning":"to have","pronunciation":"mii","categoryKey":"daily","segments":[{"text":"มี","sound":"mii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"c321b707-4346-5fb4-a2ec-ef4ae570730a","key":"word-0e14-0e35","text":"ดี","meaning":"good","pronunciation":"dii","categoryKey":"daily","segments":[{"text":"ดี","sound":"dii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"2fb0d7d0-e813-5ed3-a01c-11e7b9cb22cd","key":"word-0e21-0e35-0e14","text":"มีด","meaning":"knife","pronunciation":"miit","categoryKey":"food","segments":[{"text":"มีด","sound":"miit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"ed1aa82b-1c19-59de-ad16-fcc1669fd68b","key":"word-0e21-0e32-0e01","text":"มาก","meaning":"very / a lot","pronunciation":"maak","categoryKey":"daily","segments":[{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"90dd223e-c255-5285-a129-360e6205288e","key":"short-i-above","name":"Short ิ Sits Above","shortDescription":"The short i vowel appears above the consonant you read first","explanation":"Thai often asks you to scan above the line as you read. In กิน, the consonant ก comes first and the short vowel ิ is written above it, giving you gi before the final consonant closes the syllable.","examples":[{"text":"กิน = gin"},{"text":"บิน = bin"}]},{"id":"23dac35f-4b61-566e-a6f9-3ba53bd27a9d","key":"final-n-stays-n","name":"Final น Stays N","shortDescription":"At the end of a syllable, น keeps a clear n sound","explanation":"Not every Thai final consonant gets clipped into a stop. Final น stays nasal and easy to hear, so กิน closes with a clear n sound.","examples":[{"text":"กิน = gin"},{"text":"บิน = bin"}]}],"drills":[{"id":"039886d4-14ad-5d4d-a3b4-b8b5dcacec12","key":"gin-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"n\" sound?","payload":{},"options":[{"text":"ก"},{"text":"น","isCorrect":true},{"text":"ด"},{"text":"ม"}]},{"id":"972fb085-b457-5749-a79c-437d4a4536ec","key":"gin-drill-02-recognize","type":"recognize","prompt":"Which vowel gives the short \"i\" sound?","payload":{},"options":[{"text":"ิ","isCorrect":true},{"text":"ี"},{"text":"า"},{"text":"ั"}]},{"id":"7a6c6175-e8ba-5554-adc7-26bebbdd137e","key":"gin-drill-03-match","type":"match","prompt":"What does กิน mean?","payload":{},"options":[{"text":"to eat","isCorrect":true},{"text":"market"},{"text":"ten"},{"text":"fresh"}]},{"id":"9e64189d-5baf-5d61-a29d-2f09f206301d","key":"gin-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"to eat\"?","payload":{},"options":[{"text":"กิน","isCorrect":true},{"text":"กีน"},{"text":"นิก"},{"text":"มิน"}]},{"id":"266b3b73-cd8c-59fc-a698-3e9422669870","key":"gin-drill-05-sound","type":"sound","prompt":"How do you read the end of กิน?","payload":{},"options":[{"text":"gii"},{"text":"gin","isCorrect":true},{"text":"git"},{"text":"gim"}]}]}}'::jsonb, '3902de7bf524dde8066ee239a5918caa843e1e825101364708f4b75e15c01057', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('aa04e55f-f9d0-5f1c-aa13-4dfdf4170fc0'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '4de66997-87a5-56cb-a66f-7b2cce6228ed'::uuid, 'talat', 4, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"4de66997-87a5-56cb-a66f-7b2cce6228ed","slug":"talat","lessonOrdinal":4,"stage":2,"title":"ตลาด — Read the Market Sign","anchor":{"id":"e2ffdcfe-2699-53cb-aa90-ef775738a0b3","slug":"talat","text":"ตลาด","meaning":"market","pronunciation":"tà-làat","categoryKey":"place","contextNote":"Markets are everywhere in Thailand. You''ll see ตลาด on signs for night markets, floating markets, and neighborhood markets.","segments":[{"text":"ตล","sound":"tà-l"},{"text":"า","sound":"aa"},{"text":"ด","sound":"t"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"85fd9b41-dc44-5bee-a89e-eba19102c6fe","key":"word-0e15-0e25-0e01","text":"ตลก","meaning":"funny","pronunciation":"dta-lok","categoryKey":"daily","segments":[{"text":"ตะ","sound":"dta"},{"text":"ลก","sound":"lok"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"d512d636-b40f-5d24-acc3-1e7a586086fc","key":"word-0e15-0e32-0e25","text":"ตาล","meaning":"sugar palm","pronunciation":"dtaan","categoryKey":"daily","segments":[{"text":"ตาล","sound":"dtaan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"ce9a0864-6fa5-5db8-aa3f-620547a527ab","key":"word-0e15-0e32","text":"ตา","meaning":"eye","pronunciation":"dtaa","categoryKey":"daily","segments":[{"text":"ตา","sound":"dtaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"f52a4423-3825-5d2f-a688-dd7536f28b92","key":"word-0e25-0e32","text":"ลา","meaning":"to leave","pronunciation":"laa","categoryKey":"daily","segments":[{"text":"ลา","sound":"laa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"b95dc95e-c0a9-5d38-a6a4-2b85377bed24","key":"word-0e15-0e35","text":"ตี","meaning":"to hit","pronunciation":"dtii","categoryKey":"daily","segments":[{"text":"ตี","sound":"dtii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"8bb882a2-df23-530c-ac76-254c1ece38f1","key":"word-0e15-0e32-0e21","text":"ตาม","meaning":"to follow","pronunciation":"dtaam","categoryKey":"daily","segments":[{"text":"ตาม","sound":"dtaam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"5bd76382-990f-518b-a22d-2c2d1a9b68f5","key":"word-0e25-0e21","text":"ลม","meaning":"wind / air","pronunciation":"lom","categoryKey":"daily","segments":[{"text":"ลม","sound":"lom"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"6f963964-1641-57fc-a3f1-b1e43e5bc3fa","key":"word-0e25-0e14","text":"ลด","meaning":"to reduce","pronunciation":"lot","categoryKey":"sign","segments":[{"text":"ลด","sound":"lot"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"b1e8228c-b6a4-54d2-a459-0b207dc222b1","key":"word-0e15-0e01","text":"ตก","meaning":"to fall","pronunciation":"dtok","categoryKey":"daily","segments":[{"text":"ตก","sound":"dtok"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"3237ade6-2a5b-50e9-a5c7-37cbdf3d442d","key":"word-0e21-0e14","text":"มด","meaning":"ant","pronunciation":"mot","categoryKey":"daily","segments":[{"text":"มด","sound":"mot"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"50ada581-79e7-5549-a9a8-77693569d9b8","text":"ล","kind":"consonant","romanization":"l","pronunciationHint":"l as in \"love\"","mnemonic":"ล is ล ลิง (lor ling, monkey). Let the long lower curve be the monkey''s tail, and connect ลิง to the l sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"b87f5a0a-c8ed-581b-a6ec-928cce42fde3","key":"hidden-vowel-market","name":"Hidden Short \"a\" Vowel","shortDescription":"When two consonants can''t blend, a short \"a\" hides between them","explanation":"In Thai, when two consonants appear next to each other but can''t form a natural cluster, a short \"a\" sound is inserted between them. In ตลาด, the ต and ล can''t blend, so you say \"tà-làat\" not \"tlàat\". This hidden vowel is never written.","examples":[{"text":"ตล = tà-l (hidden \"a\" between ต and ล)"},{"text":"ถนน = thà-nǒn (hidden \"a\" between ถ and น)"}]},{"id":"06f3f841-d7df-5644-a11e-3c5cdebae18c","key":"final-stop-market","name":"Final Consonants are Stopped","shortDescription":"Consonants at the end of a syllable are \"swallowed\"","explanation":"When ด appears at the end of a word, it doesn''t make a full \"d\" sound. Instead, your tongue touches the roof of your mouth but you don''t release it. This is why ตลาด sounds like \"tà-làat\" and not \"tà-làad\".","examples":[{"text":"ตลาด = tà-làat"},{"text":"หมด = mòt"}]}],"drills":[{"id":"02ce9efb-92b9-5876-aef7-7cab864cfe66","key":"talat-drill-01-recognize","type":"recognize","prompt":"Which letter makes the plain \"t\" sound?","payload":{},"options":[{"text":"ถ"},{"text":"ต","isCorrect":true},{"text":"ด"},{"text":"ล"}]},{"id":"8692dc1d-2f3e-5efd-a5d4-b0019e801fa2","key":"talat-drill-02-recognize","type":"recognize","prompt":"Which letter makes the \"l\" sound?","payload":{},"options":[{"text":"ม"},{"text":"น"},{"text":"ล","isCorrect":true},{"text":"ก"}]},{"id":"0ef86fb7-0bfe-50c2-a601-f21c887e9815","key":"talat-drill-03-match","type":"match","prompt":"What does ตลาด mean?","payload":{},"options":[{"text":"road"},{"text":"market","isCorrect":true},{"text":"mother"},{"text":"airport"}]},{"id":"98fee299-f831-5c87-ae8f-1432c5119075","key":"talat-drill-04-sound","type":"sound","prompt":"Why is there an \"a\" between ต and ล in ตลาด?","payload":{},"options":[{"text":"Because it is written but invisible"},{"text":"Because Thai inserts a short \"a\" when the consonants do not blend naturally","isCorrect":true},{"text":"Because the tone mark creates it"},{"text":"Because ล always starts with a vowel"}]},{"id":"67fb27d1-1746-5a08-aec8-8dac1b69edad","key":"talat-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"market\"?","payload":{},"options":[{"text":"ตลาด","isCorrect":true},{"text":"ตาลด"},{"text":"ลาดต"},{"text":"ดาลต"}]}]}}'::jsonb, '118696478ec4e2d0aa3c765967e8135cfc195f830c1a54eb761e837fb1735881', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('4cd0ebf5-d946-51b1-af06-0011cef5d048'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '0afff15b-0b20-53d3-ae86-21d3fe37de52'::uuid, 'bin', 5, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"0afff15b-0b20-53d3-ae86-21d3fe37de52","slug":"bin","lessonOrdinal":5,"stage":2,"title":"บิน — Reuse the -ิน Pattern","anchor":{"id":"689621ae-0664-5f67-abdf-69572aa9cd01","slug":"bin","text":"บิน","meaning":"to fly","pronunciation":"bin","categoryKey":"transport","contextNote":"บิน appears in airport language, travel offers, and casual talk about planes and trips. It also helps you see how reusable the -ิน frame is.","segments":[{"text":"บิ","sound":"bi"},{"text":"น","sound":"n"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"0cdff46d-d2ce-57e2-ae77-8a5e3d6dbf7a","key":"word-0e01-0e1a","text":"กบ","meaning":"frog","pronunciation":"gop","categoryKey":"daily","segments":[{"text":"กบ","sound":"gop"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"9097f5cb-6e39-542d-ab00-4606cacae615","key":"word-0e25-0e32-0e1a","text":"ลาบ","meaning":"laab salad","pronunciation":"laap","categoryKey":"food","segments":[{"text":"ลาบ","sound":"laap"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"26d4022b-01d5-5d00-ae7b-c10243eebf3b","key":"word-0e14-0e34-0e1a","text":"ดิบ","meaning":"raw / unripe","pronunciation":"dip","categoryKey":"food","segments":[{"text":"ดิบ","sound":"dip"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"82cad9f2-05d2-56aa-a194-fa4c6dfe85ff","key":"word-0e1a-0e35-0e1a","text":"บีบ","meaning":"to squeeze","pronunciation":"biip","categoryKey":"daily","segments":[{"text":"บีบ","sound":"biip"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"43928d42-5009-56d4-aeaf-c3d01a2bffd0","key":"word-0e1a-0e32-0e19","text":"บาน","meaning":"to bloom / open out","pronunciation":"baan","categoryKey":"daily","segments":[{"text":"บาน","sound":"baan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"b64d7172-1785-5bf4-aba4-37cc44d18d39","key":"word-0e1a-0e14","text":"บด","meaning":"to grind","pronunciation":"bot","categoryKey":"food","segments":[{"text":"บด","sound":"bot"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"80361b23-0c1c-5fea-a406-7c820e2c35c5","key":"word-0e1a-0e34-0e14-0e32","text":"บิดา","meaning":"father (formal)","pronunciation":"bi-daa","categoryKey":"sign","segments":[{"text":"บิ","sound":"bi"},{"text":"ดา","sound":"daa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"f1c203bb-50b5-5872-a1b8-40cdaae0eb02","key":"word-0e15-0e25-0e32-0e14","text":"ตลาด","meaning":"market","pronunciation":"dta-laat","categoryKey":"place","segments":[{"text":"ตะ","sound":"dta"},{"text":"ลาด","sound":"laat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"85fd9b41-dc44-5bee-a89e-eba19102c6fe","key":"word-0e15-0e25-0e01","text":"ตลก","meaning":"funny","pronunciation":"dta-lok","categoryKey":"daily","segments":[{"text":"ตะ","sound":"dta"},{"text":"ลก","sound":"lok"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"c1a868cf-2bdf-5f27-acd2-86fa5162beb3","key":"word-0e01-0e34-0e19","text":"กิน","meaning":"to eat","pronunciation":"gin","categoryKey":"food","segments":[{"text":"กิน","sound":"gin"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"c321b707-4346-5fb4-a2ec-ef4ae570730a","key":"word-0e14-0e35","text":"ดี","meaning":"good","pronunciation":"dii","categoryKey":"daily","segments":[{"text":"ดี","sound":"dii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"6f963964-1641-57fc-a3f1-b1e43e5bc3fa","key":"word-0e25-0e14","text":"ลด","meaning":"to reduce","pronunciation":"lot","categoryKey":"sign","segments":[{"text":"ลด","sound":"lot"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"dddb2e02-9aa3-5dde-a2ab-25524fc96559","text":"บ","kind":"consonant","romanization":"b/p","pronunciationHint":"b as in \"bat\" at the start; clipped p at the end","mnemonic":"บ is บ ใบไม้ (bor bai mai, leaf). The open bowl shape can hold a leaf, and ใบไม้ gives you the b sound at the start.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"50ada581-79e7-5549-a9a8-77693569d9b8","text":"ล","kind":"consonant","romanization":"l","pronunciationHint":"l as in \"love\"","mnemonic":"ล is ล ลิง (lor ling, monkey). Let the long lower curve be the monkey''s tail, and connect ลิง to the l sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"6346557e-a6a4-5dac-adcd-4617cd7f09a1","key":"initial-b-sound","name":"Initial บ Starts With B","shortDescription":"At the start of a syllable, บ gives you a plain b sound","explanation":"Thai consonants often shift between initial and final positions. In บิน, บ comes first, so it sounds like a clean b before the short vowel and final consonant close the word.","examples":[{"text":"บิน = bin"},{"text":"บา = baa"}]},{"id":"30f160d3-cbb7-5e8f-ae64-9be8c99ff663","key":"in-frame-pattern","name":"The -ิน Frame Repeats","shortDescription":"Once you know a syllable frame, swapping the first consonant unlocks more words","explanation":"กิน, บิน, and similar short words share the same short-i plus final-น frame. Thai gets much easier once you start seeing these reusable patterns instead of single isolated words.","examples":[{"text":"กิน = gin"},{"text":"บิน = bin"},{"text":"ดิน = din"}]}],"drills":[{"id":"52738597-5de3-55d7-a39c-34c088805b8d","key":"bin-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"b\" sound at the start?","payload":{},"options":[{"text":"บ","isCorrect":true},{"text":"ด"},{"text":"ม"},{"text":"น"}]},{"id":"524e2383-96d9-5f31-a5c1-4e4d5ae62344","key":"bin-drill-02-match","type":"match","prompt":"What does บิน mean?","payload":{},"options":[{"text":"to fly","isCorrect":true},{"text":"to eat"},{"text":"market"},{"text":"rice"}]},{"id":"2db2aeae-50e6-5409-ac53-a294a0bdec82","key":"bin-drill-03-spot","type":"spot","prompt":"Which Thai spelling means \"to fly\"?","payload":{},"options":[{"text":"บิน","isCorrect":true},{"text":"นบิ"},{"text":"บีน"},{"text":"ดิน"}]},{"id":"7946c7ee-41fe-5b34-acf3-07bd08891c89","key":"bin-drill-04-sound","type":"sound","prompt":"Which word keeps the same -ิน pattern as บิน?","payload":{},"options":[{"text":"กิน","isCorrect":true},{"text":"มาก"},{"text":"แม่"},{"text":"ร้าน"}]},{"id":"349b3282-167a-5e03-ac9d-dc39ff2c806f","key":"bin-drill-05-sound","type":"sound","prompt":"How do you pronounce บิน?","payload":{},"options":[{"text":"bin","isCorrect":true},{"text":"baan"},{"text":"boon"},{"text":"bii"}]}]}}'::jsonb, '72565a5c5ab5c262cc3b079b58d43dc5976abfd9e4e7cf9f844f5d2c7b1c62ae', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('03d24173-40f9-5857-a0f1-59c06a1edb43'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'dc5e9698-631e-5ce9-a0da-6c7fb1abd338'::uuid, 'maae', 6, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"dc5e9698-631e-5ce9-a0da-6c7fb1abd338","slug":"maae","lessonOrdinal":6,"stage":3,"title":"แม่ — Before Vowels and First Tone Marks","anchor":{"id":"89d521e3-4d9b-523d-ac4e-65377bfe9338","slug":"maae","text":"แม่","meaning":"mother","pronunciation":"mâae","categoryKey":"daily","contextNote":"You''ll see แม่ in family words, shop names, and cultural phrases. It also gives you your first look at a vowel written before the consonant.","segments":[{"text":"แม","sound":"mae"},{"text":"่","sound":"tone change"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"0e2abce6-bed9-5ca0-a6b2-e09afc124410","key":"word-0e41-0e15-0e48","text":"แต่","meaning":"but / however","pronunciation":"dtae","categoryKey":"daily","segments":[{"text":"แต่","sound":"dtae"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"a23f7435-c081-54d4-abaa-0287352f280f","key":"word-0e41-0e01-0e48","text":"แก่","meaning":"old","pronunciation":"gae","categoryKey":"daily","segments":[{"text":"แก่","sound":"gae"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"999b600f-d3d2-5d5a-aff6-b0db7661510b","key":"word-0e41-0e14-0e14","text":"แดด","meaning":"sunlight","pronunciation":"daet","categoryKey":"daily","segments":[{"text":"แดด","sound":"daet"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"c336b414-7092-5360-afeb-e00fc28829bf","key":"word-0e41-0e15-0e01","text":"แตก","meaning":"to break","pronunciation":"dtaek","categoryKey":"daily","segments":[{"text":"แตก","sound":"dtaek"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"01ce66af-4e79-5b14-a794-033f56ee7e39","key":"word-0e41-0e1a-0e19","text":"แบน","meaning":"flat","pronunciation":"baen","categoryKey":"daily","segments":[{"text":"แบน","sound":"baen"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"0b650405-5f9d-5cc0-ad3f-83a853e24962","key":"word-0e1a-0e48-0e19","text":"บ่น","meaning":"to complain","pronunciation":"bon","categoryKey":"daily","segments":[{"text":"บ่น","sound":"bon"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"28b1a975-232b-5c2f-ae30-832858b634ee","key":"word-0e41-0e01","text":"แก","meaning":"you (casual)","pronunciation":"gae","categoryKey":"daily","segments":[{"text":"แก","sound":"gae"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"letter-type-tone-mark","title":"Tone mark","body":"Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"1684cb46-8524-51a4-ad84-8dd2fe3b46be","text":"แ","kind":"vowel","romanization":"ae","pronunciationHint":"long \"ae\" as in the vowel of \"care\"","mnemonic":"แ is a double left-side vowel. The two front posts tell your eye to look left first, then come back to the consonant for ae.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"13e7c7cd-283c-5d0b-a9cc-ce5b3831e495","text":"่","kind":"tone_mark","romanization":"mai ek","pronunciationHint":"first tone mark written above the consonant","mnemonic":"่ is mai ek, the first tone mark. It is one small stroke above the consonant, so read it as a compact tone cue.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"339f3a02-f34d-5263-a796-4d45cd2e4b7f","key":"before-vowels-left","name":"Some Vowels Sit on the Left","shortDescription":"The vowel แ is written before the consonant you pronounce first","explanation":"Thai does not always place vowels after the consonant. In แม่, your eye has to notice แ on the left, then come back to read ม with that vowel sound attached.","examples":[{"text":"แม = mae"},{"text":"แต่ = dtàae"}]},{"id":"c360364a-3f7a-5b8d-a892-563359ef7e9e","key":"mai-ek-tone-mark","name":"Meet Your First Tone Mark","shortDescription":"Tone marks sit above the consonant and change the sound of the whole syllable","explanation":"You do not need the full tone system at once. Start by recognizing that ่ lives above the consonant and changes the word you say. High-frequency sight words make tone marks easier to remember than abstract charts.","examples":[{"text":"แม่ = mâae"},{"text":"แต่ = dtàae"}]}],"drills":[{"id":"5bc9e17a-4a8a-51bb-a316-aa0a0aa74608","key":"maae-drill-01-recognize","type":"recognize","prompt":"Which vowel is written before the consonant?","payload":{},"options":[{"text":"แ","isCorrect":true},{"text":"า"},{"text":"ิ"},{"text":"ี"}]},{"id":"1b86c74a-d1ff-548e-a833-04ecf6f7c281","key":"maae-drill-02-recognize","type":"recognize","prompt":"Which mark is mai ek?","payload":{},"options":[{"text":"่","isCorrect":true},{"text":"้"},{"text":"แ"},{"text":"ั"}]},{"id":"5b514efd-9fe0-52b0-a98d-87af1c9de60c","key":"maae-drill-03-match","type":"match","prompt":"What does แม่ mean?","payload":{},"options":[{"text":"mother","isCorrect":true},{"text":"shop"},{"text":"road"},{"text":"fresh"}]},{"id":"f0776231-13a2-56ed-a053-5092778712f0","key":"maae-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"mother\"?","payload":{},"options":[{"text":"แม่","isCorrect":true},{"text":"แม"},{"text":"มา"},{"text":"แน"}]},{"id":"87008ac4-4fa4-5eda-a86a-fbd12791e726","key":"maae-drill-05-recognize","type":"recognize","prompt":"What changes when you add ่ above แม?","payload":{},"options":[{"text":"the vowel disappears"},{"text":"the tone changes","isCorrect":true},{"text":"the final consonant changes"},{"text":"the word becomes longer"}]}]}}'::jsonb, '919e5ca6b46bb1e50203cd193a7e1f54402b478075c4fd88332ec80758672f10', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('54ff1cc4-122f-5a46-a56b-ca7ba4b0bdf9'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '5f706588-560c-598f-ab7a-52a47ecb2015'::uuid, 'raan', 7, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"5f706588-560c-598f-ab7a-52a47ecb2015","slug":"raan","lessonOrdinal":7,"stage":3,"title":"ร้าน — The Word on Every Storefront","anchor":{"id":"c971805c-561a-5000-a9e8-846afac9e80b","slug":"raan","text":"ร้าน","meaning":"shop","pronunciation":"râan","categoryKey":"place","contextNote":"You''ll see ร้าน everywhere: ร้านกาแฟ, ร้านอาหาร, ร้านยา. Learning it early pays off on almost every street.","segments":[{"text":"ร้า","sound":"raa"},{"text":"น","sound":"n"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"6a66a60f-c509-56f7-a54b-bd44a4028c40","key":"word-0e21-0e49-0e32","text":"ม้า","meaning":"horse","pronunciation":"maa","categoryKey":"daily","segments":[{"text":"ม้า","sound":"maa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"78377bc9-780c-569b-af55-a4e43492b8ac","key":"word-0e1a-0e49-0e32-0e19","text":"บ้าน","meaning":"house / home","pronunciation":"baan","categoryKey":"place","segments":[{"text":"บ้าน","sound":"baan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"c328a5e5-6749-5e36-acd0-170fffcf5e4d","key":"word-0e19-0e49-0e32","text":"น้า","meaning":"aunt / uncle","pronunciation":"naa","categoryKey":"daily","segments":[{"text":"น้า","sound":"naa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"8af6bfe1-3b05-5ada-a070-0cafba9b65be","key":"word-0e14-0e49-0e32-0e19","text":"ด้าน","meaning":"side / aspect","pronunciation":"daan","categoryKey":"sign","segments":[{"text":"ด้าน","sound":"daan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"cccd4ff6-3438-5676-ac28-90cf88fa8941","key":"word-0e23-0e32-0e14","text":"ราด","meaning":"to pour over","pronunciation":"raat","categoryKey":"food","segments":[{"text":"ราด","sound":"raat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"c56de297-1a8f-5f2e-a9ba-5345ef5540bc","key":"word-0e23-0e35-0e14","text":"รีด","meaning":"to iron","pronunciation":"riit","categoryKey":"daily","segments":[{"text":"รีด","sound":"riit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"2498f294-f413-5697-a418-9ede9e739f4b","key":"word-0e23-0e14","text":"รด","meaning":"to water","pronunciation":"rot","categoryKey":"daily","segments":[{"text":"รด","sound":"rot"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"d5e43ad2-f9f4-5a78-ac14-995f15b83169","key":"word-0e23-0e49-0e32-0e19-0e14-0e35","text":"ร้านดี","meaning":"good shop","pronunciation":"raan dii","categoryKey":"place","segments":[{"text":"ร้าน","sound":"raan"},{"text":"ดี","sound":"dii"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-tone-mark","title":"Tone mark","body":"Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."}],"newGraphemes":[{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"50ada581-79e7-5549-a9a8-77693569d9b8","text":"ล","kind":"consonant","romanization":"l","pronunciationHint":"l as in \"love\"","mnemonic":"ล is ล ลิง (lor ling, monkey). Let the long lower curve be the monkey''s tail, and connect ลิง to the l sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"1684cb46-8524-51a4-ad84-8dd2fe3b46be","text":"แ","kind":"vowel","romanization":"ae","pronunciationHint":"long \"ae\" as in the vowel of \"care\"","mnemonic":"แ is a double left-side vowel. The two front posts tell your eye to look left first, then come back to the consonant for ae.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"13e7c7cd-283c-5d0b-a9cc-ce5b3831e495","text":"่","kind":"tone_mark","romanization":"mai ek","pronunciationHint":"first tone mark written above the consonant","mnemonic":"่ is mai ek, the first tone mark. It is one small stroke above the consonant, so read it as a compact tone cue.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]}],"rules":[{"id":"ba8c4da3-023b-5812-a6fb-0c09b52ce472","key":"initial-r-sound","name":"Initial ร Gives You R","shortDescription":"At the start of a syllable, ร is read as an r sound","explanation":"Thai ร has a few different jobs, but in ร้าน it is straightforward: it starts the word with an r sound before the tone mark and vowel shape do the rest of the work.","examples":[{"text":"รา = raa"},{"text":"ร้าน = râan"}]},{"id":"9d39de17-63e6-5cde-a43b-0d5655df93ec","key":"mai-tho-above","name":"Tone Marks Sit Above the Consonant","shortDescription":"Even when the vowel is on the right, the tone mark still sits above the main consonant","explanation":"In ร้าน, the long vowel า is on the right, but the tone mark ้ still sits above ร. Thai asks you to scan the whole syllable block, not just read from left to right.","examples":[{"text":"ร้า = râa"},{"text":"ร้าน = râan"}]}],"drills":[{"id":"7552ce0b-c30c-52bc-a88e-872c25d657d5","key":"raan-drill-01-recognize","type":"recognize","prompt":"Which letter starts with the \"r\" sound?","payload":{},"options":[{"text":"ร","isCorrect":true},{"text":"ล"},{"text":"น"},{"text":"ม"}]},{"id":"de5ad6bb-5b0c-5ede-a4f5-6266b4601f04","key":"raan-drill-02-recognize","type":"recognize","prompt":"Which mark is mai tho?","payload":{},"options":[{"text":"่"},{"text":"้","isCorrect":true},{"text":"ี"},{"text":"แ"}]},{"id":"565b7d5e-735f-5050-ad09-71fed55ac6a7","key":"raan-drill-03-match","type":"match","prompt":"What does ร้าน mean?","payload":{},"options":[{"text":"mother"},{"text":"shop","isCorrect":true},{"text":"ten"},{"text":"very"}]},{"id":"d7002b7d-1e35-5a0f-ae7e-e26a33f09a90","key":"raan-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"shop\"?","payload":{},"options":[{"text":"ร้าน","isCorrect":true},{"text":"ร่าน"},{"text":"ราน"},{"text":"น้าร"}]},{"id":"29a3d27f-d998-532c-abcd-12564e689931","key":"raan-drill-05-sound","type":"sound","prompt":"Where is the tone mark written in ร้าน?","payload":{},"options":[{"text":"under the consonant"},{"text":"above the consonant","isCorrect":true},{"text":"before the vowel"},{"text":"after the final consonant"}]}]}}'::jsonb, '4cc41fab79c243c751d999e942df26a70c8fc952540d25c73939c610667eb71c', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('b54e0d58-84f8-5ea6-a75a-6e3fa02991c2'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'a85af404-45e0-50ae-a491-e082f54018a8'::uuid, 'chut', 8, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"a85af404-45e0-50ae-a491-e082f54018a8","slug":"chut","lessonOrdinal":8,"stage":4,"title":"ชุด — Short U in Menu Combos","anchor":{"id":"8888dcb4-b725-5c58-abe7-96cfcb8ab970","slug":"chut","text":"ชุด","meaning":"set / combo","pronunciation":"chút","categoryKey":"food","contextNote":"ชุด shows up in set menus, school uniforms, and clothing signs. On menus, it often means a fixed combo or meal set.","segments":[{"text":"ชุ","sound":"chu"},{"text":"ด","sound":"t"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"04981577-f898-5f42-ab6b-336cc3b526a5","key":"word-0e0a-0e32","text":"ชา","meaning":"tea","pronunciation":"chaa","categoryKey":"food","segments":[{"text":"ชา","sound":"chaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"6fef4f01-e1de-53f6-aa34-34c060d1b847","key":"word-0e0a-0e21","text":"ชม","meaning":"to admire","pronunciation":"chom","categoryKey":"daily","segments":[{"text":"ชม","sound":"chom"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"5cded218-1a29-5f43-aa86-0333a6b83802","key":"word-0e0a-0e32-0e21","text":"ชาม","meaning":"bowl","pronunciation":"chaam","categoryKey":"food","segments":[{"text":"ชาม","sound":"chaam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"f6f40f9d-5920-56c7-ad3c-f8c251f15074","key":"word-0e0a-0e34-0e14","text":"ชิด","meaning":"close together","pronunciation":"chit","categoryKey":"daily","segments":[{"text":"ชิด","sound":"chit"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"123734b3-b6f6-5e91-ad26-b556d9a700d8","key":"word-0e14-0e38","text":"ดุ","meaning":"fierce / strict","pronunciation":"du","categoryKey":"daily","segments":[{"text":"ดุ","sound":"du"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"55b20bc1-ad75-526e-a9b8-5e84c53169f6","key":"word-0e25-0e38-0e01","text":"ลุก","meaning":"to get up","pronunciation":"luk","categoryKey":"daily","segments":[{"text":"ลุก","sound":"luk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"0faee178-a297-58d6-a92a-2a8f533b4991","key":"word-0e1a-0e38-0e01","text":"บุก","meaning":"to charge in","pronunciation":"buk","categoryKey":"daily","segments":[{"text":"บุก","sound":"buk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"a4a954e0-6ba3-5292-a173-5ad05f9964ce","key":"word-0e19-0e38-0e48-0e21","text":"นุ่ม","meaning":"soft","pronunciation":"num","categoryKey":"daily","segments":[{"text":"นุ่ม","sound":"num"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"85fd9b41-dc44-5bee-a89e-eba19102c6fe","key":"word-0e15-0e25-0e01","text":"ตลก","meaning":"funny","pronunciation":"dta-lok","categoryKey":"daily","segments":[{"text":"ตะ","sound":"dta"},{"text":"ลก","sound":"lok"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"f1c203bb-50b5-5872-a1b8-40cdaae0eb02","key":"word-0e15-0e25-0e32-0e14","text":"ตลาด","meaning":"market","pronunciation":"dta-laat","categoryKey":"place","segments":[{"text":"ตะ","sound":"dta"},{"text":"ลาด","sound":"laat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"6a66a60f-c509-56f7-a54b-bd44a4028c40","key":"word-0e21-0e49-0e32","text":"ม้า","meaning":"horse","pronunciation":"maa","categoryKey":"daily","segments":[{"text":"ม้า","sound":"maa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"63417404-20b6-5c86-a755-817318929a4c","key":"word-0e23-0e49-0e32-0e19","text":"ร้าน","meaning":"shop","pronunciation":"raan","categoryKey":"place","segments":[{"text":"ร้าน","sound":"raan"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"letter-type-tone-mark","title":"Tone mark","body":"Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify."}],"newGraphemes":[{"id":"9593d6a6-13bb-563d-a33d-b01dd74e3528","text":"ช","kind":"consonant","romanization":"ch","pronunciationHint":"ch as in \"check\"","mnemonic":"ช is ช ช้าง (chor chaang, elephant). Picture the long dropping stroke as an elephant trunk, and use ช้าง for the ch sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"a57ca296-4754-50f0-aad0-9856fff5c81d","text":"ุ","kind":"vowel","romanization":"u","pronunciationHint":"short \"u\" as in \"put\"","mnemonic":"ุ is the short u mark tucked under the consonant. Low on the page and short in sound: use it for the quick u in ชุด.","position":"below","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]}],"rules":[{"id":"215881f9-c7b2-522c-aaea-b676d1f481a5","key":"short-u-below","name":"Short ุ Sits Below","shortDescription":"The short u vowel is written below the consonant you pronounce first","explanation":"Thai keeps asking you to scan vertically. In ชุด, the consonant ช comes first and the short vowel ุ is tucked underneath, so you read chu before the final consonant closes the syllable.","examples":[{"text":"ชุ = chu"},{"text":"ชุด = chút"}]},{"id":"707d8403-783a-58bc-a40e-f63cb7a936d5","key":"dead-syllable-stop","name":"Short Vowels Feel Clipped in Closed Syllables","shortDescription":"A short vowel plus a final stop makes the whole word feel quick and closed","explanation":"ชุด feels short because the vowel is short and the final consonant is stopped. This clipped rhythm shows up in lots of practical Thai words on menus and signs.","examples":[{"text":"ชุด = chút"},{"text":"มุด = mút"}]}],"drills":[{"id":"3618386b-665b-5416-a461-d0ef90065f36","key":"chut-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"ch\" sound?","payload":{},"options":[{"text":"ช","isCorrect":true},{"text":"ส"},{"text":"บ"},{"text":"ร"}]},{"id":"d59be859-7c84-5a9e-a350-e26e03ab8e12","key":"chut-drill-02-recognize","type":"recognize","prompt":"Which vowel is written below the consonant?","payload":{},"options":[{"text":"ุ","isCorrect":true},{"text":"ิ"},{"text":"า"},{"text":"แ"}]},{"id":"477d26d8-9e21-5d7c-a3c0-a8424c722db5","key":"chut-drill-03-match","type":"match","prompt":"What does ชุด mean on a menu?","payload":{},"options":[{"text":"set / combo","isCorrect":true},{"text":"fresh"},{"text":"rice"},{"text":"to fly"}]},{"id":"6e35c2ec-6361-5a90-a52b-2b9af1fc07a5","key":"chut-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"set / combo\"?","payload":{},"options":[{"text":"ชุด","isCorrect":true},{"text":"ชาด"},{"text":"สด"},{"text":"ชดุ"}]},{"id":"f533d512-ef1d-59d1-a42b-a53b713e4eeb","key":"chut-drill-05-sound","type":"sound","prompt":"How does the final ด sound in ชุด?","payload":{},"options":[{"text":"d"},{"text":"t","isCorrect":true},{"text":"n"},{"text":"silent"}]}]}}'::jsonb, '9a95ac0c5de4fd6bef32f1fbbc48be96476033d1db9bc19da68e7d80a2caff15', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('3785d71c-3918-5276-ad7b-6f6d07fa48c9'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'fb4954f1-e326-56e2-a3d1-b4132b60e254'::uuid, 'sip', 9, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"fb4954f1-e326-56e2-a3d1-b4132b60e254","slug":"sip","lessonOrdinal":9,"stage":4,"title":"สิบ — Read Prices Faster","anchor":{"id":"c7f7eeee-be9c-59ec-a5ca-e993cf2d61c4","slug":"sip","text":"สิบ","meaning":"ten","pronunciation":"sìp","categoryKey":"sign","contextNote":"สิบ helps with prices, receipts, and quantity labels. Even one number word gives you real payoff in markets and transit.","segments":[{"text":"สิ","sound":"si"},{"text":"บ","sound":"p"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"19e88090-7511-52e2-a642-6b7417be5672","key":"word-0e2a-0e35","text":"สี","meaning":"color","pronunciation":"sii","categoryKey":"daily","segments":[{"text":"สี","sound":"sii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"cc6952b1-247e-5295-a69b-5c101bbac32e","key":"word-0e2a-0e32-0e21","text":"สาม","meaning":"three","pronunciation":"saam","categoryKey":"sign","segments":[{"text":"สาม","sound":"saam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"78a836eb-7d55-50ee-a937-1d175bbb96a6","key":"word-0e2a-0e49-0e21","text":"ส้ม","meaning":"orange","pronunciation":"som","categoryKey":"food","segments":[{"text":"ส้ม","sound":"som"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"3cbedc7a-a552-5f04-a1d8-dcf9b13223e4","key":"word-0e2a-0e19-0e38-0e01","text":"สนุก","meaning":"fun","pronunciation":"sa-nuk","categoryKey":"daily","segments":[{"text":"สะ","sound":"sa"},{"text":"นุก","sound":"nuk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"8f5f0a36-8b88-5899-a374-902c8ccc7d85","key":"word-0e2a-0e38-0e14","text":"สุด","meaning":"most / end","pronunciation":"sut","categoryKey":"daily","segments":[{"text":"สุด","sound":"sut"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"80d07517-ec44-52c4-a8c0-32a13e8b620f","key":"word-0e2a-0e14","text":"สด","meaning":"fresh","pronunciation":"sot","categoryKey":"food","segments":[{"text":"สด","sound":"sot"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"9bf27553-37c4-5eb4-a25f-3cd94a769825","key":"word-0e2a-0e21-0e38-0e14","text":"สมุด","meaning":"notebook","pronunciation":"sa-mut","categoryKey":"sign","segments":[{"text":"สะ","sound":"sa"},{"text":"มุด","sound":"mut"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"d9a39e42-58de-53a3-a768-752c144b9c6b","key":"word-0e2a-0e32-0e21-0e2a-0e34-0e1a","text":"สามสิบ","meaning":"thirty","pronunciation":"saam sip","categoryKey":"sign","segments":[{"text":"สาม","sound":"saam"},{"text":"สิบ","sound":"sip"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"79b85f07-1c04-5cf4-aedc-10e88083faf6","key":"word-0e2a-0e49-0e21-0e2a-0e14","text":"ส้มสด","meaning":"fresh oranges","pronunciation":"som sot","categoryKey":"food","segments":[{"text":"ส้ม","sound":"som"},{"text":"สด","sound":"sot"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"ae26196d-7a39-57e3-a8c4-061567bf9167","text":"ส","kind":"consonant","romanization":"s","pronunciationHint":"s as in \"sun\"","mnemonic":"ส is ส เสือ (sor suea, tiger). The pointed, striped-looking shape can cue a tiger, and เสือ starts with the crisp s sound.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"dddb2e02-9aa3-5dde-a2ab-25524fc96559","text":"บ","kind":"consonant","romanization":"b/p","pronunciationHint":"b as in \"bat\" at the start; clipped p at the end","mnemonic":"บ is บ ใบไม้ (bor bai mai, leaf). The open bowl shape can hold a leaf, and ใบไม้ gives you the b sound at the start.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"9593d6a6-13bb-563d-a33d-b01dd74e3528","text":"ช","kind":"consonant","romanization":"ch","pronunciationHint":"ch as in \"check\"","mnemonic":"ช is ช ช้าง (chor chaang, elephant). Picture the long dropping stroke as an elephant trunk, and use ช้าง for the ch sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"a57ca296-4754-50f0-aad0-9856fff5c81d","text":"ุ","kind":"vowel","romanization":"u","pronunciationHint":"short \"u\" as in \"put\"","mnemonic":"ุ is the short u mark tucked under the consonant. Low on the page and short in sound: use it for the quick u in ชุด.","position":"below","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"1a204ee8-b537-5026-a80e-84c60be7b87d","key":"initial-s-sound","name":"Initial ส Gives You S","shortDescription":"At the start of a syllable, ส is a clean s sound","explanation":"Thai has several letters that can map to an s-like sound, but you do not need them all at once. Start with ส because it appears constantly in useful words, labels, and polite formulas.","examples":[{"text":"สิบ = sìp"},{"text":"สด = sòt"}]},{"id":"a81aec16-221e-590d-a79d-ca348451a472","key":"final-b-to-p","name":"Final บ Closes as P","shortDescription":"At the end of a word, บ does not stay a full b sound","explanation":"Like several Thai final consonants, บ gets clipped at the end of a syllable. In สิบ, your lips close for p without the full released English b sound.","examples":[{"text":"สิบ = sìp"},{"text":"บัส = bát"}]}],"drills":[{"id":"acc21424-6128-5919-a890-2a2c4ac0c784","key":"sip-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"s\" sound?","payload":{},"options":[{"text":"ส","isCorrect":true},{"text":"ช"},{"text":"ร"},{"text":"บ"}]},{"id":"f12da006-4547-53fe-ac15-725c30c4746c","key":"sip-drill-02-match","type":"match","prompt":"What does สิบ mean?","payload":{},"options":[{"text":"rice"},{"text":"shop"},{"text":"ten","isCorrect":true},{"text":"mother"}]},{"id":"106c959c-12be-57d5-ae47-989845755e78","key":"sip-drill-03-sound","type":"sound","prompt":"Why does final บ in สิบ sound like p?","payload":{},"options":[{"text":"Thai drops all final consonants"},{"text":"final บ closes as p in Thai","isCorrect":true},{"text":"the tone mark changes it"},{"text":"the vowel makes it silent"}]},{"id":"02af70d4-c198-587f-aa33-3b8717f34737","key":"sip-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"ten\"?","payload":{},"options":[{"text":"สิบ","isCorrect":true},{"text":"บิส"},{"text":"สด"},{"text":"สบิ"}]},{"id":"df92c923-c1a1-513a-a6ab-ea02c5bf16df","key":"sip-drill-05-sound","type":"sound","prompt":"How do you pronounce สิบ?","payload":{},"options":[{"text":"sib"},{"text":"sii"},{"text":"sip","isCorrect":true},{"text":"sup"}]}]}}'::jsonb, '57296a431e27025135ec9dd37e0ed6338263c8589fe5546be669eee4a14484f6', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('a254cee8-2991-5cd1-aac1-883d929d4cd7'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '489857d0-a162-5afa-a7bb-c797b5761864'::uuid, 'khao', 10, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"489857d0-a162-5afa-a7bb-c797b5761864","slug":"khao","lessonOrdinal":10,"stage":5,"title":"ข้าว — A Survival Food Word","anchor":{"id":"cc47d33e-ee3d-50dc-a6ce-b3d61029996d","slug":"khao","text":"ข้าว","meaning":"rice","pronunciation":"khâao","categoryKey":"food","contextNote":"ข้าว is one of the highest-value food words in Thailand. It appears on menus, in meal names, and in everyday conversation.","segments":[{"text":"ข้า","sound":"khaa"},{"text":"ว","sound":"w glide"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"49d998d8-81d7-509b-ab5c-b6fab9b2e9c3","key":"word-0e02-0e27-0e32","text":"ขวา","meaning":"right side","pronunciation":"khwaa","categoryKey":"sign","segments":[{"text":"ขวา","sound":"khwaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"ad5f5493-0875-5b14-a014-ed4c5d2d7a8a","key":"word-0e02-0e48-0e32-0e27","text":"ข่าว","meaning":"news","pronunciation":"khaao","categoryKey":"sign","segments":[{"text":"ข่าว","sound":"khaao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"4b277ab9-99f9-523d-a6b3-895443e63944","key":"word-0e02-0e32-0e27","text":"ขาว","meaning":"white","pronunciation":"khaao","categoryKey":"daily","segments":[{"text":"ขาว","sound":"khaao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"8a92dbf1-5054-53f5-a5a4-6a75e342a6ee","key":"word-0e02-0e27-0e14","text":"ขวด","meaning":"bottle","pronunciation":"khuat","categoryKey":"daily","segments":[{"text":"ขวด","sound":"khuat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"ecee6e47-ebbb-5dae-aad2-38cfec474745","key":"word-0e02-0e32","text":"ขา","meaning":"leg","pronunciation":"khaa","categoryKey":"daily","segments":[{"text":"ขา","sound":"khaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"5d489b6f-4e4d-5924-a401-f2c555ed94f8","key":"word-0e02-0e21","text":"ขม","meaning":"bitter","pronunciation":"khom","categoryKey":"food","segments":[{"text":"ขม","sound":"khom"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"1621be98-12f7-5c95-a927-eb04c7ccbdbd","key":"word-0e02-0e32-0e14","text":"ขาด","meaning":"to lack / be torn","pronunciation":"khaat","categoryKey":"daily","segments":[{"text":"ขาด","sound":"khaat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"27f8a8b4-3ade-5533-a6bc-5a7bb7fdd7f4","key":"word-0e27-0e32-0e14","text":"วาด","meaning":"to draw","pronunciation":"waat","categoryKey":"daily","segments":[{"text":"วาด","sound":"waat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"04f9ae15-2e7a-57b1-a70e-d8c7c10f10f7","key":"word-0e27-0e48-0e32","text":"ว่า","meaning":"to say / that","pronunciation":"waa","categoryKey":"daily","segments":[{"text":"ว่า","sound":"waa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"0f38335e-0377-50b9-a08c-34d41e5821ac","key":"word-0e14-0e32-0e27","text":"ดาว","meaning":"star","pronunciation":"daao","categoryKey":"daily","segments":[{"text":"ดาว","sound":"daao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"4380bfe9-6e97-500e-afa1-c84528ddd28c","key":"word-0e2a-0e27-0e19","text":"สวน","meaning":"garden / park","pronunciation":"suan","categoryKey":"place","segments":[{"text":"สวน","sound":"suan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"bb650142-5eea-5cbe-a533-eaf8abae663d","key":"word-0e02-0e49-0e32-0e27-0e02-0e32-0e27","text":"ข้าวขาว","meaning":"white rice","pronunciation":"khaao khaao","categoryKey":"food","segments":[{"text":"ข้าว","sound":"khaao"},{"text":"ขาว","sound":"khaao"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"letter-type-tone-mark","title":"Tone mark","body":"Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify."}],"newGraphemes":[{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"5e1b543b-6be0-5279-a812-4ec61ce2b1dc","text":"ว","kind":"consonant","romanization":"w","pronunciationHint":"w as in \"water\"; can help form vowel glides","mnemonic":"ว is ว แหวน (wor waen, ring). The rounded curl looks like a ring, and แหวน gives you the w sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"71da4ee2-bbc8-5047-a6bf-bbfd13816bfc","key":"kh-vs-k","name":"ข Adds Air to K","shortDescription":"ข is not the same as ก; it has a stronger puff of air","explanation":"Thai distinguishes plain k sounds from aspirated kh sounds. If you hold your hand in front of your mouth, ข pushes out a little air in a way ก does not.","examples":[{"text":"กา = gaa"},{"text":"ข่าว = khàao"},{"text":"ข้าว = khâao"}]},{"id":"52b3fcea-a418-58db-ad81-2054c133fba1","key":"aaw-glide","name":"ว Can Help Build a Vowel Glide","shortDescription":"In words like ข้าว, ว helps shape the ending vowel sound instead of behaving like a full separate consonant","explanation":"Not every written consonant is heard as a clean standalone consonant. In ข้าว, ว helps form the -าว ending, so you hear a smooth glide rather than a sharp final w.","examples":[{"text":"ข่าว = khàao"},{"text":"ข้าว = khâao"}]}],"drills":[{"id":"9277e873-bfa3-53f7-a26f-72549d58727a","key":"khao-drill-01-recognize","type":"recognize","prompt":"Which letter gives the aspirated \"kh\" sound?","payload":{},"options":[{"text":"ก"},{"text":"ข","isCorrect":true},{"text":"บ"},{"text":"ห"}]},{"id":"72b362c6-5874-5eb5-ae33-d322cad13016","key":"khao-drill-02-recognize","type":"recognize","prompt":"Which letter helps build the -าว ending in ข้าว?","payload":{},"options":[{"text":"น"},{"text":"ว","isCorrect":true},{"text":"ร"},{"text":"ล"}]},{"id":"c744f172-4cd7-5f24-a563-6dbefb6498ad","key":"khao-drill-03-match","type":"match","prompt":"What does ข้าว mean?","payload":{},"options":[{"text":"rice","isCorrect":true},{"text":"fresh"},{"text":"ten"},{"text":"mother"}]},{"id":"a54b1113-2c41-5e38-a0a6-f4ed6ce3b6f3","key":"khao-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"rice\"?","payload":{},"options":[{"text":"ข้าว","isCorrect":true},{"text":"ขาว"},{"text":"ข้า"},{"text":"ขน"}]},{"id":"62a04a09-d6ca-5d0c-a968-c3a5a904b052","key":"khao-drill-05-sound","type":"sound","prompt":"What is the key difference between ก and ข?","payload":{},"options":[{"text":"ก is nasal and ข is silent"},{"text":"ข has a puff of air and ก does not","isCorrect":true},{"text":"they sound the same"},{"text":"ข is only used at the end of words"}]}]}}'::jsonb, '68ffe6fee686421257bf1fc7410efa5a3a33125e8082ab8350a6662fc41e2a1b', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('a606d673-c171-56e5-a0a8-09a4dee06c2f'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '6a8b53e3-50a0-5db3-a089-a15c56bc01c6'::uuid, 'moo', 11, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"6a8b53e3-50a0-5db3-a089-a15c56bc01c6","slug":"moo","lessonOrdinal":11,"stage":5,"title":"หมู — Leading ห in a Real Menu Word","anchor":{"id":"c771541d-bc22-55d6-ade9-52b9d986cfe2","slug":"moo","text":"หมู","meaning":"pork","pronunciation":"mǔu","categoryKey":"food","contextNote":"หมู is everywhere on Thai menus. It is also the cleanest early example of the leading-ห pattern that learners need sooner rather than later.","segments":[{"text":"ห","sound":"leading h"},{"text":"มู","sound":"muu"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"8add2650-ea68-509f-ae3d-8c35db8b7b59","key":"word-0e2b-0e39","text":"หู","meaning":"ear","pronunciation":"huu","categoryKey":"daily","segments":[{"text":"หู","sound":"huu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"8c79ebe5-9b38-5d70-a534-b40b909e194e","key":"word-0e2b-0e21-0e32","text":"หมา","meaning":"dog","pronunciation":"maa","categoryKey":"daily","segments":[{"text":"หมา","sound":"maa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"f4755169-67ed-53b6-ac5f-8f9c0b01cc4f","key":"word-0e2b-0e32","text":"หา","meaning":"to look for","pronunciation":"haa","categoryKey":"daily","segments":[{"text":"หา","sound":"haa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"f12c3344-3a1f-53c0-a42e-0f068f47080c","key":"word-0e23-0e39-0e49","text":"รู้","meaning":"to know","pronunciation":"ruu","categoryKey":"daily","segments":[{"text":"รู้","sound":"ruu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"598027dc-4153-5c7b-adcd-e5c1fecc9140","key":"word-0e14-0e39","text":"ดู","meaning":"to watch","pronunciation":"duu","categoryKey":"daily","segments":[{"text":"ดู","sound":"duu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"cda49f45-c2e6-58b2-ad64-ce6066aeb0fa","key":"word-0e2b-0e34-0e27","text":"หิว","meaning":"hungry","pronunciation":"hiw","categoryKey":"daily","segments":[{"text":"หิว","sound":"hiw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"52c43174-6f7b-563d-a0cc-490c2598a58a","key":"word-0e2b-0e21-0e14","text":"หมด","meaning":"all gone","pronunciation":"mot","categoryKey":"daily","segments":[{"text":"หมด","sound":"mot"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"0edbc717-9d7f-5069-ad5a-fd22c5ec3c54","key":"word-0e25-0e39-0e01","text":"ลูก","meaning":"child","pronunciation":"luuk","categoryKey":"daily","segments":[{"text":"ลูก","sound":"luuk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"7c54b99c-c014-5d9d-abe1-b92bbc15d050","key":"word-0e15-0e39-0e49","text":"ตู้","meaning":"cabinet","pronunciation":"tuu","categoryKey":"place","segments":[{"text":"ตู้","sound":"tuu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"cbbf92fe-74b0-5d46-a1d9-9b5e2e19cff2","key":"word-0e2a-0e39-0e49","text":"สู้","meaning":"to fight","pronunciation":"suu","categoryKey":"daily","segments":[{"text":"สู้","sound":"suu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"c7fa958a-64c3-52ea-a4ba-845f0a7feb4e","key":"word-0e2b-0e27-0e32-0e19","text":"หวาน","meaning":"sweet","pronunciation":"waan","categoryKey":"food","segments":[{"text":"หวาน","sound":"waan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"8968cae3-fe97-5863-af6c-6932e5f2d4fb","key":"word-0e2b-0e49-0e32-0e21","text":"ห้าม","meaning":"forbidden / do not","pronunciation":"haam","categoryKey":"sign","segments":[{"text":"ห้าม","sound":"haam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"7ba77c91-000c-5258-aff4-7680dd07e122","key":"word-0e2b-0e34-0e27-0e21-0e32-0e01","text":"หิวมาก","meaning":"very hungry","pronunciation":"hiw maak","categoryKey":"daily","segments":[{"text":"หิว","sound":"hiw"},{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_extension","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"1aa8932e-9563-5621-aaec-4477efb463ff","key":"word-0e2b-0e21-0e39-0e2a-0e14","text":"หมูสด","meaning":"fresh pork","pronunciation":"muu sot","categoryKey":"food","segments":[{"text":"หมู","sound":"muu"},{"text":"สด","sound":"sot"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"98079396-6adf-5409-a63c-121764a3840e","text":"ห","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hello\"; often used as a leading tone helper","mnemonic":"ห is ห หีบ (hor hiip, chest). Picture the tall shape as a chest with a lid; in words like หมู, this h-letter can also guide the tone.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"6cbd6547-63c8-52cd-a2e5-378aa42e3e46","text":"ู","kind":"vowel","romanization":"uu","pronunciationHint":"long \"oo\" as in \"food\"","mnemonic":"ู is the long uu mark below the consonant. It is like ุ with a longer lower tail, so let the oo sound run longer.","position":"below","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"5e1b543b-6be0-5279-a812-4ec61ce2b1dc","text":"ว","kind":"consonant","romanization":"w","pronunciationHint":"w as in \"water\"; can help form vowel glides","mnemonic":"ว is ว แหวน (wor waen, ring). The rounded curl looks like a ring, and แหวน gives you the w sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"62ade15b-2ecf-5726-a1dd-6689ff8c548e","key":"leading-h-pattern","name":"Leading ห Changes the Tone Pattern","shortDescription":"In common words like หมู, ห helps a following low consonant behave differently","explanation":"This is one of the Thai chunks worth learning as a whole. In words like หมู, the ห is not there to give you a full h sound before every letter. It helps control the syllable pattern of the low consonant that follows.","examples":[{"text":"หมู = mǔu"},{"text":"หมอ = mǎaw"}]},{"id":"d5b18e8e-9a1e-5ea5-a808-651961f8dfb4","key":"long-uu-below","name":"Long ู Sits Below","shortDescription":"The long oo vowel is written below the consonant","explanation":"Thai uses the space below the line too. In หมู and หู, the vowel ู sits under the consonant and gives you a long oo sound.","examples":[{"text":"หมู = mǔu"},{"text":"ดู = duu"}]}],"drills":[{"id":"aee4f232-92da-5ff9-ab9a-4f6159e0013a","key":"moo-drill-01-recognize","type":"recognize","prompt":"Which letter is the leading ห in หมู?","payload":{},"options":[{"text":"ห","isCorrect":true},{"text":"ม"},{"text":"ข"},{"text":"อ"}]},{"id":"88afeac6-4549-51f2-a692-0619b08828d8","key":"moo-drill-02-recognize","type":"recognize","prompt":"Which vowel makes the long \"oo\" sound?","payload":{},"options":[{"text":"ุ"},{"text":"ู","isCorrect":true},{"text":"ิ"},{"text":"ี"}]},{"id":"8b2a3c3c-c41d-5097-afcd-6ae79c70b553","key":"moo-drill-03-match","type":"match","prompt":"What does หมู mean?","payload":{},"options":[{"text":"pork","isCorrect":true},{"text":"rice"},{"text":"shop"},{"text":"food"}]},{"id":"de1ce793-e310-5856-a6da-cabd69b2e3d9","key":"moo-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"pork\"?","payload":{},"options":[{"text":"หมู","isCorrect":true},{"text":"มู"},{"text":"หมา"},{"text":"ขู"}]},{"id":"81bb588d-fda4-5b93-ac8d-d7b10794035c","key":"moo-drill-05-sound","type":"sound","prompt":"Why is ห useful in words like หมู?","payload":{},"options":[{"text":"It adds a final consonant"},{"text":"It changes the tone pattern of the low consonant that follows","isCorrect":true},{"text":"It marks plural"},{"text":"It makes the vowel longer all by itself"}]}]}}'::jsonb, 'c1ed28af3b130afcf4adbf845ecb48ac5b43c44f365a0a9c125c23972f223118', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('96311bdb-d7ff-5120-a392-2a9046da278b'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'e387c914-ad75-5a7c-a972-cf079418042d'::uuid, 'ahan', 12, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"e387c914-ad75-5a7c-a972-cf079418042d","slug":"ahan","lessonOrdinal":12,"stage":5,"title":"อาหาร — Silent Carrier, Useful Sign","anchor":{"id":"01409ff0-7f6d-54f3-ab1e-8e428d0ca405","slug":"ahan","text":"อาหาร","meaning":"food","pronunciation":"aa-hǎan","categoryKey":"food","contextNote":"อาหาร appears on restaurant signs, food courts, and delivery labels. Once you can read ร้านอาหาร, the street starts feeling more legible.","segments":[{"text":"อา","sound":"aa"},{"text":"หา","sound":"hǎa"},{"text":"ร","sound":"n"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"c0ae7fff-a846-5198-af67-4174b5a833ab","key":"word-0e2d-0e2d-0e01","text":"ออก","meaning":"to exit / go out","pronunciation":"awk","categoryKey":"sign","segments":[{"text":"ออก","sound":"awk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"46902c0d-543a-55e1-ab8a-e5d2c299ab39","key":"word-0e02-0e2d","text":"ขอ","meaning":"to ask for","pronunciation":"khaaw","categoryKey":"daily","segments":[{"text":"ขอ","sound":"khaaw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"7debb9fb-b969-59fa-a6de-bda8eb99829c","key":"word-0e0a-0e2d-0e1a","text":"ชอบ","meaning":"to like","pronunciation":"chaawp","categoryKey":"daily","segments":[{"text":"ชอบ","sound":"chaawp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"e1949758-58f1-594e-a1c4-fff2d139bc20","key":"word-0e23-0e49-0e2d-0e19","text":"ร้อน","meaning":"hot","pronunciation":"raawn","categoryKey":"daily","segments":[{"text":"ร้อน","sound":"raawn"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"be7afec8-972c-5cc1-a833-fa707d436cd8","key":"word-0e23-0e2d","text":"รอ","meaning":"to wait","pronunciation":"raaw","categoryKey":"daily","segments":[{"text":"รอ","sound":"raaw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"f6aa72e4-6ec4-5756-a920-7e868f166d6d","key":"word-0e1a-0e2d-0e01","text":"บอก","meaning":"to tell","pronunciation":"baawk","categoryKey":"daily","segments":[{"text":"บอก","sound":"baawk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"1bf9cebe-27d0-5606-a9f6-96d3eaf3b7fb","key":"word-0e2b-0e21-0e2d","text":"หมอ","meaning":"doctor","pronunciation":"maaw","categoryKey":"daily","segments":[{"text":"หมอ","sound":"maaw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"cae64235-6767-58f0-ac6b-dd2e62c23141","key":"word-0e14-0e2d-0e01","text":"ดอก","meaning":"flower","pronunciation":"daawk","categoryKey":"daily","segments":[{"text":"ดอก","sound":"daawk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"a1b845ac-b7ec-57bc-ae29-1151128172f0","key":"word-0e2b-0e2d-0e21","text":"หอม","meaning":"fragrant","pronunciation":"haawm","categoryKey":"daily","segments":[{"text":"หอม","sound":"haawm"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"7f0cf283-d9f0-5d82-a968-3c8605cfb741","key":"word-0e15-0e2d-0e1a","text":"ตอบ","meaning":"to answer","pronunciation":"dtaawp","categoryKey":"daily","segments":[{"text":"ตอบ","sound":"dtaawp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"6e3d61d8-c2a8-5d55-aaff-4512b69e43da","key":"word-0e2d-0e49-0e27-0e19","text":"อ้วน","meaning":"fat / overweight","pronunciation":"uuan","categoryKey":"daily","segments":[{"text":"อ้วน","sound":"uuan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"038d8c5a-b113-5036-afe0-83c560b4e838","key":"word-0e02-0e2d-0e0a-0e32","text":"ขอชา","meaning":"may I have tea","pronunciation":"khaaw chaa","categoryKey":"food","segments":[{"text":"ขอ","sound":"khaaw"},{"text":"ชา","sound":"chaa"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_extension","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"f7ae2242-6833-5d1c-a43c-9d4c8c3afd39","key":"word-0e0a-0e2d-0e1a-0e21-0e32-0e01","text":"ชอบมาก","meaning":"like very much","pronunciation":"chaawp maak","categoryKey":"daily","segments":[{"text":"ชอบ","sound":"chaawp"},{"text":"มาก","sound":"maak"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"98079396-6adf-5409-a63c-121764a3840e","text":"ห","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hello\"; often used as a leading tone helper","mnemonic":"ห is ห หีบ (hor hiip, chest). Picture the tall shape as a chest with a lid; in words like หมู, this h-letter can also guide the tone.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"12476104-aabd-52e5-ad0e-4994d23aec74","key":"silent-carrier","name":"อ Can Carry a Vowel Silently","shortDescription":"Thai still wants a consonant slot even when the syllable begins with a vowel sound","explanation":"In อาหาร, the first syllable sounds like aa, but Thai still writes a consonant letter to hold that opening vowel. อ acts as the carrier without adding a strong sound of its own.","examples":[{"text":"อา = aa"},{"text":"อาหาร = aa-hǎan"}]},{"id":"b144050a-1ef9-53f3-ae3c-d669fc4571f3","key":"final-r-to-n","name":"Final ร Often Sounds Like \"n\"","shortDescription":"At the end of a syllable, ร is often heard as \"n\" instead of a full r","explanation":"Thai final consonants do not always match their initial sounds. In อาหาร, the final ร is not read as a strong r. It closes the word with an n-like ending instead.","examples":[{"text":"อาหาร = aa-hǎan"},{"text":"สาร = sǎan"}]}],"drills":[{"id":"1b4dcf0d-6c4b-508e-a299-8c8d60f12f33","key":"ahan-drill-01-recognize","type":"recognize","prompt":"Which letter is the silent carrier?","payload":{},"options":[{"text":"อ","isCorrect":true},{"text":"ห"},{"text":"ร"},{"text":"ว"}]},{"id":"f802dbbd-32dc-5fc5-a3ec-03038e9fe5c8","key":"ahan-drill-02-match","type":"match","prompt":"What does อาหาร mean?","payload":{},"options":[{"text":"food","isCorrect":true},{"text":"set menu"},{"text":"mother"},{"text":"to fly"}]},{"id":"143f1ddd-6c90-53a5-aca3-03d10ecb8226","key":"ahan-drill-03-spot","type":"spot","prompt":"Which Thai spelling means \"food\"?","payload":{},"options":[{"text":"อาหาร","isCorrect":true},{"text":"หารอา"},{"text":"หมู"},{"text":"ผัด"}]},{"id":"afd544e1-be46-5ddc-a9bb-a97a33eee37a","key":"ahan-drill-04-sound","type":"sound","prompt":"How does the final ร sound in อาหาร?","payload":{},"options":[{"text":"r"},{"text":"l"},{"text":"n","isCorrect":true},{"text":"silent"}]},{"id":"b917b9b7-a124-51ac-a09a-ac2df18d12cd","key":"ahan-drill-05-recognize","type":"recognize","prompt":"Why does อาหาร begin with อ?","payload":{},"options":[{"text":"It marks plural"},{"text":"Thai needs a consonant slot, so อ carries the opening vowel","isCorrect":true},{"text":"It is only decorative"},{"text":"It always means the word is formal"}]}]}}'::jsonb, '144bf88766d12d73786e4045748535c178f9554e0c9e8f7c1f7625a57fc39b84', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('f41342dd-6644-59cb-a627-4f879f99628e'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '227b7204-c818-5c7c-ad68-654e72285cd6'::uuid, 'phat', 13, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"227b7204-c818-5c7c-ad68-654e72285cd6","slug":"phat","lessonOrdinal":13,"stage":5,"title":"ผัด — Unlock Stir-Fry Words","anchor":{"id":"d2faba91-170e-5cef-ad0b-7f3a04ac6143","slug":"phat","text":"ผัด","meaning":"stir-fry","pronunciation":"phàt","categoryKey":"food","contextNote":"ผัด appears on some of the most common Thai dishes, from ผัดไทย to vegetable stir-fries. It is one of the highest-value cooking words you can learn.","segments":[{"text":"ผั","sound":"pha"},{"text":"ด","sound":"t"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"b0c734f8-b446-5b48-ab6f-188e3678a636","key":"word-0e1c-0e31-0e01","text":"ผัก","meaning":"vegetables","pronunciation":"phak","categoryKey":"food","segments":[{"text":"ผัก","sound":"phak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"dad63552-fe4a-55e4-a8e1-9e0804d5a448","key":"word-0e1c-0e21","text":"ผม","meaning":"I / hair","pronunciation":"phom","categoryKey":"daily","segments":[{"text":"ผม","sound":"phom"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"07330a77-9112-51d7-a364-42c132bc7614","key":"word-0e23-0e31-0e01","text":"รัก","meaning":"to love","pronunciation":"rak","categoryKey":"daily","segments":[{"text":"รัก","sound":"rak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"5d73dcdf-4d91-5d90-ad80-d7c6c4d1c3a7","key":"word-0e27-0e31-0e19","text":"วัน","meaning":"day","pronunciation":"wan","categoryKey":"sign","segments":[{"text":"วัน","sound":"wan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"60e93954-b63a-52aa-a0ea-881bda6a7364","key":"word-0e21-0e31-0e19","text":"มัน","meaning":"it / oily","pronunciation":"man","categoryKey":"daily","segments":[{"text":"มัน","sound":"man"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"2ef7151f-6563-5b7b-a5e9-fe8de6c75f66","key":"word-0e27-0e31-0e14","text":"วัด","meaning":"temple / to measure","pronunciation":"wat","categoryKey":"place","segments":[{"text":"วัด","sound":"wat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"a9b39b92-ff0e-56e0-a99a-6e0afc2df519","key":"word-0e23-0e31-0e1a","text":"รับ","meaning":"to receive","pronunciation":"rap","categoryKey":"daily","segments":[{"text":"รับ","sound":"rap"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"47638a79-db13-5297-ad71-1c26b39d6a22","key":"word-0e02-0e31-0e1a","text":"ขับ","meaning":"to drive","pronunciation":"khap","categoryKey":"daily","segments":[{"text":"ขับ","sound":"khap"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"0c3d4a24-2b48-581a-a296-6f0b7480f539","key":"word-0e2b-0e31-0e27","text":"หัว","meaning":"head","pronunciation":"hua","categoryKey":"daily","segments":[{"text":"หัว","sound":"hua"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"cb1240ca-1d7b-5509-a6e2-d53911ecf508","key":"word-0e15-0e31-0e1a","text":"ตับ","meaning":"liver","pronunciation":"dtap","categoryKey":"food","segments":[{"text":"ตับ","sound":"dtap"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"05a466bf-5f31-5bfa-af06-d11c752c2595","key":"word-0e2a-0e31-0e49-0e19","text":"สั้น","meaning":"short","pronunciation":"san","categoryKey":"daily","segments":[{"text":"สั้น","sound":"san"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"ee58ba57-f2fb-5b14-a9da-e37e9d0f800f","key":"word-0e1c-0e49-0e32","text":"ผ้า","meaning":"cloth","pronunciation":"phaa","categoryKey":"daily","segments":[{"text":"ผ้า","sound":"phaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"d15b5e1e-de21-5f76-af19-397033576d45","key":"word-0e1c-0e35","text":"ผี","meaning":"ghost","pronunciation":"phii","categoryKey":"daily","segments":[{"text":"ผี","sound":"phii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"18d020b7-932a-5d37-a916-eb1cba31dc37","key":"word-0e15-0e31-0e27","text":"ตัว","meaning":"body / self","pronunciation":"dtua","categoryKey":"daily","segments":[{"text":"ตัว","sound":"dtua"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_extension","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"82fe7ab6-0023-50d4-a20c-cd5e249f5adc","key":"word-0e1c-0e31-0e14-0e1c-0e31-0e01","text":"ผัดผัก","meaning":"stir-fried vegetables","pronunciation":"phat phak","categoryKey":"food","segments":[{"text":"ผัด","sound":"phat"},{"text":"ผัก","sound":"phak"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_extension","ordinalInRole":6,"isDrillTarget":true,"item":{"id":"ca72f102-44a9-518b-acc8-90b517fabec7","key":"word-0e1c-0e21-0e2b-0e34-0e27","text":"ผมหิว","meaning":"I am hungry","pronunciation":"phom hiw","categoryKey":"daily","segments":[{"text":"ผม","sound":"phom"},{"text":"หิว","sound":"hiw"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_extension","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"3c992023-814d-5a7d-a46d-28107afdf750","key":"word-0e23-0e31-0e01-0e41-0e21-0e48","text":"รักแม่","meaning":"to love mom","pronunciation":"rak mae","categoryKey":"daily","segments":[{"text":"รัก","sound":"rak"},{"text":"แม่","sound":"mae"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"da8975d2-f60a-59f9-a1d2-f55df44b6bfa","text":"ผ","kind":"consonant","romanization":"ph","pronunciationHint":"ph with a puff of air, like the start of \"photo\" without the f sound","mnemonic":"ผ is ผ ผึ้ง (phor phueng, bee). Picture the open shape as wings and body; ผึ้ง starts with the puffed ph sound.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"6655bad5-f432-5868-aa67-e7247253802f","text":"ั","kind":"vowel","romanization":"a","pronunciationHint":"short \"a\" as in \"cut\"","mnemonic":"ั is the short a cap above the consonant. It sits close and quick, just like the clipped a in ผัด and ผัก.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"98079396-6adf-5409-a63c-121764a3840e","text":"ห","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hello\"; often used as a leading tone helper","mnemonic":"ห is ห หีบ (hor hiip, chest). Picture the tall shape as a chest with a lid; in words like หมู, this h-letter can also guide the tone.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"a760feb3-b11d-5a48-aa4b-dfb7b7a0c055","key":"ph-vs-b","name":"ผ Gives You an Airy Ph Sound","shortDescription":"ผ is not the same as บ; it starts with a stronger puff of air","explanation":"Thai distinguishes plain b/p-like sounds from aspirated ph sounds. In ผัด, you can feel a burst of air at the start that you do not get with บ.","examples":[{"text":"ผัด = phàt"},{"text":"ผัน = phan"}]},{"id":"80814a05-caf2-5ac2-afd4-5311e1cc970e","key":"short-a-above","name":"Short ั Sits Above","shortDescription":"The short a vowel is written above the consonant","explanation":"Thai uses a small mark above the consonant for the short a sound in words like ผัด. It is quicker and more clipped than the long right-side vowel า you learned earlier.","examples":[{"text":"ผัด = phàt"},{"text":"ผัน = phan"}]}],"drills":[{"id":"62ec9ab5-e2a5-5a39-afa3-ecd5bb5329e4","key":"phat-drill-01-recognize","type":"recognize","prompt":"Which letter makes the aspirated \"ph\" sound?","payload":{},"options":[{"text":"ผ","isCorrect":true},{"text":"บ"},{"text":"ห"},{"text":"ข"}]},{"id":"9f452601-a03f-5cae-adc1-7dd3fa1f3114","key":"phat-drill-02-recognize","type":"recognize","prompt":"Which vowel gives the short \"a\" sound above the consonant?","payload":{},"options":[{"text":"ั","isCorrect":true},{"text":"า"},{"text":"แ"},{"text":"ุ"}]},{"id":"9439e02a-87e1-5211-a4e0-618142290f68","key":"phat-drill-03-match","type":"match","prompt":"What does ผัด mean?","payload":{},"options":[{"text":"stir-fry","isCorrect":true},{"text":"food court"},{"text":"shop"},{"text":"ten"}]},{"id":"d7f90549-40dd-5a16-a101-e7f33354bfaf","key":"phat-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"stir-fry\"?","payload":{},"options":[{"text":"ผัด","isCorrect":true},{"text":"ผาด"},{"text":"ผาก"},{"text":"ชุด"}]},{"id":"b9806e17-7198-5645-a174-7f5434e9b97c","key":"phat-drill-05-sound","type":"sound","prompt":"Which word shares the same ผั- opening as ผัด?","payload":{},"options":[{"text":"ผัก","isCorrect":true},{"text":"ข้าว"},{"text":"บิน"},{"text":"แม่"}]}]}}'::jsonb, '5f12bcc07a9595f35c933a5c16eaee9d6a1594e5e7876c53bd0eb0450851f253', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('9ac1ea24-785a-53c4-a058-440a94f639b4'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '7158a845-3580-5cfa-a158-db2ec59ba64b'::uuid, 'khong', 14, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"7158a845-3580-5cfa-a158-db2ec59ba64b","slug":"khong","lessonOrdinal":14,"stage":6,"title":"ของ — The ng Sound and the aw Vowel","anchor":{"id":"53cc0560-d985-57a9-a82a-f8647ffb52bf","slug":"khong","text":"ของ","meaning":"of / belonging to","pronunciation":"khǎwng","categoryKey":"daily","contextNote":"ของ is one of the most common words in Thai. It links things to owners (ของผม, mine), labels stuff to buy or eat (ของกิน, things to eat), and shows up constantly on signs and menus.","segments":[{"text":"ขอ","sound":"khǎw"},{"text":"ง","sound":"ng"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"be7afec8-972c-5cc1-a833-fa707d436cd8","key":"word-0e23-0e2d","text":"รอ","meaning":"to wait","pronunciation":"raw","categoryKey":"daily","segments":[{"text":"รอ","sound":"raw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"72e245aa-fc7c-5ccc-aefa-3b3ed2fe9dc1","key":"word-0e21-0e2d-0e07","text":"มอง","meaning":"to look at","pronunciation":"mawng","categoryKey":"daily","segments":[{"text":"มอง","sound":"mawng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"2bebb6ad-d461-5767-adbb-a354654fda76","key":"word-0e25-0e2d-0e07","text":"ลอง","meaning":"to try","pronunciation":"lawng","categoryKey":"daily","segments":[{"text":"ลอง","sound":"lawng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"cc8911bf-1afa-5669-a0f1-63db05a41184","key":"word-0e07-0e32","text":"งา","meaning":"sesame","pronunciation":"ngaa","categoryKey":"food","segments":[{"text":"งา","sound":"ngaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"9c066f29-fbfd-59d2-ab35-e5868c6f3b71","key":"word-0e15-0e49-0e2d-0e07","text":"ต้อง","meaning":"must / have to","pronunciation":"dtâwng","categoryKey":"daily","segments":[{"text":"ต้อง","sound":"dtâwng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"ae5beeac-9d83-5991-af23-9f3eabae85eb","key":"word-0e2a-0e2d-0e07","text":"สอง","meaning":"two","pronunciation":"sǎwng","categoryKey":"daily","segments":[{"text":"สอง","sound":"sǎwng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"e2b31ebe-07cb-5015-a44d-9b61dd5bc73a","key":"word-0e2b-0e49-0e2d-0e07","text":"ห้อง","meaning":"room","pronunciation":"hâwng","categoryKey":"sign","segments":[{"text":"ห้อง","sound":"hâwng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"515466c6-a753-564d-a1c3-1869c867fca1","key":"word-0e02-0e49-0e32-0e07-0e2b-0e25-0e31-0e07","text":"ข้างหลัง","meaning":"behind","pronunciation":"khâang-lǎng","categoryKey":"sign","segments":[{"text":"ข้าง","sound":"khâang"},{"text":"หลัง","sound":"lǎng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"f715bf45-b1f6-5d8a-a256-b2a87080d457","key":"word-0e02-0e2d-0e07-0e01-0e34-0e19","text":"ของกิน","meaning":"things to eat","pronunciation":"khǎwng gin","categoryKey":"food","segments":[{"text":"ของ","sound":"khǎwng"},{"text":"กิน","sound":"gin"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"bda65912-fa0a-5328-a7d4-302245d61c3e","text":"ง","kind":"consonant","romanization":"ng","pronunciationHint":"ng as in \"singer\"; used at the start or end of a syllable","mnemonic":"ง is ง งู (ngor nguu, snake). Picture the curving body of a snake; ง makes the ng sound that English only uses at the ends of words.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"163cd892-8102-57c0-aa71-21b8dc0c8678","key":"ng-sound","name":"ง Is the ng Sound","shortDescription":"ง gives the ng sound at the start or end of a syllable","explanation":"English only uses ng at the ends of words like ''song''. Thai uses ง freely, including at the start of a syllable. Either way it is the same soft nasal ng.","examples":[{"text":"ของ = khǎwng"},{"text":"งา = ngaa"}]},{"id":"75fcd479-d9cf-5987-a10f-effe48730a52","key":"final-ng","name":"Final ง Closes With ng","shortDescription":"At the end of a syllable, ง closes it with the nasal ng","explanation":"Final ง is extremely common in Thai. It is fully pronounced as the ng you hear at the end of ''song'', not clipped like the final stops you learned earlier.","examples":[{"text":"ของ = khǎwng"},{"text":"ทาง = thaang"}]},{"id":"e0feec68-c9f5-560f-a48c-dce0e36b48ce","key":"aw-vowel-or","name":"อ Can Be the aw Vowel","shortDescription":"After a consonant, อ gives the long aw sound","explanation":"You met อ as a silent carrier earlier. When อ is written after a consonant with no other vowel, it instead acts as the long aw vowel you hear in ของ and รอ.","examples":[{"text":"ของ = khǎwng"},{"text":"รอ = raw"}]}],"drills":[{"id":"2c7ff6fe-a5d7-56be-a695-26aa94913f3a","key":"khong-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"ng\" sound?","payload":{},"options":[{"text":"ง","isCorrect":true},{"text":"ม"},{"text":"น"},{"text":"ก"}]},{"id":"2cde3217-ca55-5ddb-a041-c02a68be27d7","key":"khong-drill-02-sound","type":"sound","prompt":"At the end of a syllable, how does ง sound?","payload":{},"options":[{"text":"k"},{"text":"ng","isCorrect":true},{"text":"n"},{"text":"m"}]},{"id":"5cfde455-3015-574c-ad2e-0f9777fee672","key":"khong-drill-03-sound","type":"sound","prompt":"When อ comes after a consonant as a vowel, what sound does it give?","payload":{},"options":[{"text":"long \"aw\"","isCorrect":true},{"text":"long \"ee\""},{"text":"short \"a\""},{"text":"long \"oo\""}]},{"id":"f60dda26-339f-53bb-a35b-13b3cce62428","key":"khong-drill-04-match","type":"match","prompt":"What does ของ mean?","payload":{},"options":[{"text":"of / belonging to","isCorrect":true},{"text":"way"},{"text":"game"},{"text":"medicine"}]},{"id":"ad3efbe4-8f7b-5cd9-a0ee-022b94fb4cb3","key":"khong-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"of / belonging to\"?","payload":{},"options":[{"text":"ของ","isCorrect":true},{"text":"งอข"},{"text":"ขงอ"},{"text":"ของน"}]},{"id":"ebe4f897-b647-5bd2-a933-2bf6b780ec87","key":"khong-drill-06-sound","type":"sound","prompt":"Which sound ends the word ของ?","payload":{},"options":[{"text":"ng","isCorrect":true},{"text":"k"},{"text":"t"},{"text":"m"}]}]}}'::jsonb, '70ac57aa0031fe5ad972bbe4628b27d49ba816b97f907975d187630e35c6cc0e', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('19637d3a-b137-5c60-a525-65300170bec1'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '3a606423-7c75-5465-a2f4-94d6250f99c8'::uuid, 'thang', 15, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"3a606423-7c75-5465-a2f4-94d6250f99c8","slug":"thang","lessonOrdinal":15,"stage":6,"title":"ทาง — Aspirated th and Wayfinding","anchor":{"id":"41ea5980-7420-51d8-a418-5d4411c1c665","slug":"thang","text":"ทาง","meaning":"way / direction","pronunciation":"thaang","categoryKey":"sign","contextNote":"ทาง marks routes and directions on signs everywhere. ทางออก (way out / exit) is one of the most useful sign words you can learn to spot.","segments":[{"text":"ทา","sound":"thaa"},{"text":"ง","sound":"ng"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"5fc36af8-3e9d-55f7-a9b1-4681c39b7e4c","key":"word-0e17-0e32","text":"ทา","meaning":"to apply / spread on","pronunciation":"thaa","categoryKey":"daily","segments":[{"text":"ทา","sound":"thaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"602ae36a-a89b-537d-a81c-735588da2148","key":"word-0e17-0e32-0e19","text":"ทาน","meaning":"to eat (polite)","pronunciation":"thaan","categoryKey":"food","segments":[{"text":"ทาน","sound":"thaan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"0962b566-6603-5e1f-a7fc-fab26f7569c4","key":"word-0e17-0e2d-0e07","text":"ทอง","meaning":"gold","pronunciation":"thawng","categoryKey":"daily","segments":[{"text":"ทอง","sound":"thawng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":false,"item":{"id":"8521348d-9b96-5292-a21e-d8a95f62f942","key":"word-0e17-0e35-0e48","text":"ที่","meaning":"at / place","pronunciation":"thîi","categoryKey":"daily","segments":[{"text":"ที่","sound":"thîi"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"ccd2ccb2-daeb-51bd-a2d9-f43f44cb4bc2","key":"word-0e17-0e38-0e01","text":"ทุก","meaning":"every","pronunciation":"thúk","categoryKey":"daily","segments":[{"text":"ทุก","sound":"thúk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"702a72bd-7469-5daf-aaf4-d7477252414d","key":"word-0e17-0e48-0e32-0e19","text":"ท่าน","meaning":"you (formal)","pronunciation":"thâan","categoryKey":"daily","segments":[{"text":"ท่าน","sound":"thâan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"a0167fb9-17e3-5c3d-a361-b75cb348bd96","key":"word-0e17-0e2d-0e14","text":"ทอด","meaning":"to deep-fry","pronunciation":"thâwt","categoryKey":"food","segments":[{"text":"ทอด","sound":"thâwt"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"705e3cbe-5672-5abc-a288-c6852ec41006","key":"word-0e17-0e35-0e27-0e35","text":"ทีวี","meaning":"TV","pronunciation":"thii-wii","categoryKey":"daily","segments":[{"text":"ที","sound":"thii"},{"text":"วี","sound":"wii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"1a20e67d-fcf6-56b8-afef-4944afcefc8d","key":"word-0e17-0e32-0e07-0e2d-0e2d-0e01","text":"ทางออก","meaning":"exit","pronunciation":"thaang awk","categoryKey":"sign","segments":[{"text":"ทาง","sound":"thaang"},{"text":"ออก","sound":"awk"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"cf8eaddc-cd8e-55ca-a652-237794f23e8b","text":"ท","kind":"consonant","romanization":"th","pronunciationHint":"th with a puff of air, like the \"t\" in \"top\" (not the th in \"the\")","mnemonic":"ท is ท ทหาร (thor thahaan, soldier). Picture a soldier standing tall; ท gives the aspirated th sound with a clear puff of air.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"bda65912-fa0a-5328-a7d4-302245d61c3e","text":"ง","kind":"consonant","romanization":"ng","pronunciationHint":"ng as in \"singer\"; used at the start or end of a syllable","mnemonic":"ง is ง งู (ngor nguu, snake). Picture the curving body of a snake; ง makes the ng sound that English only uses at the ends of words.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"831cdc66-6fb7-575f-acb5-7fb543f0e666","key":"low-th","name":"ท Is an Aspirated th","shortDescription":"ท starts with a puff of air, like the t in ''top''","explanation":"Thai ท is not the soft th in ''the''. It is a t sound released with a clear puff of air, the same way English starts the word ''top''.","examples":[{"text":"ทาง = thaang"},{"text":"ทา = thaa"}]},{"id":"09daaa09-a96a-517d-a22c-c5b2a68c1bf9","key":"th-vs-t","name":"ท and ต Are Different t Sounds","shortDescription":"ต is a tight, unaspirated t (dt); ท adds a puff of air","explanation":"ต and ท both involve the tongue behind the teeth, but ต is clipped with no air (closer to a d/t blend) while ท releases a puff of air. Keeping them apart changes the word.","examples":[{"text":"ตา = dtaa"},{"text":"ทา = thaa"}]}],"drills":[{"id":"e9695cb3-384c-5122-adbd-e12d25ad5ba9","key":"thang-drill-01-recognize","type":"recognize","prompt":"Which letter makes the aspirated \"th\" sound?","payload":{},"options":[{"text":"ท","isCorrect":true},{"text":"ต"},{"text":"ด"},{"text":"บ"}]},{"id":"ba71c554-7960-5fe4-af12-74eb173bb381","key":"thang-drill-02-sound","type":"sound","prompt":"How is ท different from ต?","payload":{},"options":[{"text":"ท is released with a puff of air","isCorrect":true},{"text":"they are identical"},{"text":"ท is a vowel"},{"text":"ต is nasal"}]},{"id":"2882ee13-49de-548a-af42-b6ed3f8bc504","key":"thang-drill-03-match","type":"match","prompt":"What does ทาง mean?","payload":{},"options":[{"text":"way / direction","isCorrect":true},{"text":"of"},{"text":"closed"},{"text":"medicine"}]},{"id":"d44515bf-7268-5e42-ad55-5b13e0ddca86","key":"thang-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"way / direction\"?","payload":{},"options":[{"text":"ทาง","isCorrect":true},{"text":"งทา"},{"text":"ทงา"},{"text":"ทาน"}]},{"id":"d781c4a5-2d5a-5056-a7e5-e0d1e5370573","key":"thang-drill-05-sound","type":"sound","prompt":"Which sound ends the word ทาง?","payload":{},"options":[{"text":"ng","isCorrect":true},{"text":"th"},{"text":"k"},{"text":"aa"}]}]}}'::jsonb, 'be8b9b29b5bd300793fb5538826732b04c40ac1912d1460f7135e533bf38fe2d', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('39717731-ece4-5e7b-a7ca-9d9cfd34aa0a'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '7282cb0a-aba7-5f75-a56b-f027f905a879'::uuid, 'ja', 16, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"7282cb0a-aba7-5f75-a56b-f027f905a879","slug":"ja","lessonOrdinal":16,"stage":6,"title":"จะ — j and the Short-a Glottal Stop","anchor":{"id":"cd23b164-7b20-5878-ae97-35dbb1d4b85f","slug":"ja","text":"จะ","meaning":"will (future particle)","pronunciation":"jà","categoryKey":"daily","contextNote":"จะ is a core grammar word placed before a verb to mean something will happen: จะกิน (will eat), จะมา (will come). You''ll read it in countless sentences.","segments":[{"text":"จะ","sound":"jà"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"e0566342-975c-5a4a-aa27-dc69d214347a","key":"word-0e08-0e32-0e19","text":"จาน","meaning":"plate","pronunciation":"jaan","categoryKey":"food","segments":[{"text":"จาน","sound":"jaan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"18d67dfd-c6b1-5c13-af5c-c3c7f4239e46","key":"word-0e08-0e14","text":"จด","meaning":"to write down","pronunciation":"jòt","categoryKey":"daily","segments":[{"text":"จด","sound":"jòt"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"0fd37fe8-f4d2-57fd-a068-5f911301065c","key":"word-0e01-0e30","text":"กะ","meaning":"to estimate / guess","pronunciation":"gà","categoryKey":"daily","segments":[{"text":"กะ","sound":"gà"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":false,"item":{"id":"0afa03f2-642d-5a71-aab6-f551d7e99fc1","key":"word-0e08-0e1a","text":"จบ","meaning":"to finish / end","pronunciation":"jòp","categoryKey":"daily","segments":[{"text":"จบ","sound":"jòp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"9531098c-7c7d-59e1-aa6e-f2b7b41671ac","key":"word-0e41-0e25-0e30","text":"และ","meaning":"and","pronunciation":"láe","categoryKey":"daily","segments":[{"text":"และ","sound":"láe"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"017d8621-0ce8-51ce-a16c-5740c4f2ff84","key":"word-0e08-0e2d-0e14","text":"จอด","meaning":"to park","pronunciation":"jàwt","categoryKey":"sign","segments":[{"text":"จอด","sound":"jàwt"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":true,"item":{"id":"46f0968d-b9f4-566e-a2a9-e77c34a12497","key":"word-0e08-0e30-0e01-0e34-0e19","text":"จะกิน","meaning":"will eat","pronunciation":"jà gin","categoryKey":"food","segments":[{"text":"จะ","sound":"jà"},{"text":"กิน","sound":"gin"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":true,"item":{"id":"595823e3-31b9-52d6-a7e0-a1d1f53f8f1e","key":"word-0e08-0e30-0e21-0e32","text":"จะมา","meaning":"will come","pronunciation":"jà maa","categoryKey":"daily","segments":[{"text":"จะ","sound":"jà"},{"text":"มา","sound":"maa"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"e4575690-2031-5d02-a9ed-227f99686432","text":"จ","kind":"consonant","romanization":"j","pronunciationHint":"j as in \"jar\", but lighter and unaspirated","mnemonic":"จ is จ จาน (jor jaan, plate). Picture a round dinner plate; จ gives a light, crisp j sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f4bda34e-a00e-53ac-a756-196e4fd86dcb","text":"ะ","kind":"vowel","romanization":"a","pronunciationHint":"short \"a\" cut off by a quick glottal stop, like a clipped \"ah!\"","mnemonic":"ะ is the two-dot short-a written to the right of the consonant. It ends the syllable abruptly, like catching your breath after ''ah''.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"9593d6a6-13bb-563d-a33d-b01dd74e3528","text":"ช","kind":"consonant","romanization":"ch","pronunciationHint":"ch as in \"check\"","mnemonic":"ช is ช ช้าง (chor chaang, elephant). Picture the long dropping stroke as an elephant trunk, and use ช้าง for the ch sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"6655bad5-f432-5868-aa67-e7247253802f","text":"ั","kind":"vowel","romanization":"a","pronunciationHint":"short \"a\" as in \"cut\"","mnemonic":"ั is the short a cap above the consonant. It sits close and quick, just like the clipped a in ผัด and ผัก.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"d483daf3-63c0-5acc-a73d-c558c388f8af","key":"j-sound","name":"จ Is a Light j","shortDescription":"จ gives an unaspirated j sound","explanation":"จ is close to the English j in ''jar'' but lighter, with no puff of air. It is a mid-class consonant, which keeps its tones predictable.","examples":[{"text":"จะ = jà"},{"text":"จาน = jaan"}]},{"id":"433a210b-ee14-514f-a228-9f28e323f475","key":"short-a-glottal","name":"ะ Is a Clipped Short a","shortDescription":"ะ sits after the consonant and ends with a glottal stop","explanation":"The ะ vowel gives a short a, then closes the syllable sharply with a glottal stop (the catch in the middle of ''uh-oh''). It is quicker than the long า.","examples":[{"text":"จะ = jà"},{"text":"กะ = gà"}]},{"id":"a2c1d059-1ef1-57a9-ab6c-a4aa2f120298","key":"three-a-vowels","name":"Three Ways to Write a","shortDescription":"า is long; ั is short above; ะ is short with a hard stop","explanation":"You now know all three core a-vowels: า stretches long to the right, ั is a quick short a above the consonant, and ะ is a short a after it that ends in a glottal stop.","examples":[{"text":"มา = maa"},{"text":"มัน = man"},{"text":"จะ = jà"}]}],"drills":[{"id":"007ca9f9-a4a3-5ac8-a2e9-a1c738f6ba4a","key":"ja-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"j\" sound?","payload":{},"options":[{"text":"จ","isCorrect":true},{"text":"ช"},{"text":"ต"},{"text":"ด"}]},{"id":"d0072ce1-cc6a-5e87-a999-fe62f3d795b4","key":"ja-drill-02-recognize","type":"recognize","prompt":"Which vowel is the short \"a\" that ends with a glottal stop?","payload":{},"options":[{"text":"ะ","isCorrect":true},{"text":"า"},{"text":"ั"},{"text":"ิ"}]},{"id":"96bcad97-3d3f-5a94-a905-d31429beca06","key":"ja-drill-03-match","type":"match","prompt":"What does จะ mean?","payload":{},"options":[{"text":"will (future)","isCorrect":true},{"text":"way"},{"text":"of"},{"text":"game"}]},{"id":"17323211-217c-551e-a3b7-30b0c9814b3f","key":"ja-drill-04-sound","type":"sound","prompt":"How does the syllable จะ end?","payload":{},"options":[{"text":"with a quick glottal stop","isCorrect":true},{"text":"with a long aa"},{"text":"with an ng sound"},{"text":"with a k sound"}]},{"id":"cdeab6aa-aec8-5baa-a3e1-7ee7ee62cffc","key":"ja-drill-05-spot","type":"spot","prompt":"Which Thai spelling is the future particle?","payload":{},"options":[{"text":"จะ","isCorrect":true},{"text":"ชะ"},{"text":"จา"},{"text":"ตะ"}]}]}}'::jsonb, '11314cfcb5f397df8e000b7a6a1172b07472b74f5ad06f9d92057e48c9b4a8a4', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('63e4c1f2-aa02-5214-a3e2-cf7fcc2d8e25'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '8df83813-8fd3-546a-a5bd-bf786e534b3b'::uuid, 'kem', 17, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"8df83813-8fd3-546a-a5bd-bf786e534b3b","slug":"kem","lessonOrdinal":17,"stage":6,"title":"เกม — Your First Leading Vowel","anchor":{"id":"718088c1-9980-5540-ae97-4a03b319a76e","slug":"kem","text":"เกม","meaning":"game","pronunciation":"geem","categoryKey":"daily","contextNote":"เกม is a loanword you''ll see on phones, arcades, and shopfronts like ร้านเกม (game shop). It''s a clean way to learn how leading vowels work.","segments":[{"text":"เก","sound":"gee"},{"text":"ม","sound":"m"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"59e11b50-5f14-5516-a61d-a46f13cd162e","key":"word-0e40-0e17","text":"เท","meaning":"to pour","pronunciation":"thee","categoryKey":"daily","segments":[{"text":"เท","sound":"thee"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"ab6b1225-a683-51e4-adf2-8cde3ccf3e07","key":"word-0e40-0e15-0e30","text":"เตะ","meaning":"to kick","pronunciation":"dtè","categoryKey":"daily","segments":[{"text":"เตะ","sound":"dtè"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"e7ab4bc3-5c7d-5269-a883-8a82152f894e","key":"word-0e40-0e25-0e02","text":"เลข","meaning":"number","pronunciation":"lêek","categoryKey":"sign","segments":[{"text":"เลข","sound":"lêek"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":false,"item":{"id":"bce2facb-d6d5-5a3f-a2eb-a45dd6c1f139","key":"word-0e40-0e2d-0e32","text":"เอา","meaning":"to want / take","pronunciation":"ao","categoryKey":"daily","segments":[{"text":"เอา","sound":"ao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"d6f83b16-c9bc-57e5-ac55-a3756ff19618","key":"word-0e40-0e0a-0e49-0e32","text":"เช้า","meaning":"morning","pronunciation":"cháo","categoryKey":"daily","segments":[{"text":"เช้า","sound":"cháo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"f97e5aaf-f4dd-5bfa-a099-6e8dc1904513","key":"word-0e40-0e25-0e48-0e19","text":"เล่น","meaning":"to play","pronunciation":"lên","categoryKey":"daily","segments":[{"text":"เล่น","sound":"lên"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"3ca753d0-7cf2-53c3-a121-0729f4058bb4","key":"word-0e40-0e07-0e34-0e19","text":"เงิน","meaning":"money","pronunciation":"ngern","categoryKey":"daily","segments":[{"text":"เงิน","sound":"ngern"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"c1de64c7-8d63-54e9-a8af-2efd58ea08f5","key":"word-0e40-0e27-0e25-0e32","text":"เวลา","meaning":"time","pronunciation":"wee-laa","categoryKey":"daily","segments":[{"text":"เว","sound":"wee"},{"text":"ลา","sound":"laa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"19c0120f-0122-599f-a6e8-0c3e3adf72ed","key":"word-0e40-0e01-0e30","text":"เกะ","meaning":"sound-only practice","pronunciation":"gè","categoryKey":"daily","segments":[{"text":"เกะ","sound":"gè"}],"metadata":{"sourceType":"nonsense"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"d930649b-b987-5148-a7d1-8aaabef44060","text":"เ","kind":"vowel","romanization":"e","pronunciationHint":"long \"e\" as in \"they\"","mnemonic":"เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"1684cb46-8524-51a4-ad84-8dd2fe3b46be","text":"แ","kind":"vowel","romanization":"ae","pronunciationHint":"long \"ae\" as in the vowel of \"care\"","mnemonic":"แ is a double left-side vowel. The two front posts tell your eye to look left first, then come back to the consonant for ae.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"939342eb-ed8d-5580-a1cd-b756e757ffba","key":"leading-e-vowel","name":"เ Is Written Before the Consonant","shortDescription":"เ appears to the left but is pronounced after the consonant","explanation":"Some Thai vowels are written in front of their consonant even though they are spoken after it. เ is the first of these: it gives a long e, but you read the consonant that follows it first.","examples":[{"text":"เก = gee"},{"text":"เกม = geem"}]},{"id":"6409b125-3787-5409-af45-9681cf842fdf","key":"scan-left-rule","name":"Scan Left for Leading Vowels","shortDescription":"When a word starts with เ, read the next consonant first","explanation":"When you see a leading vowel like เ at the front of a syllable, do not read straight across. Read the consonant after it, then wrap the vowel around. This same habit covers ไ, ใ, and โ next.","examples":[{"text":"เกม = geem"},{"text":"เท = thee"}]}],"drills":[{"id":"622c854f-4d2d-5cb3-acd3-32e36e73dc97","key":"kem-drill-01-recognize","type":"recognize","prompt":"Which vowel is written before the consonant and gives a long \"e\"?","payload":{},"options":[{"text":"เ","isCorrect":true},{"text":"แ"},{"text":"า"},{"text":"ิ"}]},{"id":"f6455f92-9a9f-51e4-a3da-bdde93cbe8ac","key":"kem-drill-02-sound","type":"sound","prompt":"In เกม, where is เ written and when is it pronounced?","payload":{},"options":[{"text":"before the consonant, but pronounced after it","isCorrect":true},{"text":"after the consonant"},{"text":"above the consonant"},{"text":"below the consonant"}]},{"id":"20e501c4-3282-5375-ad2f-8523fd0bbcd6","key":"kem-drill-03-match","type":"match","prompt":"What does เกม mean?","payload":{},"options":[{"text":"game","isCorrect":true},{"text":"way"},{"text":"medicine"},{"text":"closed"}]},{"id":"9e2613e1-4129-50b8-af59-02f667000da6","key":"kem-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"game\"?","payload":{},"options":[{"text":"เกม","isCorrect":true},{"text":"แกม"},{"text":"เมก"},{"text":"กเม"}]},{"id":"e4fe2818-459a-5a0a-a3be-f0b7447e1392","key":"kem-drill-05-sound","type":"sound","prompt":"How do you read a word that starts with เ?","payload":{},"options":[{"text":"read the next consonant first, then add the vowel","isCorrect":true},{"text":"read strictly left to right"},{"text":"ignore the เ"},{"text":"the เ is silent"}]}]}}'::jsonb, 'd6650f5bbf9b9e2b06f36ad20660fbc133e572bd8c8f9277b6486426a4790150', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('e7bffa47-ed14-5822-a321-70b8d6bd5683'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '220e45ef-a665-57fb-af90-9359b64d941b'::uuid, 'gai', 18, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"220e45ef-a665-57fb-af90-9359b64d941b","slug":"gai","lessonOrdinal":18,"stage":6,"title":"ไก่ — The Two ai Vowels","anchor":{"id":"29f69529-8848-57e6-aefc-97277fe6fce5","slug":"gai","text":"ไก่","meaning":"chicken","pronunciation":"gài","categoryKey":"food","contextNote":"ไก่ means chicken and appears on menus everywhere — ข้าวมันไก่ (chicken rice) is a national favorite. It also teaches the two leading ai vowels.","segments":[{"text":"ไก่","sound":"gài"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"4d5c0edd-c178-5d56-a617-cf4cbbdb29c9","key":"word-0e44-0e21-0e48","text":"ไม่","meaning":"not","pronunciation":"mâi","categoryKey":"daily","segments":[{"text":"ไม่","sound":"mâi"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"caaaef54-6e9d-5a48-a804-2209e230a7fb","key":"word-0e43-0e08","text":"ใจ","meaning":"heart / mind","pronunciation":"jai","categoryKey":"daily","segments":[{"text":"ใจ","sound":"jai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"f748ebfc-5d91-564d-aa5f-460388db2d02","key":"word-0e43-0e0a-0e48","text":"ใช่","meaning":"yes / that''s right","pronunciation":"châi","categoryKey":"daily","segments":[{"text":"ใช่","sound":"châi"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"2b62afe2-e480-5864-a7c6-9310bb7593e8","key":"word-0e44-0e2b-0e19","text":"ไหน","meaning":"where / which","pronunciation":"nǎi","categoryKey":"daily","segments":[{"text":"ไหน","sound":"nǎi"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"ac56c769-bb8f-5ee9-ab22-642b4e94cabb","key":"word-0e43-0e2b-0e21-0e48","text":"ใหม่","meaning":"new","pronunciation":"mài","categoryKey":"daily","segments":[{"text":"ใหม่","sound":"mài"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"92155fd9-ff47-5779-a013-528f056f18dd","key":"word-0e44-0e14-0e49","text":"ได้","meaning":"can / to get","pronunciation":"dâai","categoryKey":"daily","segments":[{"text":"ได้","sound":"dâai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"3ba715f3-bd01-5ab4-aa5d-de45bc5bd528","key":"word-0e44-0e2b-0e21","text":"ไหม","meaning":"(question particle)","pronunciation":"mǎi","categoryKey":"daily","segments":[{"text":"ไหม","sound":"mǎi"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"daa00e69-d751-5829-a515-240942f6f447","key":"word-0e43-0e0a-0e49","text":"ใช้","meaning":"to use","pronunciation":"chái","categoryKey":"daily","segments":[{"text":"ใช้","sound":"chái"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"258ff941-6ca1-5f00-a022-96ffb4e2fe13","key":"word-0e43-0e19","text":"ใน","meaning":"in","pronunciation":"nai","categoryKey":"daily","segments":[{"text":"ใน","sound":"nai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"f70b59aa-c5e7-5040-a94d-07669a4422b7","key":"word-0e43-0e2b-0e49","text":"ให้","meaning":"to give / for","pronunciation":"hâi","categoryKey":"daily","segments":[{"text":"ให้","sound":"hâi"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":false,"item":{"id":"46cb62c9-1a11-5fce-a587-a96188798b13","key":"word-0e44-0e02-0e48","text":"ไข่","meaning":"egg","pronunciation":"khài","categoryKey":"food","segments":[{"text":"ไข่","sound":"khài"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-tone-mark","title":"Tone mark","body":"Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify."}],"newGraphemes":[{"id":"d636b36c-e319-5414-ad3e-8657562bd576","text":"ไ","kind":"vowel","romanization":"ai","pronunciationHint":"the \"ai\" sound as in \"Thai\"","mnemonic":"ไ (ไม้มลาย, mai malai) is the common ai vowel, written before the consonant. Note the small flag curling off the top.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"54ee9c51-1ccc-59bb-a95d-2e6f8d66ecf1","text":"ใ","kind":"vowel","romanization":"ai","pronunciationHint":"the same \"ai\" sound as ไ","mnemonic":"ใ (ไม้ม้วน, mai muan) sounds identical to ไ but appears in only about 20 specific words you memorize. Note the curled-in top.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"13e7c7cd-283c-5d0b-a9cc-ce5b3831e495","text":"่","kind":"tone_mark","romanization":"mai ek","pronunciationHint":"first tone mark written above the consonant","mnemonic":"่ is mai ek, the first tone mark. It is one small stroke above the consonant, so read it as a compact tone cue.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]},{"id":"e4575690-2031-5d02-a9ed-227f99686432","text":"จ","kind":"consonant","romanization":"j","pronunciationHint":"j as in \"jar\", but lighter and unaspirated","mnemonic":"จ is จ จาน (jor jaan, plate). Picture a round dinner plate; จ gives a light, crisp j sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"2bcd40f2-7394-5631-a41e-47605ee7d502","key":"leading-ai","name":"ไ and ใ Are Leading ai Vowels","shortDescription":"Both sound like ''ai'' and are written before the consonant","explanation":"ไ and ใ are leading vowels, just like เ: written in front of the consonant, pronounced after it. Both give the same ai sound you hear in the word ''Thai''.","examples":[{"text":"ไก่ = gài"},{"text":"ใจ = jai"}]},{"id":"203bfa56-3595-5e10-a6b0-aca06096f272","key":"mai-malai-vs-muan","name":"Two Spellings, One Sound","shortDescription":"ไ is the common ai; ใ covers only about 20 must-know words","explanation":"ไ (mai malai) is by far the more common spelling. ใ (mai muan) sounds exactly the same but is used in roughly 20 fixed words, such as ใจ (heart), ใหม่ (new), and ใช่ (yes). Those are worth memorizing as a set.","examples":[{"text":"ไก่ = gài"},{"text":"ใจ = jai"}]}],"drills":[{"id":"74b2e9b3-c075-59d2-aa0f-6d94a842affb","key":"gai-drill-01-recognize","type":"recognize","prompt":"Which vowel gives the \"ai\" sound and is the common one?","payload":{},"options":[{"text":"ไ","isCorrect":true},{"text":"ใ"},{"text":"เ"},{"text":"แ"}]},{"id":"c0d0a1ad-55a3-582e-a5c1-040c097d62ff","key":"gai-drill-02-sound","type":"sound","prompt":"How do ไ and ใ differ in sound?","payload":{},"options":[{"text":"they sound identical","isCorrect":true},{"text":"ไ is longer"},{"text":"ใ is a tone mark"},{"text":"ไ is silent"}]},{"id":"35268dce-077e-5175-a57c-490da1f45fe5","key":"gai-drill-03-match","type":"match","prompt":"What does ไก่ mean?","payload":{},"options":[{"text":"chicken","isCorrect":true},{"text":"game"},{"text":"way"},{"text":"medicine"}]},{"id":"578055a0-784a-528d-ab7e-85f17d8c9353","key":"gai-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"chicken\"?","payload":{},"options":[{"text":"ไก่","isCorrect":true},{"text":"ใก่"},{"text":"ไก"},{"text":"กไ่"}]},{"id":"7f8f8915-0ed6-536a-a11a-06533150d50d","key":"gai-drill-05-recognize","type":"recognize","prompt":"ใ (mai muan) is used in roughly how many words?","payload":{},"options":[{"text":"about 20","isCorrect":true},{"text":"over a thousand"},{"text":"none"},{"text":"about two hundred"}]}]}}'::jsonb, '5bd7f8203ee31d91ffe241b356cd312ac5978593b90341b3a66093b97398ff5d', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('22cf148a-6038-506d-abfc-149bef8be6da'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'a5eb07e9-b71d-59c8-a3ac-ce5fab1e5fc0'::uuid, 'to', 19, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"a5eb07e9-b71d-59c8-a3ac-ce5fab1e5fc0","slug":"to","lessonOrdinal":19,"stage":6,"title":"โต — The Leading Long-o Vowel","anchor":{"id":"0effddc9-d911-5f5a-a5a3-dda9b5454195","slug":"to","text":"โต","meaning":"big / to grow","pronunciation":"dtoo","categoryKey":"daily","contextNote":"โต means big or to grow up. It teaches the leading long-o vowel โ, which — like เ and ไ — is written before the consonant but spoken after it.","segments":[{"text":"โต","sound":"dtoo"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"629d2c25-1535-5927-acbf-79eacfc2f9ff","key":"word-0e42-0e21-0e07","text":"โมง","meaning":"o''clock","pronunciation":"moong","categoryKey":"daily","segments":[{"text":"โมง","sound":"moong"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"fd263eb3-967a-512b-a57f-87dfe59f7bd4","key":"word-0e42-0e14-0e19","text":"โดน","meaning":"to get / be affected by","pronunciation":"doon","categoryKey":"daily","segments":[{"text":"โดน","sound":"doon"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"37f6b886-3654-5907-acd5-3093bc491a06","key":"word-0e42-0e07-0e48","text":"โง่","meaning":"silly / foolish","pronunciation":"ngôo","categoryKey":"daily","segments":[{"text":"โง่","sound":"ngôo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"69052388-c521-5bb6-a06d-45f1336801d4","key":"word-0e42-0e25","text":"โล","meaning":"kilo","pronunciation":"loo","categoryKey":"sign","segments":[{"text":"โล","sound":"loo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"15359918-5431-5185-ac0d-bd9359f765cc","key":"word-0e42-0e17-0e23","text":"โทร","meaning":"to phone","pronunciation":"thoo","categoryKey":"daily","segments":[{"text":"โทร","sound":"thoo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"56dd46ae-0bf9-5ff5-a22a-d0240fe91b57","key":"word-0e42-0e23-0e07","text":"โรง","meaning":"building / hall","pronunciation":"roong","categoryKey":"place","segments":[{"text":"โรง","sound":"roong"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"da7d4e63-eda1-5c0b-a7bd-7089ed3601ce","key":"word-0e42-0e01-0e2b-0e01","text":"โกหก","meaning":"to lie","pronunciation":"goo-hòk","categoryKey":"daily","segments":[{"text":"โก","sound":"goo"},{"text":"หก","sound":"hòk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"1b806a4a-3d50-5dc0-aa1f-9a02be7047f0","key":"word-0e42-0e21-0e42-0e2b","text":"โมโห","meaning":"angry","pronunciation":"moo-hǒo","categoryKey":"daily","segments":[{"text":"โม","sound":"moo"},{"text":"โห","sound":"hǒo"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"6450d4bf-a0e5-5f34-aaad-6b404ea92b59","text":"โ","kind":"vowel","romanization":"o","pronunciationHint":"long \"o\" as in \"go\"","mnemonic":"โ is the long-o vowel with a tall vertical stroke, written before the consonant. Like เ and ไ, read the consonant after it first.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"d930649b-b987-5148-a7d1-8aaabef44060","text":"เ","kind":"vowel","romanization":"e","pronunciationHint":"long \"e\" as in \"they\"","mnemonic":"เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"d636b36c-e319-5414-ad3e-8657562bd576","text":"ไ","kind":"vowel","romanization":"ai","pronunciationHint":"the \"ai\" sound as in \"Thai\"","mnemonic":"ไ (ไม้มลาย, mai malai) is the common ai vowel, written before the consonant. Note the small flag curling off the top.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"615f71c4-a9dc-55aa-a872-f0955ec5ea8c","key":"leading-long-o","name":"โ Is a Leading Long o","shortDescription":"โ sits before the consonant and gives a long o","explanation":"โ is another leading vowel. It is written in front of the consonant and gives a clean long o, like the vowel in English ''go''.","examples":[{"text":"โต = dtoo"},{"text":"โล = loo"}]},{"id":"14b01fb1-3ab2-54ba-abe7-5517eb3f1af9","key":"leading-vowel-family","name":"The Leading-Vowel Family","shortDescription":"เ, ไ, ใ, and โ are all written before the consonant","explanation":"You now know four leading vowels: เ (e), ไ and ใ (ai), and โ (o). All four break the left-to-right order — write them first, but read the following consonant before adding the vowel.","examples":[{"text":"เกม = geem"},{"text":"ไก่ = gài"},{"text":"โต = dtoo"}]}],"drills":[{"id":"b9b6f9b1-b189-5df7-a21f-9da6054d0c8d","key":"to-drill-01-recognize","type":"recognize","prompt":"Which vowel gives a long \"o\" and is written before the consonant?","payload":{},"options":[{"text":"โ","isCorrect":true},{"text":"เ"},{"text":"แ"},{"text":"ไ"}]},{"id":"91115ced-df10-5611-a5d4-ece820a8a876","key":"to-drill-02-sound","type":"sound","prompt":"In โต, which sound do you say first?","payload":{},"options":[{"text":"the consonant ต, then the o","isCorrect":true},{"text":"the o, then ต"},{"text":"they blend together"},{"text":"ต is silent"}]},{"id":"f8772626-00d7-503c-a415-9654a9ad9896","key":"to-drill-03-match","type":"match","prompt":"What does โต mean?","payload":{},"options":[{"text":"big / to grow","isCorrect":true},{"text":"chicken"},{"text":"closed"},{"text":"game"}]},{"id":"8ff33741-65f1-590d-a54c-0ed4489fe5de","key":"to-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"big\"?","payload":{},"options":[{"text":"โต","isCorrect":true},{"text":"โด"},{"text":"เต"},{"text":"ตโ"}]},{"id":"4ce9dbc2-2ae7-557e-a2d0-ea7f918d7894","key":"to-drill-05-recognize","type":"recognize","prompt":"Which of these vowels is NOT written before the consonant?","payload":{},"options":[{"text":"ี","isCorrect":true},{"text":"เ"},{"text":"ไ"},{"text":"โ"}]}]}}'::jsonb, '47491dc0b8ab87bc78fcfbdd103b84ec1d2ca7d82fb6699d3b49f687ada2da6e', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('6dc45c89-7313-59c5-af27-73c8d93b95c1'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'd1d3fe12-62f5-5fa6-ab64-c59a5156b603'::uuid, 'pit', 20, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"d1d3fe12-62f5-5fa6-ab64-c59a5156b603","slug":"pit","lessonOrdinal":20,"stage":6,"title":"ปิด — Mid p and the Open/Closed Pair","anchor":{"id":"953ff4f2-a5b7-5bda-abe3-51eab2ed86d0","slug":"pit","text":"ปิด","meaning":"closed","pronunciation":"bpìt","categoryKey":"sign","contextNote":"ปิด (closed) and เปิด (open) are the most useful sign pair in Thailand — on shops, doors, and opening hours. ป is a tight p, easy to confuse with บ.","segments":[{"text":"ปิ","sound":"bpì"},{"text":"ด","sound":"t"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"2f6d7782-aa00-517d-a01a-dbbcc35aef5d","key":"word-0e40-0e1b-0e34-0e14","text":"เปิด","meaning":"to open","pronunciation":"bpèrt","categoryKey":"sign","segments":[{"text":"เปิด","sound":"bpèrt"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"70d1713d-55b7-50af-ae71-0a4f199c01ed","key":"word-0e44-0e1b","text":"ไป","meaning":"to go","pronunciation":"bpai","categoryKey":"daily","segments":[{"text":"ไป","sound":"bpai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"c833b9cd-fa67-543d-ade0-de98f52acf36","key":"word-0e1b-0e25-0e32","text":"ปลา","meaning":"fish","pronunciation":"bplaa","categoryKey":"food","segments":[{"text":"ปลา","sound":"bplaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"1a80c504-1679-5d16-a24e-72044b0955b8","key":"word-0e1b-0e35","text":"ปี","meaning":"year","pronunciation":"bpii","categoryKey":"daily","segments":[{"text":"ปี","sound":"bpii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"3298e2e3-5f8b-5593-a778-1eef71986d23","key":"word-0e1b-0e32","text":"ปา","meaning":"to throw","pronunciation":"bpaa","categoryKey":"daily","segments":[{"text":"ปา","sound":"bpaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"2f9ad7a0-318a-5741-a2ae-787428f5bbdc","key":"word-0e1b-0e27-0e14","text":"ปวด","meaning":"to ache","pronunciation":"bpùuat","categoryKey":"daily","segments":[{"text":"ปวด","sound":"bpùuat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"c72309ee-2b8f-56f2-a94d-9e0b34f7cbc6","key":"word-0e1b-0e32-0e01","text":"ปาก","meaning":"mouth","pronunciation":"bpàak","categoryKey":"daily","segments":[{"text":"ปาก","sound":"bpàak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"b57c9c30-eb93-5f09-ab02-d77647f8fb64","key":"word-0e1b-0e01-0e15-0e34","text":"ปกติ","meaning":"normal","pronunciation":"bpòk-gà-dtì","categoryKey":"daily","segments":[{"text":"ปก","sound":"bpòk"},{"text":"ติ","sound":"gà-dtì"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"b849b0cd-ec22-5eda-a5a1-2fad524ff9d1","key":"word-0e1b-0e34-0e14-0e23-0e49-0e32-0e19","text":"ปิดร้าน","meaning":"to close a shop","pronunciation":"bpìt ráan","categoryKey":"sign","segments":[{"text":"ปิด","sound":"bpìt"},{"text":"ร้าน","sound":"ráan"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"1468f8a2-d91f-5127-ac8d-e40de6f54950","text":"ป","kind":"consonant","romanization":"bp","pronunciationHint":"a tight, unaspirated p, like the p in \"spin\" (between English b and p)","mnemonic":"ป is ป ปลา (bpor bplaa, fish). Picture a tall fish standing on its tail; ป is the unaspirated p that pairs with the dt sound of ต.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"dddb2e02-9aa3-5dde-a2ab-25524fc96559","text":"บ","kind":"consonant","romanization":"b/p","pronunciationHint":"b as in \"bat\" at the start; clipped p at the end","mnemonic":"บ is บ ใบไม้ (bor bai mai, leaf). The open bowl shape can hold a leaf, and ใบไม้ gives you the b sound at the start.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"da8975d2-f60a-59f9-a1d2-f55df44b6bfa","text":"ผ","kind":"consonant","romanization":"ph","pronunciationHint":"ph with a puff of air, like the start of \"photo\" without the f sound","mnemonic":"ผ is ผ ผึ้ง (phor phueng, bee). Picture the open shape as wings and body; ผึ้ง starts with the puffed ph sound.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"7dba55ea-1ad4-5d3c-a85d-9c7b7a6f3553","text":"ิ","kind":"vowel","romanization":"i","pronunciationHint":"short \"i\" as in \"sit\"","mnemonic":"ิ is the short i mark above the consonant. It has no extra length stroke, so keep the vowel quick in words like กิน.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"d930649b-b987-5148-a7d1-8aaabef44060","text":"เ","kind":"vowel","romanization":"e","pronunciationHint":"long \"e\" as in \"they\"","mnemonic":"เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"e5c49a63-f082-5af8-acd5-736ab3b9f0ff","key":"mid-p","name":"ป Is a Tight, Unaspirated p","shortDescription":"ป has no puff of air, like the p in ''spin''","explanation":"ป is a mid-class p with no aspiration. To an English ear it sits between b and p, like the p in ''spin''. It is distinct from the airy ผ you already know.","examples":[{"text":"ปิด = bpìt"},{"text":"ปา = bpaa"}]},{"id":"c890a4d0-1151-5225-a234-0a15bdc7bde5","key":"p-vs-b","name":"ป and บ Look and Sound Close","shortDescription":"ป (bp) and บ (b) are easy to mix up","explanation":"ป and บ have similar shapes and similar sounds. ป is taller with a flag on top and is slightly tighter. Compare ปิด (closed) with บิน (to fly) to feel the difference.","examples":[{"text":"ปิด = bpìt"},{"text":"บิน = bin"}]},{"id":"834616d7-e6ee-59ea-acc1-9766723d17a3","key":"open-closed-pair","name":"เปิด / ปิด: Open and Closed","shortDescription":"Adding the leading vowel เ turns ปิด (closed) into เปิด (open)","explanation":"This is the highest-value sign pair you can learn. ปิด means closed; put the leading vowel เ in front and you get เปิด, meaning open. You''ll read both on doors every day.","examples":[{"text":"ปิด = bpìt (closed)"},{"text":"เปิด = bpèrt (open)"}]}],"drills":[{"id":"8fc88a73-ba17-5255-ae07-5830dc0ec0f6","key":"pit-drill-01-recognize","type":"recognize","prompt":"Which letter is the tight, unaspirated \"p\"?","payload":{},"options":[{"text":"ป","isCorrect":true},{"text":"บ"},{"text":"ผ"},{"text":"ด"}]},{"id":"a54c1a3a-4a59-5990-ab35-43f6a0d7fb2e","key":"pit-drill-02-sound","type":"sound","prompt":"How does ป differ from ผ?","payload":{},"options":[{"text":"ป has no puff of air; ผ does","isCorrect":true},{"text":"they are identical"},{"text":"ป is a vowel"},{"text":"ผ is nasal"}]},{"id":"53cfbc23-3042-5c23-ab99-bb5404e65d92","key":"pit-drill-03-match","type":"match","prompt":"What does ปิด mean?","payload":{},"options":[{"text":"closed","isCorrect":true},{"text":"open"},{"text":"big"},{"text":"chicken"}]},{"id":"fc910999-9eeb-5a1e-ad3b-d70018593c19","key":"pit-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"closed\"?","payload":{},"options":[{"text":"ปิด","isCorrect":true},{"text":"บิด"},{"text":"ผิด"},{"text":"ปิน"}]},{"id":"77c6bda7-681d-5b59-abdd-e57ed7377a2f","key":"pit-drill-05-match","type":"match","prompt":"What does เปิด mean?","payload":{},"options":[{"text":"open","isCorrect":true},{"text":"closed"},{"text":"medicine"},{"text":"way"}]}]}}'::jsonb, '28d06f9a81fcf35877e29588c37b7e4de89e61ec7969e7ce39ae0ba6a06f59bf', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('37488384-01c2-5db8-a3f2-cf10d82f8818'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '9f1d8410-24a1-50ce-af53-d035634ca0d6'::uuid, 'ya', 21, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"9f1d8410-24a1-50ce-af53-d035634ca0d6","slug":"ya","lessonOrdinal":21,"stage":6,"title":"ยา — y and Glide Finals","anchor":{"id":"b3a09902-4528-5718-a8fe-068c2032b55d","slug":"ya","text":"ยา","meaning":"medicine","pronunciation":"yaa","categoryKey":"sign","contextNote":"ยา means medicine — ร้านขายยา (pharmacy) is a key sign to recognize. ย also closes many words as a y-glide, alongside ว as a w-glide.","segments":[{"text":"ยา","sound":"yaa"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"91f507f7-7ed9-5b70-ad59-0b0cf90924da","key":"word-0e22-0e32-0e01","text":"ยาก","meaning":"difficult","pronunciation":"yâak","categoryKey":"daily","segments":[{"text":"ยาก","sound":"yâak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"7084e707-5eb2-51a4-a18d-b729e6d4d5a0","key":"word-0e22-0e32-0e27","text":"ยาว","meaning":"long","pronunciation":"yaao","categoryKey":"daily","segments":[{"text":"ยาว","sound":"yaao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"87e4f1a8-5a5f-5756-a970-c699446dbb92","key":"word-0e02-0e32-0e22","text":"ขาย","meaning":"to sell","pronunciation":"khǎai","categoryKey":"sign","segments":[{"text":"ขาย","sound":"khǎai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"4b277ab9-99f9-523d-a6b3-895443e63944","key":"word-0e02-0e32-0e27","text":"ขาว","meaning":"white","pronunciation":"khǎao","categoryKey":"daily","segments":[{"text":"ขาว","sound":"khǎao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"4ce54fa7-a5d2-5304-abf5-c0abec5cd751","key":"word-0e02-0e49-0e32-0e27","text":"ข้าว","meaning":"rice","pronunciation":"khâao","categoryKey":"food","segments":[{"text":"ข้าว","sound":"khâao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"2eaf93d4-a195-5415-a2bd-fe228658b036","key":"word-0e2a-0e27-0e22","text":"สวย","meaning":"beautiful","pronunciation":"sǔuai","categoryKey":"daily","segments":[{"text":"สวย","sound":"sǔuai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"48020f26-c096-59c2-a7cd-e965f5091c18","key":"word-0e14-0e49-0e27-0e22","text":"ด้วย","meaning":"also / with","pronunciation":"dûuai","categoryKey":"daily","segments":[{"text":"ด้วย","sound":"dûuai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"9c6ca6c5-a560-5d3a-a4ef-391347f3ba4d","key":"word-0e22-0e34-0e49-0e21","text":"ยิ้ม","meaning":"to smile","pronunciation":"yím","categoryKey":"daily","segments":[{"text":"ยิ้ม","sound":"yím"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"b735e854-d60f-5839-a552-9be8afef3590","key":"word-0e2a-0e32-0e22","text":"สาย","meaning":"late / line","pronunciation":"sǎai","categoryKey":"daily","segments":[{"text":"สาย","sound":"sǎai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"1a71a8c0-993f-582b-ac45-1a1039ed8d19","key":"word-0e02-0e32-0e22-0e02-0e2d-0e07","text":"ขายของ","meaning":"to sell goods","pronunciation":"khǎai khǎwng","categoryKey":"sign","segments":[{"text":"ขาย","sound":"khǎai"},{"text":"ของ","sound":"khǎwng"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":true,"item":{"id":"148c18bf-3921-531e-a0f6-8a6f2b87fccd","key":"word-0e23-0e49-0e32-0e19-0e02-0e32-0e22-0e22-0e32","text":"ร้านขายยา","meaning":"pharmacy","pronunciation":"ráan khǎai yaa","categoryKey":"sign","segments":[{"text":"ร้าน","sound":"ráan"},{"text":"ขาย","sound":"khǎai"},{"text":"ยา","sound":"yaa"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"f08f3ab4-ea11-53cf-a8b5-c3ea310041b1","text":"ย","kind":"consonant","romanization":"y","pronunciationHint":"y as in \"yes\"; at the end of a syllable it forms a glide like the \"y\" in \"boy\"","mnemonic":"ย is ย ยักษ์ (yor yak, giant). Picture a towering giant; ย gives the y sound at the start and a y-glide at the end.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"5e1b543b-6be0-5279-a812-4ec61ce2b1dc","text":"ว","kind":"consonant","romanization":"w","pronunciationHint":"w as in \"water\"; can help form vowel glides","mnemonic":"ว is ว แหวน (wor waen, ring). The rounded curl looks like a ring, and แหวน gives you the w sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"fe76a3d2-1584-562c-aedb-afdee78c0e80","key":"y-sound","name":"ย Is a y Glide","shortDescription":"ย gives the y sound at the start of a syllable","explanation":"At the start of a syllable, ย is the y in ''yes''. It is a low-class consonant. The same letter can also close a syllable as a y-glide.","examples":[{"text":"ยา = yaa"},{"text":"ยาย = yaai"}]},{"id":"278b5a51-aef0-5335-a42d-9e94a29d7ef6","key":"glide-final-y-w","name":"ย and ว Can Close a Syllable as Glides","shortDescription":"Final ย adds an i/y glide; final ว adds a w glide","explanation":"At the end of a syllable, ย and ว do not act as full consonants. ย adds a short i/y glide (as in ขาย) and ว adds a w glide (as in ขาว). You first met the w-glide back in ข้าว.","examples":[{"text":"ขาย = khǎai"},{"text":"ขาว = khǎao"}]}],"drills":[{"id":"32b2535f-e55e-5476-abae-7ea7fd95734a","key":"ya-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"y\" sound?","payload":{},"options":[{"text":"ย","isCorrect":true},{"text":"ว"},{"text":"ร"},{"text":"ล"}]},{"id":"dac2cee0-4e69-554a-a587-1660e52f1868","key":"ya-drill-02-sound","type":"sound","prompt":"At the end of a syllable, what does ว add?","payload":{},"options":[{"text":"a w glide","isCorrect":true},{"text":"a k stop"},{"text":"an ng sound"},{"text":"nothing"}]},{"id":"427e0929-4380-50e2-ab2e-6acd27b474fe","key":"ya-drill-03-match","type":"match","prompt":"What does ยา mean?","payload":{},"options":[{"text":"medicine","isCorrect":true},{"text":"chicken"},{"text":"closed"},{"text":"game"}]},{"id":"4d93c299-e6a0-5a4b-a038-f59efa91b0f1","key":"ya-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"medicine\"?","payload":{},"options":[{"text":"ยา","isCorrect":true},{"text":"วา"},{"text":"ยาม"},{"text":"รา"}]},{"id":"18f33d0c-a6fb-51dc-aa57-7fa209ef4d8e","key":"ya-drill-05-sound","type":"sound","prompt":"Which sound ends the word ขาย?","payload":{},"options":[{"text":"a y glide","isCorrect":true},{"text":"a k stop"},{"text":"an ng sound"},{"text":"a long aa"}]}]}}'::jsonb, '67ffa6f8a56a759545eb85d09c672b8a12afe2f4f0a7a4b0ea635f661d1a91c9', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('e3abe51e-ca73-55bf-a10f-339a18db44d4'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'c5e22f76-3e90-52fc-ad0e-83bbb93263af'::uuid, 'khon', 22, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"c5e22f76-3e90-52fc-ad0e-83bbb93263af","slug":"khon","lessonOrdinal":22,"stage":7,"title":"คน — The Low-Class kh","anchor":{"id":"32871dae-effa-553d-a900-ababa15c81cd","slug":"khon","text":"คน","meaning":"person","pronunciation":"khon","categoryKey":"daily","contextNote":"คน (person) is one of the highest-frequency words in Thai. It opens countless compounds — คนไทย (Thai person), คนขับ (driver) — and shows the low-class partner of the kh sound you met in ข.","segments":[{"text":"คน","sound":"khon"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"bd858f5b-f080-57c9-a8af-9a9e18e9d931","key":"word-0e04-0e38-0e13","text":"คุณ","meaning":"you","pronunciation":"khun","categoryKey":"daily","segments":[{"text":"คุณ","sound":"khun"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"11f22b97-7055-5933-a5ee-0984de2aaa0f","key":"word-0e04-0e23-0e31-0e1a","text":"ครับ","meaning":"polite particle (male)","pronunciation":"khráp","categoryKey":"daily","segments":[{"text":"ครับ","sound":"khráp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"71da2605-860f-5533-aff1-cf830943bbc3","key":"word-0e04-0e48-0e30","text":"ค่ะ","meaning":"polite particle (female)","pronunciation":"khâ","categoryKey":"daily","segments":[{"text":"ค่ะ","sound":"khâ"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"e725ff85-8c8e-58ee-aa4c-1ec8791c8995","key":"word-0e04-0e27-0e32-0e21-0e23-0e31-0e01","text":"ความรัก","meaning":"love","pronunciation":"khwaam-rák","categoryKey":"daily","segments":[{"text":"ความ","sound":"khwaam"},{"text":"รัก","sound":"rák"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"f6e8213d-c710-5c88-a268-cddfb120a0e1","key":"word-0e04-0e34-0e14","text":"คิด","meaning":"to think","pronunciation":"khít","categoryKey":"daily","segments":[{"text":"คิด","sound":"khít"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"20e21427-0466-5d72-a64f-723522203d0e","key":"word-0e04-0e48-0e32","text":"ค่า","meaning":"value / fee","pronunciation":"khâa","categoryKey":"sign","segments":[{"text":"ค่า","sound":"khâa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"9dd03a71-ca30-5cc5-a29c-721d9687fbdf","key":"word-0e04-0e33","text":"คำ","meaning":"word","pronunciation":"kham","categoryKey":"daily","segments":[{"text":"คำ","sound":"kham"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"9f3d0004-e8ad-5afd-ad9f-e5aa59680043","key":"word-0e04-0e23-0e39","text":"ครู","meaning":"teacher","pronunciation":"khruu","categoryKey":"daily","segments":[{"text":"ครู","sound":"khruu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"e8620b89-20f7-5557-af77-5263f88fa321","key":"word-0e04-0e37-0e19","text":"คืน","meaning":"night / to return","pronunciation":"khuen","categoryKey":"daily","segments":[{"text":"คืน","sound":"khuen"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"c95af394-b06c-5eef-a36f-92d0b91affdc","key":"word-0e04-0e38-0e22","text":"คุย","meaning":"to chat","pronunciation":"khui","categoryKey":"daily","segments":[{"text":"คุย","sound":"khui"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":false,"item":{"id":"3b37eace-a20d-5f7a-abda-04840eb1d43c","key":"word-0e04-0e27-0e32-0e21-0e2a-0e38-0e02","text":"ความสุข","meaning":"happiness","pronunciation":"khwaam-sùk","categoryKey":"daily","segments":[{"text":"ความ","sound":"khwaam"},{"text":"สุข","sound":"sùk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":12,"isDrillTarget":false,"item":{"id":"24b0374d-6c6a-51bd-a501-79f3eb10bc90","key":"word-0e04-0e23-0e2d-0e1a-0e04-0e23-0e31-0e27","text":"ครอบครัว","meaning":"family","pronunciation":"khrâwp-khruua","categoryKey":"daily","segments":[{"text":"ครอบ","sound":"khrâwp"},{"text":"ครัว","sound":"khruua"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":13,"isDrillTarget":false,"item":{"id":"1bbc758f-6a83-59ad-a50d-96155c5cd36b","key":"word-0e04-0e34-0e14-0e16-0e36-0e07","text":"คิดถึง","meaning":"to miss (someone)","pronunciation":"khít-thǔeng","categoryKey":"daily","segments":[{"text":"คิด","sound":"khít"},{"text":"ถึง","sound":"thǔeng"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"c40165fd-c08b-5e06-a932-28747ec7490c","text":"ค","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the \"c\" in \"cat\"","mnemonic":"ค is ค ควาย (khaw khwaai, buffalo). Picture a broad water buffalo; ค gives the same breathy kh as ข but belongs to the low class.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"2f994f9e-b598-5371-a4d0-d6876d1c868d","key":"low-kh","name":"ค Is a Low-Class kh","shortDescription":"ค makes the aspirated kh sound and is a low-class consonant","explanation":"ค gives the same breathy kh you learned from ข, released with a puff of air. What differs is its class: ค is low class, so it follows the low-class tone rules rather than the high-class ones.","examples":[{"text":"คน = khon"},{"text":"คิด = khít"}]},{"id":"a1501843-4423-5bb8-a477-0846deaebfa2","key":"kh-pair-class","name":"ค and ข Share a Sound","shortDescription":"ข and ค both sound kh; ข is high class, ค is low class","explanation":"ข and ค are pronounced the same way, but their class decides the tone. This high/low pairing repeats across Thai, so learning both members together makes later tone rules easier.","examples":[{"text":"ขา = khǎa"},{"text":"คา = khaa"}]}],"drills":[{"id":"34dc5924-223c-5892-aec9-a76ede0be9fc","key":"khon-drill-01-recognize","type":"recognize","prompt":"Which letter is the low-class \"kh\"?","payload":{},"options":[{"text":"ค","isCorrect":true},{"text":"ข"},{"text":"ก"},{"text":"ง"}]},{"id":"e3fc51af-f321-5d64-ab05-1f37f066bf7f","key":"khon-drill-02-sound","type":"sound","prompt":"What sound does ค make?","payload":{},"options":[{"text":"kh with a puff of air","isCorrect":true},{"text":"hard g"},{"text":"ng"},{"text":"s"}]},{"id":"f8a15ae1-4e83-539b-a91e-001f1fa077e7","key":"khon-drill-03-sound","type":"sound","prompt":"How do ข and ค differ?","payload":{},"options":[{"text":"they sound the same but differ in class","isCorrect":true},{"text":"ค is a vowel"},{"text":"ข is nasal"},{"text":"they are unrelated"}]},{"id":"927bcd30-e41c-52fc-a6f4-b16f1b677584","key":"khon-drill-04-match","type":"match","prompt":"What does คน mean?","payload":{},"options":[{"text":"person","isCorrect":true},{"text":"way"},{"text":"fish"},{"text":"medicine"}]},{"id":"ef60bcbb-c527-5b0e-a665-f402770626ce","key":"khon-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"person\"?","payload":{},"options":[{"text":"คน","isCorrect":true},{"text":"นค"},{"text":"ขน"},{"text":"คง"}]}]}}'::jsonb, 'c62a03058f658981bf42d6416576589943075a5427b7bfcb0c2ecd714ead4fb1', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('7b584b46-4d79-50ce-ae87-8a969cf8c33a'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'be7bc78d-7bb3-5b03-abd3-d8b659c200cd'::uuid, 'phaeng', 23, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"be7bc78d-7bb3-5b03-abd3-d8b659c200cd","slug":"phaeng","lessonOrdinal":23,"stage":7,"title":"แพง — The Low-Class ph","anchor":{"id":"410398be-ab73-5dc2-ae6e-0a2fa60be9a4","slug":"phaeng","text":"แพง","meaning":"expensive","pronunciation":"phaeng","categoryKey":"sign","contextNote":"แพง (expensive) is a core price-tag adjective. It also completes the trio of p letters: ป (bp), ผ (ph, high), and now พ (ph, low).","segments":[{"text":"แพง","sound":"phaeng"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"b431d1ec-4c3d-5a4e-aa00-14b623c1d6be","key":"word-0e1e-0e48-0e2d","text":"พ่อ","meaning":"father","pronunciation":"phâw","categoryKey":"daily","segments":[{"text":"พ่อ","sound":"phâw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"184f0ed1-97de-540c-ade2-5f0d15c8cf18","key":"word-0e40-0e1e-0e37-0e48-0e2d-0e19","text":"เพื่อน","meaning":"friend","pronunciation":"phûuean","categoryKey":"daily","segments":[{"text":"เพื่อน","sound":"phûuean"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"2a648549-fd7f-5872-a4cb-c95206edb016","key":"word-0e1e-0e39-0e14","text":"พูด","meaning":"to speak","pronunciation":"phûut","categoryKey":"daily","segments":[{"text":"พูด","sound":"phûut"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"e164e571-cdb7-5680-afd2-69a20dd73d11","key":"word-0e1e-0e1a","text":"พบ","meaning":"to meet","pronunciation":"phóp","categoryKey":"daily","segments":[{"text":"พบ","sound":"phóp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"087c71de-8957-5c31-ae3f-97f237606b8a","key":"word-0e1e-0e32","text":"พา","meaning":"to lead / take","pronunciation":"phaa","categoryKey":"daily","segments":[{"text":"พา","sound":"phaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"4238c11c-edf4-5df6-a643-a2f6eff129d1","key":"word-0e40-0e1e-0e25-0e07","text":"เพลง","meaning":"song","pronunciation":"phleeng","categoryKey":"daily","segments":[{"text":"เพลง","sound":"phleeng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"9ec75fd5-6649-5332-a2fd-530598698823","key":"word-0e1e-0e35-0e48","text":"พี่","meaning":"older sibling","pronunciation":"phîi","categoryKey":"daily","segments":[{"text":"พี่","sound":"phîi"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"90267c41-4bf0-58c0-a441-9104a60815b5","key":"word-0e41-0e1e-0e49","text":"แพ้","meaning":"to lose / be allergic","pronunciation":"pháe","categoryKey":"daily","segments":[{"text":"แพ้","sound":"pháe"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"a9ee0b37-5920-5a55-a177-8640a2436f91","key":"word-0e1e-0e2d","text":"พอ","meaning":"enough","pronunciation":"phaw","categoryKey":"daily","segments":[{"text":"พอ","sound":"phaw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"5376ecaa-def3-575e-ab77-209c94b13712","key":"word-0e40-0e1e-0e23-0e32-0e30","text":"เพราะ","meaning":"because","pronunciation":"phráw","categoryKey":"daily","segments":[{"text":"เพราะ","sound":"phráw"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":false,"item":{"id":"c7e6a736-2264-5f62-ad34-cfef464e1aad","key":"word-0e1e-0e23-0e30","text":"พระ","meaning":"monk","pronunciation":"phrá","categoryKey":"daily","segments":[{"text":"พระ","sound":"phrá"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":12,"isDrillTarget":false,"item":{"id":"76f610be-af1e-594e-ae03-f1aa17c33ecd","key":"word-0e1e-0e23-0e34-0e01","text":"พริก","meaning":"chili","pronunciation":"phrík","categoryKey":"food","segments":[{"text":"พริก","sound":"phrík"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"0abef0b2-0c0d-5a3b-a853-11eddd2dd366","text":"พ","kind":"consonant","romanization":"ph","pronunciationHint":"ph with a puff of air, like the \"p\" in \"pin\"","mnemonic":"พ is พ พาน (phaw phaan, a footed offering tray). Picture the tall pedestal tray; พ gives the aspirated ph sound in the low class.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"1684cb46-8524-51a4-ad84-8dd2fe3b46be","text":"แ","kind":"vowel","romanization":"ae","pronunciationHint":"long \"ae\" as in the vowel of \"care\"","mnemonic":"แ is a double left-side vowel. The two front posts tell your eye to look left first, then come back to the consonant for ae.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"bda65912-fa0a-5328-a7d4-302245d61c3e","text":"ง","kind":"consonant","romanization":"ng","pronunciationHint":"ng as in \"singer\"; used at the start or end of a syllable","mnemonic":"ง is ง งู (ngor nguu, snake). Picture the curving body of a snake; ง makes the ng sound that English only uses at the ends of words.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"da8975d2-f60a-59f9-a1d2-f55df44b6bfa","text":"ผ","kind":"consonant","romanization":"ph","pronunciationHint":"ph with a puff of air, like the start of \"photo\" without the f sound","mnemonic":"ผ is ผ ผึ้ง (phor phueng, bee). Picture the open shape as wings and body; ผึ้ง starts with the puffed ph sound.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"1468f8a2-d91f-5127-ac8d-e40de6f54950","text":"ป","kind":"consonant","romanization":"bp","pronunciationHint":"a tight, unaspirated p, like the p in \"spin\" (between English b and p)","mnemonic":"ป is ป ปลา (bpor bplaa, fish). Picture a tall fish standing on its tail; ป is the unaspirated p that pairs with the dt sound of ต.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"0a659c55-8f6d-53da-a0e1-bbecd04b2b69","key":"low-ph","name":"พ Is a Low-Class ph","shortDescription":"พ makes an aspirated ph and is low class","explanation":"พ is a ph released with a puff of air, the same breathy sound as ผ. The difference is class: พ is low class, ผ is high class, so the two take different tones.","examples":[{"text":"แพง = phaeng"},{"text":"พูด = phûut"}]},{"id":"1932b500-7080-5b50-a966-a8d5092de230","key":"three-p-letters","name":"Thai Has Three p Letters","shortDescription":"ป is bp (no air), ผ is high ph, พ is low ph","explanation":"Keep the three apart by air and class: ป (bp) is tight with no puff, while ผ and พ both add a puff of air — ผ high class, พ low class. The puff and the class together decide the word.","examples":[{"text":"ปา = bpaa"},{"text":"ผา = phǎa"},{"text":"พา = phaa"}]}],"drills":[{"id":"d978d0b3-b5ba-5fbc-a68c-46841a6adc3c","key":"phaeng-drill-01-recognize","type":"recognize","prompt":"Which letter is the low-class \"ph\"?","payload":{},"options":[{"text":"พ","isCorrect":true},{"text":"ผ"},{"text":"ป"},{"text":"บ"}]},{"id":"2833e72c-5b0a-5251-a851-58f6228cb42e","key":"phaeng-drill-02-sound","type":"sound","prompt":"What sound does พ make?","payload":{},"options":[{"text":"ph with a puff of air","isCorrect":true},{"text":"bp with no air"},{"text":"f"},{"text":"m"}]},{"id":"a0dff08e-4808-5051-ab7e-1df1a7e84514","key":"phaeng-drill-03-sound","type":"sound","prompt":"Which letter has NO puff of air?","payload":{},"options":[{"text":"ป","isCorrect":true},{"text":"ผ"},{"text":"พ"},{"text":"ค"}]},{"id":"119ab329-dd6f-5a53-a788-2ad970846d7e","key":"phaeng-drill-04-match","type":"match","prompt":"What does แพง mean?","payload":{},"options":[{"text":"expensive","isCorrect":true},{"text":"cheap"},{"text":"open"},{"text":"person"}]},{"id":"8d0dd69b-bd05-5789-a57d-afc1ccf94ffe","key":"phaeng-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"expensive\"?","payload":{},"options":[{"text":"แพง","isCorrect":true},{"text":"พงแ"},{"text":"แผง"},{"text":"แพน"}]}]}}'::jsonb, '72e3dcf0967f6c5cc96bb4f937d731bcd75c8da7216cade5a9dd2ecb42aca9b9', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('d4951011-edb7-569a-a860-9fb96b0a108c'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'ca28d549-96b2-585a-a988-213769cb7801'::uuid, 'nam', 24, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"ca28d549-96b2-585a-a988-213769cb7801","slug":"nam","lessonOrdinal":24,"stage":7,"title":"น้ำ — The am Vowel","anchor":{"id":"3ca2f3fd-058e-5d41-a635-caf8caa24c00","slug":"nam","text":"น้ำ","meaning":"water","pronunciation":"náam","categoryKey":"daily","contextNote":"น้ำ (water) is everywhere — bottles, menus, and compounds like น้ำแข็ง (ice) and น้ำมัน (oil). It introduces ◌ำ, a vowel that carries its own final m.","segments":[{"text":"น้ำ","sound":"náam"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"18b622ae-0178-5a66-a97b-6b75507ebdab","key":"word-0e17-0e33","text":"ทำ","meaning":"to do / make","pronunciation":"tham","categoryKey":"daily","segments":[{"text":"ทำ","sound":"tham"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"9dd03a71-ca30-5cc5-a29c-721d9687fbdf","key":"word-0e04-0e33","text":"คำ","meaning":"word","pronunciation":"kham","categoryKey":"daily","segments":[{"text":"คำ","sound":"kham"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"87f5d512-5c2c-5db2-a7f7-c215f7baa9cb","key":"word-0e14-0e33","text":"ดำ","meaning":"black","pronunciation":"dam","categoryKey":"daily","segments":[{"text":"ดำ","sound":"dam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"6bbecd64-d700-55f7-aecb-39171172bb59","key":"word-0e08-0e33","text":"จำ","meaning":"to remember","pronunciation":"jam","categoryKey":"daily","segments":[{"text":"จำ","sound":"jam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"0f79faa2-d143-568a-a9d0-aa5303177b81","key":"word-0e17-0e33-0e44-0e21","text":"ทำไม","meaning":"why","pronunciation":"tham-mai","categoryKey":"daily","segments":[{"text":"ทำ","sound":"tham"},{"text":"ไม","sound":"mai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"1ae6a253-dfe1-57d5-a69d-7e76a2417830","key":"word-0e19-0e33","text":"นำ","meaning":"to lead","pronunciation":"nam","categoryKey":"daily","segments":[{"text":"นำ","sound":"nam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"288bc045-d61b-585a-af4a-459b04fc4abb","key":"word-0e17-0e33-0e07-0e32-0e19","text":"ทำงาน","meaning":"to work","pronunciation":"tham-ngaan","categoryKey":"daily","segments":[{"text":"ทำ","sound":"tham"},{"text":"งาน","sound":"ngaan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"2037d55d-814a-5f0d-acfb-8ce6aa0af97c","key":"word-0e19-0e49-0e33-0e21-0e31-0e19","text":"น้ำมัน","meaning":"oil / fuel","pronunciation":"nám-man","categoryKey":"sign","segments":[{"text":"น้ำ","sound":"nám"},{"text":"มัน","sound":"man"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"b66794bd-592b-5dd3-a2ed-46de9c3d4c11","key":"word-0e2a-0e33-0e04-0e31-0e0d","text":"สำคัญ","meaning":"important","pronunciation":"sǎm-khan","categoryKey":"daily","segments":[{"text":"สำ","sound":"sǎm"},{"text":"คัญ","sound":"khan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"9549c914-b28f-567d-a4f6-257b6869c009","key":"word-0e01-0e33-0e25-0e31-0e07","text":"กำลัง","meaning":"(progressive marker)","pronunciation":"gam-lang","categoryKey":"daily","segments":[{"text":"กำ","sound":"gam"},{"text":"ลัง","sound":"lang"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":false,"item":{"id":"149db931-4755-5e3a-a6ef-3bcad178d5c6","key":"word-0e04-0e33-0e16-0e32-0e21","text":"คำถาม","meaning":"question","pronunciation":"kham-thǎam","categoryKey":"daily","segments":[{"text":"คำ","sound":"kham"},{"text":"ถาม","sound":"thǎam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":12,"isDrillTarget":true,"item":{"id":"22e621fc-bf4a-5d19-ae57-f43117613924","key":"word-0e17-0e33-0e2d-0e32-0e2b-0e32-0e23","text":"ทำอาหาร","meaning":"to cook","pronunciation":"tham aa-hǎan","categoryKey":"food","segments":[{"text":"ทำ","sound":"tham"},{"text":"อา","sound":"aa"},{"text":"หาร","sound":"hǎan"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-tone-mark","title":"Tone mark","body":"Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify."}],"newGraphemes":[{"id":"6dcb5f4d-ee45-5907-ae15-26739f104438","text":"ำ","kind":"vowel","romanization":"am","pronunciationHint":"short \"am\", like the \"um\" in \"hum\"","mnemonic":"ำ is sara am: a little circle rides above and a tail hooks down on the right. It always ends in an m, so you never add a separate final.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]},{"id":"cf8eaddc-cd8e-55ca-a652-237794f23e8b","text":"ท","kind":"consonant","romanization":"th","pronunciationHint":"th with a puff of air, like the \"t\" in \"top\" (not the th in \"the\")","mnemonic":"ท is ท ทหาร (thor thahaan, soldier). Picture a soldier standing tall; ท gives the aspirated th sound with a clear puff of air.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"c40165fd-c08b-5e06-a932-28747ec7490c","text":"ค","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the \"c\" in \"cat\"","mnemonic":"ค is ค ควาย (khaw khwaai, buffalo). Picture a broad water buffalo; ค gives the same breathy kh as ข but belongs to the low class.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"3c55c9e9-4ff3-5ddc-ada1-8a6996a64cd2","key":"am-vowel","name":"◌ำ Is the am Vowel","shortDescription":"◌ำ gives a short ''am'' with a built-in final m","explanation":"◌ำ is a short vowel that already includes its final m, so ทำ is read tham and คำ is read kham. You never write a separate ม after it.","examples":[{"text":"ทำ = tham"},{"text":"คำ = kham"}]},{"id":"f6c2f9fd-e5f7-5e6d-a79c-280ebe995b22","key":"naam-length","name":"น้ำ Stretches Long on Its Own","shortDescription":"น้ำ is long by itself but short inside compounds","explanation":"By itself น้ำ is pronounced long (náam). Inside a compound the vowel shortens, as in น้ำมัน (nám-man, oil). It is the one common exception to the short ◌ำ.","examples":[{"text":"น้ำ = náam"},{"text":"น้ำมัน = nám-man"}]}],"drills":[{"id":"149a2723-d406-5013-aeff-5a38a287f5af","key":"nam-drill-01-recognize","type":"recognize","prompt":"Which vowel makes the \"am\" sound?","payload":{},"options":[{"text":"ำ","isCorrect":true},{"text":"า"},{"text":"ั"},{"text":"ู"}]},{"id":"7f98c96d-ed96-5244-ab14-9f262d329e30","key":"nam-drill-02-sound","type":"sound","prompt":"What sound ends every ◌ำ syllable?","payload":{},"options":[{"text":"m","isCorrect":true},{"text":"n"},{"text":"ng"},{"text":"k"}]},{"id":"992a7e6e-ca82-59b0-a7b5-fe4b8d9c9af7","key":"nam-drill-03-sound","type":"sound","prompt":"How is น้ำ pronounced on its own?","payload":{},"options":[{"text":"long: náam","isCorrect":true},{"text":"short: nám"},{"text":"with a k"},{"text":"with an ng"}]},{"id":"f2a8ec52-e161-5b1f-ab93-3c8db8ca929d","key":"nam-drill-04-match","type":"match","prompt":"What does น้ำ mean?","payload":{},"options":[{"text":"water","isCorrect":true},{"text":"word"},{"text":"person"},{"text":"fire"}]},{"id":"9c9a6d6b-09c3-5016-a7da-4f1a20097eb1","key":"nam-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"water\"?","payload":{},"options":[{"text":"น้ำ","isCorrect":true},{"text":"นำ"},{"text":"ทำ"},{"text":"คำ"}]}]}}'::jsonb, '632b002e4cd3dce2f6afa7153de2a2919aa651bf636ed2d5032a477420582752', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('9babb6fe-6eb8-52bf-a453-fe4ef0451cb6'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'e1787c4e-fabf-58a7-ad6e-8a576a895014'::uuid, 'khao-he', 25, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"e1787c4e-fabf-58a7-ad6e-8a576a895014","slug":"khao-he","lessonOrdinal":25,"stage":7,"title":"เขา — The Wrap-Around ao Vowel","anchor":{"id":"72e8b19d-90ec-5161-af69-546c398d3d6e","slug":"khao-he","text":"เขา","meaning":"he / she / they","pronunciation":"khǎo","categoryKey":"daily","contextNote":"เขา is the everyday pronoun for he, she, or they. It shows how เ and า wrap around a consonant to make the short ao diphthong.","segments":[{"text":"เขา","sound":"khǎo"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"1bd5a55a-f5f9-5588-a173-32c61cad96a4","key":"word-0e40-0e23-0e32","text":"เรา","meaning":"we","pronunciation":"rao","categoryKey":"daily","segments":[{"text":"เรา","sound":"rao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"bce2facb-d6d5-5a3f-a2eb-a45dd6c1f139","key":"word-0e40-0e2d-0e32","text":"เอา","meaning":"to take / want","pronunciation":"ao","categoryKey":"daily","segments":[{"text":"เอา","sound":"ao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"942ad2fd-d5db-5e0a-ac73-21faf8dd00bc","key":"word-0e40-0e01-0e49-0e32","text":"เก้า","meaning":"nine","pronunciation":"gâo","categoryKey":"daily","segments":[{"text":"เก้า","sound":"gâo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"d6f83b16-c9bc-57e5-ac55-a3756ff19618","key":"word-0e40-0e0a-0e49-0e32","text":"เช้า","meaning":"morning","pronunciation":"cháo","categoryKey":"daily","segments":[{"text":"เช้า","sound":"cháo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"7fc02aa1-c333-560b-aa86-58ccd9121505","key":"word-0e40-0e25-0e48-0e32","text":"เล่า","meaning":"to tell (a story)","pronunciation":"lâo","categoryKey":"daily","segments":[{"text":"เล่า","sound":"lâo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"bab8433b-7dfd-586b-a3fd-579e205c9b33","key":"word-0e40-0e1a-0e32","text":"เบา","meaning":"light / soft","pronunciation":"bao","categoryKey":"daily","segments":[{"text":"เบา","sound":"bao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"80912310-dd56-5830-a617-1e619aa7cc10","key":"word-0e40-0e1c-0e32","text":"เผา","meaning":"to burn","pronunciation":"phǎo","categoryKey":"daily","segments":[{"text":"เผา","sound":"phǎo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"b5325b9a-90b0-5bc0-a7f6-6b7a7bb2619a","key":"word-0e40-0e14-0e32","text":"เดา","meaning":"to guess","pronunciation":"dao","categoryKey":"daily","segments":[{"text":"เดา","sound":"dao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"243c1bc9-8cc7-5c86-a9c9-2f05195e99df","key":"word-0e40-0e02-0e49-0e32","text":"เข้า","meaning":"to enter","pronunciation":"khâo","categoryKey":"daily","segments":[{"text":"เข้า","sound":"khâo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"dd4af863-d7f8-5f55-a894-80120a4325c1","key":"word-0e40-0e17-0e48-0e32","text":"เท่า","meaning":"equal to","pronunciation":"thâo","categoryKey":"daily","segments":[{"text":"เท่า","sound":"thâo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":false,"item":{"id":"d936c02c-ea9e-51f4-a67f-6ffdab144382","key":"word-0e40-0e2a-0e32","text":"เสา","meaning":"pillar / post","pronunciation":"sǎo","categoryKey":"daily","segments":[{"text":"เสา","sound":"sǎo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":12,"isDrillTarget":false,"item":{"id":"78173592-f441-5a38-aa13-fb03b44067b8","key":"word-0e40-0e02-0e49-0e32-0e43-0e08","text":"เข้าใจ","meaning":"to understand","pronunciation":"khâo-jai","categoryKey":"daily","segments":[{"text":"เข้า","sound":"khâo"},{"text":"ใจ","sound":"jai"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"a9e18bf6-2166-534c-a309-cd195f0f2ddc","text":"เ◌า","kind":"vowel","romanization":"ao","pronunciationHint":"short \"ao\", like the \"ow\" in \"cow\"","mnemonic":"เ leads on the left and า trails on the right, wrapping the consonant. Read the consonant first, then the ao that surrounds it.","position":"around","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"d930649b-b987-5148-a7d1-8aaabef44060","text":"เ","kind":"vowel","romanization":"e","pronunciationHint":"long \"e\" as in \"they\"","mnemonic":"เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"6bda921c-8e22-5e36-a62a-ea770798bffb","key":"ao-frame","name":"เ + า Wrap to Make ao","shortDescription":"เ before and า after a consonant give the short ao vowel","explanation":"You already know เ and า on their own. Together, with เ on the left and า on the right, they frame the consonant and produce a short ao. Always read the consonant before the vowel sound.","examples":[{"text":"เขา = khǎo"},{"text":"เรา = rao"}]}],"drills":[{"id":"f6c59a98-312d-5cee-a4f3-f8873471fad1","key":"khao-he-drill-01-recognize","type":"recognize","prompt":"Which frame makes the \"ao\" sound?","payload":{},"options":[{"text":"เ◌า","isCorrect":true},{"text":"โ◌"},{"text":"ไ◌"},{"text":"เ◌"}]},{"id":"03c03da6-c664-5785-ae30-be43a13568d1","key":"khao-he-drill-02-sound","type":"sound","prompt":"In เขา, which sound comes first?","payload":{},"options":[{"text":"the consonant kh","isCorrect":true},{"text":"the า"},{"text":"the เ"},{"text":"an m"}]},{"id":"085be7bd-c2a8-554c-aa1b-5f5e4e0ae961","key":"khao-he-drill-03-sound","type":"sound","prompt":"How is the เ-า vowel written?","payload":{},"options":[{"text":"wrapped around the consonant","isCorrect":true},{"text":"only above"},{"text":"only below"},{"text":"only after"}]},{"id":"e6fb3c3e-e1ba-5072-a90f-a4a80dbdf82e","key":"khao-he-drill-04-match","type":"match","prompt":"What does เขา mean?","payload":{},"options":[{"text":"he / she / they","isCorrect":true},{"text":"we"},{"text":"water"},{"text":"person"}]},{"id":"7451d34a-f9d5-5cb2-a7b9-16b747219c69","key":"khao-he-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"he / she / they\"?","payload":{},"options":[{"text":"เขา","isCorrect":true},{"text":"ขาว"},{"text":"เรา"},{"text":"เขาน"}]}]}}'::jsonb, '8f83e9c6ad63a43c7dc8a107f9cc687bb14ea2357bc5f74864d0e64d6db6001a', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('d0f0cfdf-8cd5-53d5-acaa-a6169d8ee4b9'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '32329333-ccf2-5eab-ae0f-bd10a8a64107'::uuid, 'soi', 26, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"32329333-ccf2-5eab-ae0f-bd10a8a64107","slug":"soi","lessonOrdinal":26,"stage":8,"title":"ซอย — The Low-Class s","anchor":{"id":"14c3515c-5502-5cae-a90c-ae4f26f88f1e","slug":"soi","text":"ซอย","meaning":"lane / soi","pronunciation":"sawy","categoryKey":"sign","contextNote":"ซอย (a lane off a main road) is part of nearly every Thai address. It introduces ซ, the low-class partner of the s sound.","segments":[{"text":"ซอย","sound":"sawy"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"09cd5a51-a564-5e56-a3cd-bbb8eb3e823d","key":"word-0e0b-0e37-0e49-0e2d","text":"ซื้อ","meaning":"to buy","pronunciation":"súe","categoryKey":"daily","segments":[{"text":"ซื้อ","sound":"súe"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"29937615-2fb7-506e-a080-7619f839bb12","key":"word-0e0b-0e49-0e32-0e22","text":"ซ้าย","meaning":"left","pronunciation":"sáai","categoryKey":"sign","segments":[{"text":"ซ้าย","sound":"sáai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"a189810c-7c7f-5610-ae0c-5c5a6ccac5fe","key":"word-0e0b-0e31-0e01","text":"ซัก","meaning":"to wash (clothes)","pronunciation":"sák","categoryKey":"daily","segments":[{"text":"ซัก","sound":"sák"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"0e1c377b-423d-50ac-a70c-28b11234c022","key":"word-0e40-0e0b-0e47-0e19","text":"เซ็น","meaning":"to sign","pronunciation":"sen","categoryKey":"sign","segments":[{"text":"เซ็น","sound":"sen"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"1e84dd57-8958-597b-a950-b3ea7c05b420","key":"word-0e0b-0e49-0e33","text":"ซ้ำ","meaning":"to repeat","pronunciation":"sám","categoryKey":"daily","segments":[{"text":"ซ้ำ","sound":"sám"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"afd335b0-8482-5d31-afe1-40e7b9790ca4","key":"word-0e0b-0e2d-0e07","text":"ซอง","meaning":"envelope","pronunciation":"sawng","categoryKey":"daily","segments":[{"text":"ซอง","sound":"sawng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"ac138f3a-a5cd-5e1f-aaae-d30500ce8cb3","key":"word-0e0b-0e27-0e22","text":"ซวย","meaning":"unlucky","pronunciation":"suuai","categoryKey":"daily","segments":[{"text":"ซวย","sound":"suuai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"863decb7-c1e5-588a-a33b-3c976535ab57","key":"word-0e0b-0e48-0e2d-0e21","text":"ซ่อม","meaning":"to repair","pronunciation":"sâwm","categoryKey":"daily","segments":[{"text":"ซ่อม","sound":"sâwm"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"78b060c8-2a2f-53c6-a761-1ef149e994cf","key":"word-0e0b-0e37-0e49-0e2d-0e02-0e2d-0e07","text":"ซื้อของ","meaning":"to shop","pronunciation":"súe khǎwng","categoryKey":"daily","segments":[{"text":"ซื้อ","sound":"súe"},{"text":"ของ","sound":"khǎwng"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"b27c4bc9-bef2-5b6e-ab00-89715a2aa22b","key":"word-0e0b-0e31-0e01-0e1c-0e49-0e32","text":"ซักผ้า","meaning":"to do laundry","pronunciation":"sák phâa","categoryKey":"daily","segments":[{"text":"ซัก","sound":"sák"},{"text":"ผ้า","sound":"phâa"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":false,"item":{"id":"1169a705-eb75-56e0-a622-c3ad876c43f9","key":"word-0e0b-0e37-0e49-0e2d-0e02-0e32-0e22","text":"ซื้อขาย","meaning":"to trade","pronunciation":"súe khǎai","categoryKey":"daily","segments":[{"text":"ซื้อ","sound":"súe"},{"text":"ขาย","sound":"khǎai"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"2b7b4a4e-8970-5752-ac27-3975c5537981","text":"ซ","kind":"consonant","romanization":"s","pronunciationHint":"s as in \"sun\"","mnemonic":"ซ is ซ โซ่ (saw sôo, a chain). Picture the links of a chain; ซ gives a plain s in the low class.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f08f3ab4-ea11-53cf-a8b5-c3ea310041b1","text":"ย","kind":"consonant","romanization":"y","pronunciationHint":"y as in \"yes\"; at the end of a syllable it forms a glide like the \"y\" in \"boy\"","mnemonic":"ย is ย ยักษ์ (yor yak, giant). Picture a towering giant; ย gives the y sound at the start and a y-glide at the end.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"ae26196d-7a39-57e3-a8c4-061567bf9167","text":"ส","kind":"consonant","romanization":"s","pronunciationHint":"s as in \"sun\"","mnemonic":"ส is ส เสือ (sor suea, tiger). The pointed, striped-looking shape can cue a tiger, and เสือ starts with the crisp s sound.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"9593d6a6-13bb-563d-a33d-b01dd74e3528","text":"ช","kind":"consonant","romanization":"ch","pronunciationHint":"ch as in \"check\"","mnemonic":"ช is ช ช้าง (chor chaang, elephant). Picture the long dropping stroke as an elephant trunk, and use ช้าง for the ch sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"c90dd0b0-534a-5770-a50e-2bcc02581dfd","key":"low-s","name":"ซ Is a Low-Class s","shortDescription":"ซ makes a plain s and is low class","explanation":"ซ is a straightforward s sound, but unlike the high-class ส you met earlier, it is low class and follows the low-class tone rules.","examples":[{"text":"ซอย = sawy"},{"text":"ซื้อ = súe"}]},{"id":"aa4ecd2b-2880-5d6a-a387-63d84a034ffa","key":"s-look-alikes","name":"ซ, ส, and ช Look Similar","shortDescription":"ซ and ส both sound s; ช is a different ch sound","explanation":"ซ (low s) and ส (high s) share a sound but differ in class. ช looks similar but is a ch. Check the small details of each letter before you read it.","examples":[{"text":"ซอง = sawng"},{"text":"สอง = sǎwng"}]}],"drills":[{"id":"2ec458e5-6fd3-57a2-adc6-22259823dc86","key":"soi-drill-01-recognize","type":"recognize","prompt":"Which letter is the low-class \"s\"?","payload":{},"options":[{"text":"ซ","isCorrect":true},{"text":"ส"},{"text":"ช"},{"text":"จ"}]},{"id":"33838251-0ba0-5819-a3ed-3f29de2c5e98","key":"soi-drill-02-sound","type":"sound","prompt":"What sound does ซ make?","payload":{},"options":[{"text":"s","isCorrect":true},{"text":"ch"},{"text":"z as in zoo"},{"text":"sh"}]},{"id":"92ae9210-0c1f-58a5-a0f5-135dcd3d3e2a","key":"soi-drill-03-sound","type":"sound","prompt":"How do ซ and ส differ?","payload":{},"options":[{"text":"they sound the same but differ in class","isCorrect":true},{"text":"ซ is a vowel"},{"text":"ส is nasal"},{"text":"they are unrelated"}]},{"id":"bfa348dd-f0ce-599c-a958-e8db679dc75b","key":"soi-drill-04-match","type":"match","prompt":"What does ซอย mean?","payload":{},"options":[{"text":"lane / soi","isCorrect":true},{"text":"road"},{"text":"left"},{"text":"envelope"}]},{"id":"ca518a18-918c-5e1b-a522-f71c1037e197","key":"soi-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"lane / soi\"?","payload":{},"options":[{"text":"ซอย","isCorrect":true},{"text":"สอย"},{"text":"ซอง"},{"text":"ยอซ"}]}]}}'::jsonb, 'f8a09ad9322b2fec524f3698cece2bfc45d1ca8b9bda9b57137b4f2ae9ab740f', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('b5067c46-c4ad-5df1-a0b1-64f323bcf24f'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'ebb4afe8-f2e5-55fd-a790-7687d9b8fdc1'::uuid, 'fai', 27, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"ebb4afe8-f2e5-55fd-a790-7687d9b8fdc1","slug":"fai","lessonOrdinal":27,"stage":8,"title":"ไฟ — The Low-Class f","anchor":{"id":"c308414f-aec6-5570-a935-484457a5e5a9","slug":"fai","text":"ไฟ","meaning":"fire / light","pronunciation":"fai","categoryKey":"sign","contextNote":"ไฟ means fire, light, or electricity. It powers everyday signs like ไฟฟ้า (electricity) and ไฟแดง (red light), and introduces the low-class f.","segments":[{"text":"ไฟ","sound":"fai"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"a44fdf07-cda9-50ef-aaaf-c7bfffcf302d","key":"word-0e1f-0e31-0e07","text":"ฟัง","meaning":"to listen","pronunciation":"fang","categoryKey":"daily","segments":[{"text":"ฟัง","sound":"fang"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"f54faae0-25eb-524f-a207-06b06bc11a21","key":"word-0e44-0e1f-0e1f-0e49-0e32","text":"ไฟฟ้า","meaning":"electricity","pronunciation":"fai-fáa","categoryKey":"sign","segments":[{"text":"ไฟ","sound":"fai"},{"text":"ฟ้า","sound":"fáa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"47556124-4483-5d47-abd5-0d08cdaaa912","key":"word-0e1f-0e23-0e35","text":"ฟรี","meaning":"free","pronunciation":"frii","categoryKey":"sign","segments":[{"text":"ฟรี","sound":"frii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"f9465423-da97-5ccf-a826-5f6d24462694","key":"word-0e1f-0e31-0e19","text":"ฟัน","meaning":"tooth","pronunciation":"fan","categoryKey":"daily","segments":[{"text":"ฟัน","sound":"fan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"6e74e3c8-c998-5ced-ae66-0e06ca2687c0","key":"word-0e1f-0e49-0e32","text":"ฟ้า","meaning":"sky / blue","pronunciation":"fáa","categoryKey":"daily","segments":[{"text":"ฟ้า","sound":"fáa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"79b957d6-bfb0-5899-a460-37e247bf9986","key":"word-0e01-0e32-0e41-0e1f","text":"กาแฟ","meaning":"coffee","pronunciation":"gaa-fae","categoryKey":"food","segments":[{"text":"กา","sound":"gaa"},{"text":"แฟ","sound":"fae"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"ca4751e7-b9d3-57a0-af38-7b10adff4c1c","key":"word-0e1f-0e32-0e07","text":"ฟาง","meaning":"straw / hay","pronunciation":"faang","categoryKey":"daily","segments":[{"text":"ฟาง","sound":"faang"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"5434cf00-f949-5fad-ae67-35f9b91d2fc5","key":"word-0e44-0e1f-0e41-0e14-0e07","text":"ไฟแดง","meaning":"red light","pronunciation":"fai-daeng","categoryKey":"sign","segments":[{"text":"ไฟ","sound":"fai"},{"text":"แดง","sound":"daeng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"f52239bc-3d2f-5d8a-ae99-ed5846db0fc3","key":"word-0e40-0e1b-0e34-0e14-0e44-0e1f","text":"เปิดไฟ","meaning":"to turn on the light","pronunciation":"bpèrt fai","categoryKey":"daily","segments":[{"text":"เปิด","sound":"bpèrt"},{"text":"ไฟ","sound":"fai"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"b69ea913-c035-50e7-a810-ac53deb443f0","key":"word-0e14-0e31-0e1a-0e44-0e1f","text":"ดับไฟ","meaning":"to turn off the light","pronunciation":"dàp fai","categoryKey":"daily","segments":[{"text":"ดับ","sound":"dàp"},{"text":"ไฟ","sound":"fai"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"27b2ee31-e73d-533a-adfd-5b8a76f0c39f","text":"ฟ","kind":"consonant","romanization":"f","pronunciationHint":"f as in \"fan\"","mnemonic":"ฟ is ฟ ฟัน (faw fan, teeth). Picture a row of teeth; ฟ gives a plain f in the low class.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"d636b36c-e319-5414-ad3e-8657562bd576","text":"ไ","kind":"vowel","romanization":"ai","pronunciationHint":"the \"ai\" sound as in \"Thai\"","mnemonic":"ไ (ไม้มลาย, mai malai) is the common ai vowel, written before the consonant. Note the small flag curling off the top.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"1684cb46-8524-51a4-ad84-8dd2fe3b46be","text":"แ","kind":"vowel","romanization":"ae","pronunciationHint":"long \"ae\" as in the vowel of \"care\"","mnemonic":"แ is a double left-side vowel. The two front posts tell your eye to look left first, then come back to the consonant for ae.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"bda65912-fa0a-5328-a7d4-302245d61c3e","text":"ง","kind":"consonant","romanization":"ng","pronunciationHint":"ng as in \"singer\"; used at the start or end of a syllable","mnemonic":"ง is ง งู (ngor nguu, snake). Picture the curving body of a snake; ง makes the ng sound that English only uses at the ends of words.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"3919f47f-fdaf-5e51-a8e4-985bc1765a13","key":"low-f","name":"ฟ Is a Low-Class f","shortDescription":"ฟ makes a plain f and is low class","explanation":"ฟ is a simple f sound and is low class. You will meet its rarer high-class partner ฝ later; for now, ฟ covers almost every f word you will read.","examples":[{"text":"ไฟ = fai"},{"text":"ฟัง = fang"}]}],"drills":[{"id":"35dc42f9-8757-5d78-aa0c-488666a84d34","key":"fai-drill-01-recognize","type":"recognize","prompt":"Which letter makes the \"f\" sound?","payload":{},"options":[{"text":"ฟ","isCorrect":true},{"text":"พ"},{"text":"ผ"},{"text":"ป"}]},{"id":"ac4106ed-186b-5d34-a453-7a765875e7b1","key":"fai-drill-02-sound","type":"sound","prompt":"What sound does ฟ make?","payload":{},"options":[{"text":"f","isCorrect":true},{"text":"ph with a puff"},{"text":"bp"},{"text":"v"}]},{"id":"aec9e879-2067-5100-a0c1-5075ac1c43cb","key":"fai-drill-03-match","type":"match","prompt":"What does ไฟ mean?","payload":{},"options":[{"text":"fire / light","isCorrect":true},{"text":"water"},{"text":"road"},{"text":"cheap"}]},{"id":"8bf1acde-a544-5050-a2fe-980687d11584","key":"fai-drill-04-spot","type":"spot","prompt":"Which Thai spelling means \"fire / light\"?","payload":{},"options":[{"text":"ไฟ","isCorrect":true},{"text":"ฟไ"},{"text":"ไพ"},{"text":"ไฟฟ"}]},{"id":"3807672c-1e66-50d3-a39d-7161d831527b","key":"fai-drill-05-match","type":"match","prompt":"What does ไฟฟ้า mean?","payload":{},"options":[{"text":"electricity","isCorrect":true},{"text":"firewood"},{"text":"candle"},{"text":"sunlight"}]}]}}'::jsonb, 'b871d9191feebf178ecd183ce0c24e23c903bfd7c3529863307689a45e6a15c0', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('c850abce-daa7-5041-a809-d78982a439ac'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'f744f3da-0ec6-5c6d-af0c-4be7bc5d245c'::uuid, 'thanon', 28, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"f744f3da-0ec6-5c6d-af0c-4be7bc5d245c","slug":"thanon","lessonOrdinal":28,"stage":8,"title":"ถนน — The High-Class th and Leading Consonants","anchor":{"id":"a8707ee0-b48b-524c-a63b-ab2e78e46ba4","slug":"thanon","text":"ถนน","meaning":"road / street","pronunciation":"thà-nǒn","categoryKey":"sign","contextNote":"ถนน (road) appears on every street sign. It also shows the leading-consonant rule: the high-class ถ reaches across and sets the tone of the next syllable.","segments":[{"text":"ถ","sound":"thà"},{"text":"นน","sound":"nǒn"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"e93239c2-748d-560b-a904-003729e662dd","key":"word-0e16-0e32-0e21","text":"ถาม","meaning":"to ask","pronunciation":"thǎam","categoryKey":"daily","segments":[{"text":"ถาม","sound":"thǎam"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"61a19052-1d96-58dc-a07a-171675ec21e1","key":"word-0e16-0e39-0e01","text":"ถูก","meaning":"cheap / correct","pronunciation":"thùuk","categoryKey":"sign","segments":[{"text":"ถูก","sound":"thùuk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"3e01e673-b5d5-5b50-ac2b-842c8670b7a1","key":"word-0e16-0e49-0e32","text":"ถ้า","meaning":"if","pronunciation":"thâa","categoryKey":"daily","segments":[{"text":"ถ้า","sound":"thâa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"70add51c-5aab-5a06-a9bd-9eab94e7f276","key":"word-0e16-0e37-0e2d","text":"ถือ","meaning":"to hold","pronunciation":"thǔe","categoryKey":"daily","segments":[{"text":"ถือ","sound":"thǔe"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"ca7859eb-3daa-5777-adc9-2dffb6a37a04","key":"word-0e16-0e31-0e07","text":"ถัง","meaning":"bucket / tank","pronunciation":"thǎng","categoryKey":"daily","segments":[{"text":"ถัง","sound":"thǎng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"f6297a59-9869-5f47-a326-8bc6a90308ca","key":"word-0e16-0e36-0e07","text":"ถึง","meaning":"to arrive / until","pronunciation":"thǔeng","categoryKey":"daily","segments":[{"text":"ถึง","sound":"thǔeng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"0b76e5d0-2d90-587e-a280-52569c9e3a70","key":"word-0e16-0e2d-0e19","text":"ถอน","meaning":"to withdraw","pronunciation":"thǎwn","categoryKey":"daily","segments":[{"text":"ถอน","sound":"thǎwn"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"7b5996dc-c02b-5dda-a841-7f263d3c1835","key":"word-0e16-0e48-0e32-0e22","text":"ถ่าย","meaning":"to photograph","pronunciation":"thàai","categoryKey":"daily","segments":[{"text":"ถ่าย","sound":"thàai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"90e71f72-93b3-5e8d-a879-80df0e253191","key":"word-0e16-0e32-0e14","text":"ถาด","meaning":"tray","pronunciation":"thàat","categoryKey":"food","segments":[{"text":"ถาด","sound":"thàat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"562e8810-b199-57b9-a49e-4c4d8a3178d2","key":"word-0e16-0e39-0e01-0e15-0e49-0e2d-0e07","text":"ถูกต้อง","meaning":"correct","pronunciation":"thùuk-dtâwng","categoryKey":"daily","segments":[{"text":"ถูก","sound":"thùuk"},{"text":"ต้อง","sound":"dtâwng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":true,"item":{"id":"82a11a37-a228-55f0-ae69-6745f93685cf","key":"word-0e16-0e32-0e21-0e17-0e32-0e07","text":"ถามทาง","meaning":"to ask directions","pronunciation":"thǎam thaang","categoryKey":"sign","segments":[{"text":"ถาม","sound":"thǎam"},{"text":"ทาง","sound":"thaang"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"12f624a3-8cc9-55e5-a9c2-f3e6dd779f77","text":"ถ","kind":"consonant","romanization":"th","pronunciationHint":"th with a puff of air, like the \"t\" in \"top\"","mnemonic":"ถ is ถ ถุง (thǎw thǔng, a bag). Picture a drawstring sack; ถ gives an aspirated th in the high class.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"cf8eaddc-cd8e-55ca-a652-237794f23e8b","text":"ท","kind":"consonant","romanization":"th","pronunciationHint":"th with a puff of air, like the \"t\" in \"top\" (not the th in \"the\")","mnemonic":"ท is ท ทหาร (thor thahaan, soldier). Picture a soldier standing tall; ท gives the aspirated th sound with a clear puff of air.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"bda65912-fa0a-5328-a7d4-302245d61c3e","text":"ง","kind":"consonant","romanization":"ng","pronunciationHint":"ng as in \"singer\"; used at the start or end of a syllable","mnemonic":"ง is ง งู (ngor nguu, snake). Picture the curving body of a snake; ง makes the ng sound that English only uses at the ends of words.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"68c2e5cc-40a1-586d-a545-68cf0150d164","key":"high-th","name":"ถ Is a High-Class th","shortDescription":"ถ makes an aspirated th and is high class","explanation":"ถ is a th released with a puff of air, the same sound as low-class ท. Because ถ is high class, it follows high-class tone rules instead.","examples":[{"text":"ถาม = thǎam"},{"text":"ถูก = thùuk"}]},{"id":"e8ff106d-b6c6-57ec-a682-ac727fe30039","key":"leading-consonant","name":"A Lone Consonant Can Lead the Next Syllable","shortDescription":"In ถนน, ถ has no vowel and passes its class to นน","explanation":"When a consonant has no vowel of its own, it borrows a short ''a'' and leads into the next syllable, lending its class. In ถนน the high-class ถ makes the second syllable rise: thà-nǒn.","examples":[{"text":"ถนน = thà-nǒn"},{"text":"ขนม = khà-nǒm"}]}],"drills":[{"id":"6235fca8-9fb4-5b65-a4a0-b9f478ca3418","key":"thanon-drill-01-recognize","type":"recognize","prompt":"Which letter is the high-class \"th\"?","payload":{},"options":[{"text":"ถ","isCorrect":true},{"text":"ท"},{"text":"ต"},{"text":"ด"}]},{"id":"fb55d3db-b3ec-5aaf-a876-315b60c69ad4","key":"thanon-drill-02-sound","type":"sound","prompt":"How do ถ and ท differ?","payload":{},"options":[{"text":"same sound, different class","isCorrect":true},{"text":"ถ is a vowel"},{"text":"ท is unaspirated"},{"text":"they are unrelated"}]},{"id":"fe1fe758-7c33-5057-a9e9-0e59779f0242","key":"thanon-drill-03-sound","type":"sound","prompt":"In ถนน, what does the leading ถ do?","payload":{},"options":[{"text":"sets the tone of the next syllable","isCorrect":true},{"text":"stays silent"},{"text":"adds an m"},{"text":"nothing"}]},{"id":"f473cc5a-be9a-5054-ab77-742b7157391b","key":"thanon-drill-04-match","type":"match","prompt":"What does ถนน mean?","payload":{},"options":[{"text":"road / street","isCorrect":true},{"text":"bag"},{"text":"to ask"},{"text":"cheap"}]},{"id":"ab29e903-ac1e-5ac5-a97a-a25d9fc8550b","key":"thanon-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"road / street\"?","payload":{},"options":[{"text":"ถนน","isCorrect":true},{"text":"ทนน"},{"text":"ถนม"},{"text":"นนถ"}]}]}}'::jsonb, 'e7baf4c34d511566ec80aee7e8e9c38a9c69f48238df16e50b6961bf6bbd569d', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('cea2f97d-cae5-56ca-acbf-7d5ad8eb3a82'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'c7ea9e7c-9fe6-5f5c-a5f3-67ad2e608fd1'::uuid, 'mue', 29, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"c7ea9e7c-9fe6-5f5c-a5f3-67ad2e608fd1","slug":"mue","lessonOrdinal":29,"stage":8,"title":"มือ — The ue Vowels","anchor":{"id":"92514603-9bf0-5e73-a268-56444aa033f0","slug":"mue","text":"มือ","meaning":"hand","pronunciation":"mue","categoryKey":"daily","contextNote":"มือ (hand) shows the long ue vowel and its silent อ seat. It builds mobile-age words like มือถือ (mobile phone), literally ''hand-hold''.","segments":[{"text":"มือ","sound":"mue"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"5d3517e1-3089-5c07-a530-0cd641cbe594","key":"word-0e04-0e37-0e2d","text":"คือ","meaning":"is / namely","pronunciation":"khue","categoryKey":"daily","segments":[{"text":"คือ","sound":"khue"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"70add51c-5aab-5a06-a9bd-9eab94e7f276","key":"word-0e16-0e37-0e2d","text":"ถือ","meaning":"to hold","pronunciation":"thǔe","categoryKey":"daily","segments":[{"text":"ถือ","sound":"thǔe"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"835c1673-5e34-5f7b-accb-494ccbed955b","key":"word-0e25-0e37-0e21","text":"ลืม","meaning":"to forget","pronunciation":"luem","categoryKey":"daily","segments":[{"text":"ลืม","sound":"luem"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"35a059ea-89ef-5974-ad02-f93b4d97a54e","key":"word-0e2b-0e19-0e36-0e48-0e07","text":"หนึ่ง","meaning":"one","pronunciation":"nùeng","categoryKey":"daily","segments":[{"text":"หนึ่ง","sound":"nùeng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"b05f2ed1-80a1-5c4a-aafc-1d0bfc6cfd76","key":"word-0e14-0e36-0e01","text":"ดึก","meaning":"late at night","pronunciation":"dùek","categoryKey":"daily","segments":[{"text":"ดึก","sound":"dùek"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"9c6fef64-874e-58bd-ab6b-c9f36f2330fe","key":"word-0e22-0e37-0e21","text":"ยืม","meaning":"to borrow","pronunciation":"yuem","categoryKey":"daily","segments":[{"text":"ยืม","sound":"yuem"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"ce4459d8-731f-5328-a369-5cc2f56ee7c5","key":"word-0e21-0e37-0e14","text":"มืด","meaning":"dark","pronunciation":"mûet","categoryKey":"daily","segments":[{"text":"มืด","sound":"mûet"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"8e49beb6-f14f-5fb9-a6e4-b8d753b7f105","key":"word-0e15-0e36-0e01","text":"ตึก","meaning":"building","pronunciation":"dtùek","categoryKey":"place","segments":[{"text":"ตึก","sound":"dtùek"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"64d40398-e5b0-5ae4-ac0d-2a0ae23b22e2","key":"word-0e14-0e37-0e48-0e21","text":"ดื่ม","meaning":"to drink","pronunciation":"dùem","categoryKey":"food","segments":[{"text":"ดื่ม","sound":"dùem"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"ff26e311-77c5-5bfa-a9d1-66c88732c1d7","key":"word-0e21-0e37-0e2d-0e16-0e37-0e2d","text":"มือถือ","meaning":"mobile phone","pronunciation":"mue-thǔe","categoryKey":"daily","segments":[{"text":"มือ","sound":"mue"},{"text":"ถือ","sound":"thǔe"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":false,"item":{"id":"1bbc758f-6a83-59ad-a50d-96155c5cd36b","key":"word-0e04-0e34-0e14-0e16-0e36-0e07","text":"คิดถึง","meaning":"to miss (someone)","pronunciation":"khít-thǔeng","categoryKey":"daily","segments":[{"text":"คิด","sound":"khít"},{"text":"ถึง","sound":"thǔeng"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"82b5708a-99b4-5f49-a31b-973bdb32ad2f","text":"ื","kind":"vowel","romanization":"ue","pronunciationHint":"long \"ue\" — say \"ee\" with your lips relaxed and pulled back","mnemonic":"◌ื is the long ue vowel; the two marks above stretch the sound. Say a long ee but unround your lips.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"d380ce7e-121b-5bd7-a536-14332e4a8d91","text":"ึ","kind":"vowel","romanization":"ue","pronunciationHint":"short \"ue\" — a quick, clipped version of the long ◌ื","mnemonic":"◌ึ is the short ue; a single hook above gives one short beat of the same unrounded sound.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"155d0198-aac0-5a9d-a8ab-fb839ccab4f9","text":"ม","kind":"consonant","romanization":"m","pronunciationHint":"m as in \"mother\"","mnemonic":"ม is ม ม้า (mor ma, horse). Picture the tall middle stroke as a horse''s neck and the small loop as its head, then tie that horse word to the m sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"12f624a3-8cc9-55e5-a9c2-f3e6dd779f77","text":"ถ","kind":"consonant","romanization":"th","pronunciationHint":"th with a puff of air, like the \"t\" in \"top\"","mnemonic":"ถ is ถ ถุง (thǎw thǔng, a bag). Picture a drawstring sack; ถ gives an aspirated th in the high class.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"c40165fd-c08b-5e06-a932-28747ec7490c","text":"ค","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the \"c\" in \"cat\"","mnemonic":"ค is ค ควาย (khaw khwaai, buffalo). Picture a broad water buffalo; ค gives the same breathy kh as ข but belongs to the low class.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"b56f95f2-2848-5e8b-a09f-0c589464f09d","key":"ue-vowels","name":"◌ื and ◌ึ Are the ue Vowels","shortDescription":"◌ื is long ue, ◌ึ is short ue","explanation":"Both make the unrounded ue sound; length is the only difference. ◌ื is held long, ◌ึ is clipped short. Watch which one sits above the consonant.","examples":[{"text":"ลืม = luem"},{"text":"หนึ่ง = nùeng"}]},{"id":"e3dee5da-0118-5db1-ae79-e5ed3fb46885","key":"silent-aw-seat","name":"A Bare ◌ื Rests on a Silent อ","shortDescription":"With no final, ◌ื is written ◌ือ and the อ stays silent","explanation":"When a long ◌ื has no final consonant, Thai writes a silent อ as a seat, so มือ is read mue. The อ here adds no sound of its own.","examples":[{"text":"มือ = mue"},{"text":"คือ = khue"}]}],"drills":[{"id":"065c9af2-96e0-5a1c-acba-61aea8cfdbfe","key":"mue-drill-01-recognize","type":"recognize","prompt":"Which vowel is the long \"ue\"?","payload":{},"options":[{"text":"ื","isCorrect":true},{"text":"ึ"},{"text":"ี"},{"text":"ู"}]},{"id":"b56291c9-3863-53f3-aab5-e1443a0c5835","key":"mue-drill-02-sound","type":"sound","prompt":"How do ◌ื and ◌ึ differ?","payload":{},"options":[{"text":"length: long vs short","isCorrect":true},{"text":"one is a tone mark"},{"text":"one is nasal"},{"text":"they are the same"}]},{"id":"6136e14c-dc6b-50c4-acc9-d9653c59c472","key":"mue-drill-03-sound","type":"sound","prompt":"In มือ, what does the อ do?","payload":{},"options":[{"text":"it is a silent seat","isCorrect":true},{"text":"it adds an aw sound"},{"text":"it is a final k"},{"text":"it is a tone mark"}]},{"id":"4b3522fb-77a3-56ff-ab68-7ceef51d4722","key":"mue-drill-04-match","type":"match","prompt":"What does มือ mean?","payload":{},"options":[{"text":"hand","isCorrect":true},{"text":"night"},{"text":"hair"},{"text":"one"}]},{"id":"03bc2084-24af-5eb9-aa28-1955e6656b05","key":"mue-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"hand\"?","payload":{},"options":[{"text":"มือ","isCorrect":true},{"text":"มอ"},{"text":"มู"},{"text":"อืม"}]}]}}'::jsonb, 'c972dcdbc59dec5f33a6b27bbe79d68577d92494c0d277b7f57b77fc6f5a70e8', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('a9c14ce5-a969-5a2a-a271-3d2c363d7616'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '94181540-937d-5441-ade4-480016067418'::uuid, 'bia', 30, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"94181540-937d-5441-ade4-480016067418","slug":"bia","lessonOrdinal":30,"stage":9,"title":"เบียร์ — The ia Vowel and the Silent Mark","anchor":{"id":"f754213c-ae41-581c-af07-ad5f68b13c45","slug":"bia","text":"เบียร์","meaning":"beer","pronunciation":"biia","categoryKey":"food","contextNote":"เบียร์ (beer) is a loanword that shows two new tools: the ia diphthong and ◌์, the mark that silences a consonant — here the final ร.","segments":[{"text":"เบียร์","sound":"biia"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"83c36c00-b7fc-5716-af5b-06f28c56f3b4","key":"word-0e40-0e2a-0e35-0e22","text":"เสีย","meaning":"to lose / broken","pronunciation":"sǐia","categoryKey":"daily","segments":[{"text":"เสีย","sound":"sǐia"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"046926db-a4a6-5b02-a3fc-e991fbc9e6be","key":"word-0e40-0e23-0e35-0e22-0e19","text":"เรียน","meaning":"to study","pronunciation":"rian","categoryKey":"daily","segments":[{"text":"เรียน","sound":"rian"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"4ddc0ded-b0ce-557c-a497-13c98ca1c3d0","key":"word-0e40-0e02-0e35-0e22-0e19","text":"เขียน","meaning":"to write","pronunciation":"khǐian","categoryKey":"daily","segments":[{"text":"เขียน","sound":"khǐian"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"eb820c9e-0ba8-5cf9-a595-2c95deb694b3","key":"word-0e40-0e21-0e35-0e22","text":"เมีย","meaning":"wife (colloquial)","pronunciation":"miia","categoryKey":"daily","segments":[{"text":"เมีย","sound":"miia"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"d6667698-0a5f-568c-a5b7-32c4c56e8588","key":"word-0e40-0e1b-0e35-0e22-0e01","text":"เปียก","meaning":"wet","pronunciation":"bpìiak","categoryKey":"daily","segments":[{"text":"เปียก","sound":"bpìiak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"f1b0fcdc-20da-577d-af5c-41fd95244512","key":"word-0e40-0e2a-0e37-0e49-0e2d","text":"เสื้อ","meaning":"shirt","pronunciation":"sûea","categoryKey":"daily","segments":[{"text":"เสื้อ","sound":"sûea"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"86ca6418-9ae0-547f-acc7-37c1772ed921","key":"word-0e42-0e17-0e23-0e28-0e31-0e1e-0e17-0e4c","text":"โทรศัพท์","meaning":"telephone","pronunciation":"thoo-rá-sàp","categoryKey":"daily","segments":[{"text":"โท","sound":"thoo"},{"text":"ระ","sound":"rá"},{"text":"ศัพท์","sound":"sàp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"6aa38476-d0da-5f3c-ac11-a6b9a1acde62","key":"word-0e2d-0e32-0e17-0e34-0e15-0e22-0e4c","text":"อาทิตย์","meaning":"week / Sunday","pronunciation":"aa-thít","categoryKey":"daily","segments":[{"text":"อา","sound":"aa"},{"text":"ทิตย์","sound":"thít"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"4bc3965a-2530-5573-a386-9f62ef276bf7","key":"word-0e40-0e2a-0e35-0e22-0e43-0e08","text":"เสียใจ","meaning":"sad","pronunciation":"sǐia-jai","categoryKey":"daily","segments":[{"text":"เสีย","sound":"sǐia"},{"text":"ใจ","sound":"jai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"f4030dbe-43e3-57bb-a822-8e241163523c","key":"word-0e40-0e23-0e35-0e22-0e19-0e20-0e32-0e29-0e32","text":"เรียนภาษา","meaning":"to study a language","pronunciation":"rian phaa-sǎa","categoryKey":"daily","segments":[{"text":"เรียน","sound":"rian"},{"text":"ภา","sound":"phaa"},{"text":"ษา","sound":"sǎa"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"letter-type-mark","title":"Written mark","body":"This is a written symbol that isn''t a consonant, vowel, or tone mark. Thai uses a few of these — for example ๆ repeats the preceding word, and ์ silences the consonant it sits above. Each one changes how you read the syllable rather than adding a sound of its own."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"4055d86a-8285-53d8-aa77-d270e4fdbe5d","text":"เ◌ีย","kind":"vowel","romanization":"ia","pronunciationHint":"the \"ia\" glide, like \"ea\" in \"ear\"","mnemonic":"เ leads on the left, ◌ี rides above, and ย trails on the right. Together they glide from ee into a, the ia diphthong.","position":"around","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"f601a10f-6f2f-5e36-a707-4bf62de8b382","text":"์","kind":"mark","romanization":"(silent)","pronunciationHint":"karan — it silences the consonant it sits above","mnemonic":"◌์ is the karan (thanthakhat). Think of it crossing out the consonant beneath it, so you do not pronounce that letter.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-mark","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"d930649b-b987-5148-a7d1-8aaabef44060","text":"เ","kind":"vowel","romanization":"e","pronunciationHint":"long \"e\" as in \"they\"","mnemonic":"เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"f08f3ab4-ea11-53cf-a8b5-c3ea310041b1","text":"ย","kind":"consonant","romanization":"y","pronunciationHint":"y as in \"yes\"; at the end of a syllable it forms a glide like the \"y\" in \"boy\"","mnemonic":"ย is ย ยักษ์ (yor yak, giant). Picture a towering giant; ย gives the y sound at the start and a y-glide at the end.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"dddb2e02-9aa3-5dde-a2ab-25524fc96559","text":"บ","kind":"consonant","romanization":"b/p","pronunciationHint":"b as in \"bat\" at the start; clipped p at the end","mnemonic":"บ is บ ใบไม้ (bor bai mai, leaf). The open bowl shape can hold a leaf, and ใบไม้ gives you the b sound at the start.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"f7ec78ba-9e54-5882-a5ac-cab27c98a100","key":"ia-vowel","name":"เ-ีย Is the ia Diphthong","shortDescription":"เ + ◌ี + ย make a gliding ia sound","explanation":"The frame เ-ีย glides from an ee into an a. It is common in everyday words like เรียน (to study) and เขียน (to write).","examples":[{"text":"เรียน = rian"},{"text":"เสีย = sǐia"}]},{"id":"7ee55321-bb8a-5e7c-a954-1e7f3c573a79","key":"karan-silent","name":"◌์ Silences a Consonant","shortDescription":"A consonant under ◌์ is not pronounced","explanation":"The karan mark cancels the consonant beneath it. It appears mostly in loanwords and Pali/Sanskrit spellings, as in เบียร์ (beer), where the final ร is silent.","examples":[{"text":"เบียร์ = biia"},{"text":"อาทิตย์ = aa-thít"}]}],"drills":[{"id":"8befe96e-96e6-5916-a19b-3f7c9e65e70e","key":"bia-drill-01-recognize","type":"recognize","prompt":"Which frame makes the \"ia\" sound?","payload":{},"options":[{"text":"เ◌ีย","isCorrect":true},{"text":"เ◌า"},{"text":"◌ัว"},{"text":"เ◌อ"}]},{"id":"47cbc99f-8159-5513-afc9-132207c91bdd","key":"bia-drill-02-sound","type":"sound","prompt":"What does the ◌์ mark do?","payload":{},"options":[{"text":"silences the consonant beneath it","isCorrect":true},{"text":"raises the tone"},{"text":"adds an m"},{"text":"lengthens the vowel"}]},{"id":"25425101-bf9e-5c9b-a2ee-f5956f731c64","key":"bia-drill-03-sound","type":"sound","prompt":"In เบียร์, why is the ร silent?","payload":{},"options":[{"text":"it carries a karan mark","isCorrect":true},{"text":"it is a vowel"},{"text":"it is doubled"},{"text":"it is at the start"}]},{"id":"94cbd8e8-9c8a-51de-ab54-30943e05566e","key":"bia-drill-04-match","type":"match","prompt":"What does เบียร์ mean?","payload":{},"options":[{"text":"beer","isCorrect":true},{"text":"week"},{"text":"to study"},{"text":"to lose"}]},{"id":"fe5bb8d8-4fa8-5b92-a6e0-8175227b9b95","key":"bia-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"beer\"?","payload":{},"options":[{"text":"เบียร์","isCorrect":true},{"text":"เบีย"},{"text":"เรียน"},{"text":"เบยร์"}]}]}}'::jsonb, 'd2c7689c1225f3913eaa693ee3627a695a559c05539b169d0d2563faf0c71f1e', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('1a5e4391-dd52-5ecd-a94d-a0271d2f2ffc'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'd6f5428a-b561-54ad-ab67-02d1f274bc9c'::uuid, 'wua', 31, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"d6f5428a-b561-54ad-ab67-02d1f274bc9c","slug":"wua","lessonOrdinal":31,"stage":9,"title":"วัว — The ua Vowel","anchor":{"id":"5473971c-c02a-52e1-a21f-05394208afb6","slug":"wua","text":"วัว","meaning":"cow","pronunciation":"wuua","categoryKey":"daily","contextNote":"วัว (cow) introduces the ua diphthong. It is a friendly word that also shows how ◌ั teams up with ว to make a gliding vowel.","segments":[{"text":"วัว","sound":"wuua"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"18d020b7-932a-5d37-a916-eb1cba31dc37","key":"word-0e15-0e31-0e27","text":"ตัว","meaning":"body / classifier","pronunciation":"dtuua","categoryKey":"daily","segments":[{"text":"ตัว","sound":"dtuua"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"0c3d4a24-2b48-581a-a296-6f0b7480f539","key":"word-0e2b-0e31-0e27","text":"หัว","meaning":"head","pronunciation":"hǔua","categoryKey":"daily","segments":[{"text":"หัว","sound":"hǔua"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"9da7f104-2907-54d1-acad-f18cffa49db1","key":"word-0e01-0e25-0e31-0e27","text":"กลัว","meaning":"to fear","pronunciation":"gluua","categoryKey":"daily","segments":[{"text":"กลัว","sound":"gluua"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"48020f26-c096-59c2-a7cd-e965f5091c18","key":"word-0e14-0e49-0e27-0e22","text":"ด้วย","meaning":"also / with","pronunciation":"dûuai","categoryKey":"daily","segments":[{"text":"ด้วย","sound":"dûuai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"ad49c694-17f5-528e-a505-0ce65ac08dce","key":"word-0e04-0e23-0e31-0e27","text":"ครัว","meaning":"kitchen","pronunciation":"khruua","categoryKey":"daily","segments":[{"text":"ครัว","sound":"khruua"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"588d85de-f8d6-5cd4-a27c-94fdcae41ed1","key":"word-0e23-0e27-0e22","text":"รวย","meaning":"rich","pronunciation":"ruuai","categoryKey":"daily","segments":[{"text":"รวย","sound":"ruuai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"2eaf93d4-a195-5415-a2bd-fe228658b036","key":"word-0e2a-0e27-0e22","text":"สวย","meaning":"beautiful","pronunciation":"sǔuai","categoryKey":"daily","segments":[{"text":"สวย","sound":"sǔuai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"1f205037-1813-5ded-a340-71fc8ac11a8d","key":"word-0e2a-0e48-0e27-0e19","text":"ส่วน","meaning":"part / portion","pronunciation":"sùuan","categoryKey":"daily","segments":[{"text":"ส่วน","sound":"sùuan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"d5ac88d8-5e65-5714-af9f-4e1b957d3c30","key":"word-0e15-0e31-0e27-0e40-0e2d-0e07","text":"ตัวเอง","meaning":"oneself","pronunciation":"dtuua-eeng","categoryKey":"daily","segments":[{"text":"ตัว","sound":"dtuua"},{"text":"เอง","sound":"eeng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"24b0374d-6c6a-51bd-a501-79f3eb10bc90","key":"word-0e04-0e23-0e2d-0e1a-0e04-0e23-0e31-0e27","text":"ครอบครัว","meaning":"family","pronunciation":"khrâwp-khruua","categoryKey":"daily","segments":[{"text":"ครอบ","sound":"khrâwp"},{"text":"ครัว","sound":"khruua"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"7f75ad3a-91f1-533b-a0fc-74edb84c7173","text":"◌ัว","kind":"vowel","romanization":"ua","pronunciationHint":"the \"ua\" glide, like \"oo-a\" said quickly","mnemonic":"◌ั sits above the consonant and ว trails after it. Together they glide from oo into a — the ua diphthong.","position":"around","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"5e1b543b-6be0-5279-a812-4ec61ce2b1dc","text":"ว","kind":"consonant","romanization":"w","pronunciationHint":"w as in \"water\"; can help form vowel glides","mnemonic":"ว is ว แหวน (wor waen, ring). The rounded curl looks like a ring, and แหวน gives you the w sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"6655bad5-f432-5868-aa67-e7247253802f","text":"ั","kind":"vowel","romanization":"a","pronunciationHint":"short \"a\" as in \"cut\"","mnemonic":"ั is the short a cap above the consonant. It sits close and quick, just like the clipped a in ผัด and ผัก.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"98079396-6adf-5409-a63c-121764a3840e","text":"ห","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hello\"; often used as a leading tone helper","mnemonic":"ห is ห หีบ (hor hiip, chest). Picture the tall shape as a chest with a lid; in words like หมู, this h-letter can also guide the tone.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"aac626a6-9661-5078-a17e-cf05d4233f7c","key":"ua-vowel","name":"◌ัว Is the ua Diphthong","shortDescription":"◌ั + ว make a gliding ua sound when there is no final","explanation":"With no final consonant, ◌ั and ว together make ua, as in วัว (cow) and ตัว (body/classifier). Read the consonant, then glide oo-a.","examples":[{"text":"วัว = wuua"},{"text":"ตัว = dtuua"}]},{"id":"0e91260e-2d71-52a8-aa93-829be8d6451a","key":"ua-with-final","name":"ua Splits Around a Final","shortDescription":"With a final, the vowel is written ◌ว◌","explanation":"When the ua syllable has a final consonant, the vowel is written with ว in the middle, as in สวน (sǔuan, garden). It is the same ua sound, just reshaped to fit the final.","examples":[{"text":"สวน = sǔuan"},{"text":"ด้วย = dûuai"}]}],"drills":[{"id":"9ab7d739-70e9-50da-a5ed-416393ef9731","key":"wua-drill-01-recognize","type":"recognize","prompt":"Which frame makes the \"ua\" sound?","payload":{},"options":[{"text":"◌ัว","isCorrect":true},{"text":"เ◌ีย"},{"text":"เ◌า"},{"text":"◌ำ"}]},{"id":"f8c6b41b-bda9-5f5c-af2b-5285b4ef4d5c","key":"wua-drill-02-sound","type":"sound","prompt":"What sound does ◌ัว make?","payload":{},"options":[{"text":"a gliding ua","isCorrect":true},{"text":"a short am"},{"text":"a long aa"},{"text":"an ao"}]},{"id":"e7cd2841-4411-52f5-a9c2-25e579c906fd","key":"wua-drill-03-sound","type":"sound","prompt":"How is the ua vowel written when a final follows?","payload":{},"options":[{"text":"as ◌ว◌ around the final","isCorrect":true},{"text":"as ◌ำ"},{"text":"it disappears"},{"text":"as เ◌า"}]},{"id":"01f3953b-afae-5952-a7b7-7d9de2883220","key":"wua-drill-04-match","type":"match","prompt":"What does วัว mean?","payload":{},"options":[{"text":"cow","isCorrect":true},{"text":"head"},{"text":"kitchen"},{"text":"beautiful"}]},{"id":"eb9b1d7d-83fe-57e4-a5d3-766232d6c6e5","key":"wua-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"cow\"?","payload":{},"options":[{"text":"วัว","isCorrect":true},{"text":"ตัว"},{"text":"หัว"},{"text":"วว"}]}]}}'::jsonb, '8ba361afe3b2d07db5920b3900f8d858d2bbbe31d84cdd533c0089187f251842', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('4a73326b-8350-54cd-a8e7-e8579ff9edce'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'e08fd5fc-bed4-5a96-a23b-f8fa42eabe13'::uuid, 'jer', 32, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"e08fd5fc-bed4-5a96-a23b-f8fa42eabe13","slug":"jer","lessonOrdinal":32,"stage":9,"title":"เจอ — The er Vowel","anchor":{"id":"dbfcd390-2522-5af1-a8be-1c4158106e14","slug":"jer","text":"เจอ","meaning":"to meet / to find","pronunciation":"jer","categoryKey":"daily","contextNote":"เจอ (to meet, to run into) introduces the long er vowel. It is a high-frequency verb — เจอกัน (see you) closes countless conversations.","segments":[{"text":"เจอ","sound":"jer"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"3d5c4482-956d-5075-a0b6-a295c62f3895","key":"word-0e40-0e18-0e2d","text":"เธอ","meaning":"you / she (intimate)","pronunciation":"ther","categoryKey":"daily","segments":[{"text":"เธอ","sound":"ther"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"3ca753d0-7cf2-53c3-a121-0729f4058bb4","key":"word-0e40-0e07-0e34-0e19","text":"เงิน","meaning":"money / silver","pronunciation":"ngern","categoryKey":"daily","segments":[{"text":"เงิน","sound":"ngern"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"7e810d18-e306-5e5e-a449-b05eaa6a3500","key":"word-0e40-0e14-0e34-0e19","text":"เดิน","meaning":"to walk","pronunciation":"dern","categoryKey":"daily","segments":[{"text":"เดิน","sound":"dern"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"2f6d7782-aa00-517d-a01a-dbbcc35aef5d","key":"word-0e40-0e1b-0e34-0e14","text":"เปิด","meaning":"to open","pronunciation":"bpèrt","categoryKey":"sign","segments":[{"text":"เปิด","sound":"bpèrt"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"e1de5e89-c49a-5f6c-ae40-c82cdaeb2950","key":"word-0e40-0e01-0e34-0e14","text":"เกิด","meaning":"to be born / happen","pronunciation":"gèrt","categoryKey":"daily","segments":[{"text":"เกิด","sound":"gèrt"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"072645de-3a53-5ba8-a175-f370579b9ab4","key":"word-0e40-0e23-0e34-0e48-0e21","text":"เริ่ม","meaning":"to begin","pronunciation":"rêrm","categoryKey":"daily","segments":[{"text":"เริ่ม","sound":"rêrm"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"4c75f85a-e58e-5dca-ace1-cde6064ee98e","key":"word-0e40-0e1e-0e34-0e48-0e21","text":"เพิ่ม","meaning":"to increase","pronunciation":"phêrm","categoryKey":"daily","segments":[{"text":"เพิ่ม","sound":"phêrm"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"d8e65a2d-5a0e-5230-a807-9772109da0d0","key":"word-0e40-0e25-0e22","text":"เลย","meaning":"at all / completely","pronunciation":"leri","categoryKey":"daily","segments":[{"text":"เลย","sound":"leri"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"35d02d5e-73f6-5526-ac36-390e9e47cca3","key":"word-0e40-0e04-0e22","text":"เคย","meaning":"to have ever","pronunciation":"keri","categoryKey":"daily","segments":[{"text":"เคย","sound":"keri"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":true,"item":{"id":"2a50157e-fb4b-5a42-aad0-6f0c230d6c17","key":"word-0e40-0e08-0e2d-0e01-0e31-0e19","text":"เจอกัน","meaning":"see you / meet up","pronunciation":"jer gan","categoryKey":"daily","segments":[{"text":"เจอ","sound":"jer"},{"text":"กัน","sound":"gan"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":false,"item":{"id":"7f8c0c18-0d58-5d6d-a293-be6ddb02997a","key":"word-0e40-0e14-0e34-0e19-0e40-0e25-0e48-0e19","text":"เดินเล่น","meaning":"to stroll","pronunciation":"dern lên","categoryKey":"daily","segments":[{"text":"เดิน","sound":"dern"},{"text":"เล่น","sound":"lên"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"fa5b3ce8-7853-5bec-ac17-d54c455cc2c5","text":"เ◌อ","kind":"vowel","romanization":"er","pronunciationHint":"long \"er\", like \"her\" without the r","mnemonic":"เ leads on the left and อ trails on the right, giving a long er. Before a final it shrinks into เ◌ิ◌.","position":"around","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"d930649b-b987-5148-a7d1-8aaabef44060","text":"เ","kind":"vowel","romanization":"e","pronunciationHint":"long \"e\" as in \"they\"","mnemonic":"เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"e4575690-2031-5d02-a9ed-227f99686432","text":"จ","kind":"consonant","romanization":"j","pronunciationHint":"j as in \"jar\", but lighter and unaspirated","mnemonic":"จ is จ จาน (jor jaan, plate). Picture a round dinner plate; จ gives a light, crisp j sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"eac919f3-4542-5bcf-ab31-3918869c1c59","key":"er-vowel","name":"เ-อ Is the Long er Vowel","shortDescription":"เ + อ make a long er with no final","explanation":"When there is no final consonant, เ-อ is a long er, as in เจอ (to meet) and เธอ (you). Read the consonant, then the er.","examples":[{"text":"เจอ = jer"},{"text":"เธอ = ther"}]},{"id":"8021bef0-f644-5e38-a099-d480c81b04a8","key":"er-before-final","name":"er Becomes เ-ิ- Before a Final","shortDescription":"With a final, er is written เ◌ิ◌; เงิน is short","explanation":"Before a final consonant the er vowel is reshaped to เ◌ิ◌, as in เดิน (dern, to walk). A few words like เงิน (ngern, money) shorten it.","examples":[{"text":"เดิน = dern"},{"text":"เงิน = ngern"}]}],"drills":[{"id":"7fbe6f0b-a235-5f4d-a2ed-c9864e7f6b9a","key":"jer-drill-01-recognize","type":"recognize","prompt":"Which frame makes the long \"er\" sound?","payload":{},"options":[{"text":"เ◌อ","isCorrect":true},{"text":"เ◌า"},{"text":"◌ัว"},{"text":"เ◌ีย"}]},{"id":"b73ba02f-5f67-5ae4-a519-9e52e258ec7a","key":"jer-drill-02-sound","type":"sound","prompt":"What sound does เ-อ make with no final?","payload":{},"options":[{"text":"a long er","isCorrect":true},{"text":"a short am"},{"text":"an ao"},{"text":"an ia"}]},{"id":"e0269841-b808-51c6-a47a-647f3f7d7701","key":"jer-drill-03-sound","type":"sound","prompt":"How is the er vowel written before a final?","payload":{},"options":[{"text":"as เ◌ิ◌","isCorrect":true},{"text":"as ◌ำ"},{"text":"as เ◌า"},{"text":"it disappears"}]},{"id":"ccf83d0e-5081-5e12-a173-e553e83fd8d8","key":"jer-drill-04-match","type":"match","prompt":"What does เจอ mean?","payload":{},"options":[{"text":"to meet / to find","isCorrect":true},{"text":"to walk"},{"text":"money"},{"text":"to open"}]},{"id":"27042d77-6a5a-5e49-abe5-37867ddda61c","key":"jer-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"to meet\"?","payload":{},"options":[{"text":"เจอ","isCorrect":true},{"text":"เธอ"},{"text":"เดิน"},{"text":"จเอ"}]}]}}'::jsonb, 'b684ac85206d09cb0d5cb601248d8a665b2a36d8fe36115c8f1eea59bb8c3a57', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('a2968839-85ca-51a3-a39f-90a04b981959'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'c1dbe83d-891d-55df-a684-4f9e445b3472'::uuid, 'plaa', 33, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"c1dbe83d-891d-55df-a684-4f9e445b3472","slug":"plaa","lessonOrdinal":33,"stage":9,"title":"ปลา — True Consonant Clusters","anchor":{"id":"9685afb1-3e97-5a92-aa1c-2f04112c19ac","slug":"plaa","text":"ปลา","meaning":"fish","pronunciation":"bplaa","categoryKey":"food","contextNote":"ปลา (fish) opens with a true cluster, ปล: both consonants blend with no vowel between them. This lesson teaches how clusters differ from the hidden-vowel frame.","segments":[{"text":"ปลา","sound":"bplaa"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"a2e3d287-1d9f-5ecd-afc0-219c6d67720a","key":"word-0e01-0e25-0e31-0e1a","text":"กลับ","meaning":"to return","pronunciation":"glàp","categoryKey":"daily","segments":[{"text":"กลับ","sound":"glàp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"11f22b97-7055-5933-a5ee-0984de2aaa0f","key":"word-0e04-0e23-0e31-0e1a","text":"ครับ","meaning":"polite particle (male)","pronunciation":"khráp","categoryKey":"daily","segments":[{"text":"ครับ","sound":"khráp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"12c6f383-8ad8-52cf-abb9-9f77b4162c19","key":"word-0e01-0e25-0e32-0e07","text":"กลาง","meaning":"middle / center","pronunciation":"glaang","categoryKey":"daily","segments":[{"text":"กลาง","sound":"glaang"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"49d998d8-81d7-509b-ab5c-b6fab9b2e9c3","key":"word-0e02-0e27-0e32","text":"ขวา","meaning":"right (direction)","pronunciation":"khwǎa","categoryKey":"sign","segments":[{"text":"ขวา","sound":"khwǎa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"04ef5693-178b-5bd7-aed1-d984481ecb33","key":"word-0e40-0e04-0e23-0e37-0e48-0e2d-0e07","text":"เครื่อง","meaning":"machine / appliance","pronunciation":"khrûeang","categoryKey":"daily","segments":[{"text":"เครื่อง","sound":"khrûeang"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"d488ad5b-ead2-53a3-a836-76ec87987e54","key":"word-0e15-0e23-0e07","text":"ตรง","meaning":"straight","pronunciation":"dtrong","categoryKey":"sign","segments":[{"text":"ตรง","sound":"dtrong"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"9da7f104-2907-54d1-acad-f18cffa49db1","key":"word-0e01-0e25-0e31-0e27","text":"กลัว","meaning":"to fear","pronunciation":"gluua","categoryKey":"daily","segments":[{"text":"กลัว","sound":"gluua"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"bb6f279f-ad37-59a9-a581-29358ad1ec75","key":"word-0e43-0e01-0e25-0e49","text":"ใกล้","meaning":"near","pronunciation":"glâi","categoryKey":"daily","segments":[{"text":"ใกล้","sound":"glâi"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"6668e1e1-7549-54aa-a270-b92ad2de2ce2","key":"word-0e1b-0e25-0e38-0e01","text":"ปลุก","meaning":"to wake (someone)","pronunciation":"bplùk","categoryKey":"daily","segments":[{"text":"ปลุก","sound":"bplùk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"4046b5f4-8aa0-51af-a567-8c6675e82b6f","key":"word-0e01-0e23-0e38-0e07-0e40-0e17-0e1e","text":"กรุงเทพ","meaning":"Bangkok","pronunciation":"grung-thêep","categoryKey":"place","segments":[{"text":"กรุง","sound":"grung"},{"text":"เทพ","sound":"thêep"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[],"reviewGraphemes":[{"id":"1468f8a2-d91f-5127-ac8d-e40de6f54950","text":"ป","kind":"consonant","romanization":"bp","pronunciationHint":"a tight, unaspirated p, like the p in \"spin\" (between English b and p)","mnemonic":"ป is ป ปลา (bpor bplaa, fish). Picture a tall fish standing on its tail; ป is the unaspirated p that pairs with the dt sound of ต.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"50ada581-79e7-5549-a9a8-77693569d9b8","text":"ล","kind":"consonant","romanization":"l","pronunciationHint":"l as in \"love\"","mnemonic":"ล is ล ลิง (lor ling, monkey). Let the long lower curve be the monkey''s tail, and connect ลิง to the l sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"5e1b543b-6be0-5279-a812-4ec61ce2b1dc","text":"ว","kind":"consonant","romanization":"w","pronunciationHint":"w as in \"water\"; can help form vowel glides","mnemonic":"ว is ว แหวน (wor waen, ring). The rounded curl looks like a ring, and แหวน gives you the w sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"a67a4ba5-86ba-587e-a59f-f3f7c726808b","key":"true-cluster","name":"True Clusters Blend Two Consonants","shortDescription":"A stop + ร/ล/ว is read together with no inserted vowel","explanation":"A true cluster joins a stop (ก ข ค ต ป พ) with ร, ล, or ว and blends them with no vowel between. The tone follows the first consonant''s class, and any tone mark sits over the second consonant.","examples":[{"text":"ปลา = bplaa"},{"text":"ครับ = khráp"}]},{"id":"52bb2994-c7e5-584c-a387-0ab1c5a8d11a","key":"cluster-vs-hidden","name":"Clusters Are Not the Hidden-Vowel Frame","shortDescription":"ปล blends, but ตล and ขน insert a short ''a''","explanation":"Compare ปลา (bplaa, blended) with ตลาด (dtà-làat) and ขนม (khà-nǒm), where a short ''a'' is inserted between the consonants. Only a stop + ร/ล/ว truly blends; other pairs lead into a second syllable.","examples":[{"text":"ปลา = bplaa"},{"text":"ขนม = khà-nǒm"}]}],"drills":[{"id":"872df683-ef2d-5e80-afb7-14a420576517","key":"plaa-drill-01-sound","type":"sound","prompt":"In a true cluster, how are the two consonants read?","payload":{},"options":[{"text":"blended, with no vowel between","isCorrect":true},{"text":"with an inserted ''a''"},{"text":"as two syllables"},{"text":"the second is silent"}]},{"id":"9bd1f48c-64fa-5bd9-a118-cf99a6553d12","key":"plaa-drill-02-sound","type":"sound","prompt":"In ปลา, which consonant sets the tone?","payload":{},"options":[{"text":"the first consonant, ป","isCorrect":true},{"text":"the second consonant, ล"},{"text":"the vowel"},{"text":"neither"}]},{"id":"9783ce0f-4ccb-503d-a39d-3b580c601498","key":"plaa-drill-03-spot","type":"spot","prompt":"Which word is a TRUE cluster (no inserted vowel)?","payload":{},"options":[{"text":"ปลา","isCorrect":true},{"text":"ตลาด"},{"text":"ขนม"},{"text":"ถนน"}]},{"id":"f1f363c0-d98f-5c49-ad43-5eaec49b9d77","key":"plaa-drill-04-match","type":"match","prompt":"What does ปลา mean?","payload":{},"options":[{"text":"fish","isCorrect":true},{"text":"to return"},{"text":"middle"},{"text":"monk"}]},{"id":"acc5bd00-3693-565c-a1b6-8ff57b433a4b","key":"plaa-drill-05-sound","type":"sound","prompt":"Where does a tone mark sit in a cluster?","payload":{},"options":[{"text":"over the second consonant","isCorrect":true},{"text":"over the first consonant"},{"text":"over the vowel"},{"text":"it is dropped"}]}]}}'::jsonb, '791112a9c8e725cc353b0f4a3bc6f9bb8ea93e5964a595b22aac805672c614b3', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('475388ac-5a63-5d5a-aabe-33a894328698'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '0f5d0c7d-a70f-56b8-ae86-6c648f7a705e'::uuid, 'toh', 34, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"0f5d0c7d-a70f-56b8-ae86-6c648f7a705e","slug":"toh","lessonOrdinal":34,"stage":10,"title":"โต๊ะ — The Last Two Tone Marks","anchor":{"id":"49b4ef3d-663d-5c7d-a495-87b6c22d954b","slug":"toh","text":"โต๊ะ","meaning":"table","pronunciation":"dtó","categoryKey":"daily","contextNote":"โต๊ะ (table) carries mai tri. With mai chattawa, this lesson completes all four Thai tone marks — the ones that appear mostly on mid-class, loan, and food words.","segments":[{"text":"โต๊ะ","sound":"dtó"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"2e48b4e6-bb58-5c48-aa98-d82376776783","key":"word-0e01-0e4b-0e27-0e22-0e40-0e15-0e35-0e4b-0e22-0e27","text":"ก๋วยเตี๋ยว","meaning":"noodle soup","pronunciation":"gǔuai-dtǐiao","categoryKey":"food","segments":[{"text":"ก๋วย","sound":"gǔuai"},{"text":"เตี๋ยว","sound":"dtǐiao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"c24d68e6-1bf3-57c5-ae82-7edeabff85cc","key":"word-0e08-0e4a-0e30","text":"จ๊ะ","meaning":"friendly particle","pronunciation":"já","categoryKey":"daily","segments":[{"text":"จ๊ะ","sound":"já"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"ba83e27d-0507-57b6-a43d-2ccac01a0d20","key":"word-0e01-0e4a-0e2d-0e01","text":"ก๊อก","meaning":"faucet / tap","pronunciation":"gáwk","categoryKey":"daily","segments":[{"text":"ก๊อก","sound":"gáwk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"b6862fd9-2e64-563e-a3f6-40991e60bfc7","key":"word-0e40-0e01-0e4b","text":"เก๋","meaning":"chic / stylish","pronunciation":"gěe","categoryKey":"daily","segments":[{"text":"เก๋","sound":"gěe"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"371be852-e481-5d9d-a745-a2de32625f59","key":"word-0e08-0e4b-0e32","text":"จ๋า","meaning":"(sweet response particle)","pronunciation":"jǎa","categoryKey":"daily","segments":[{"text":"จ๋า","sound":"jǎa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"2c1e983e-468a-5e57-aa38-70520e2e7992","key":"word-0e15-0e38-0e4a-0e01-0e15-0e32","text":"ตุ๊กตา","meaning":"doll","pronunciation":"dtúk-gà-dtaa","categoryKey":"daily","segments":[{"text":"ตุ๊ก","sound":"dtúk"},{"text":"ตา","sound":"gà-dtaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"446198ad-ae7c-5a32-a2f3-71a81eec9f9a","key":"word-0e40-0e1b-0e4a-0e30","text":"เป๊ะ","meaning":"exactly / perfect","pronunciation":"bpé","categoryKey":"daily","segments":[{"text":"เป๊ะ","sound":"bpé"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"5dec1d83-1d38-52fa-a923-af12beffc61d","key":"word-0e42-0e1b-0e4a","text":"โป๊","meaning":"nude / risqué","pronunciation":"bpó","categoryKey":"daily","segments":[{"text":"โป๊","sound":"bpó"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"c498217e-233c-5003-a4f8-e8d93a73a18c","key":"word-0e01-0e4b-0e07","text":"ก๋ง","meaning":"grandfather (Chinese-Thai)","pronunciation":"gǒng","categoryKey":"daily","segments":[{"text":"ก๋ง","sound":"gǒng"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-tone-mark","title":"Tone mark","body":"Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"be58124c-1745-501b-ac43-404a370ffad5","text":"๊","kind":"tone_mark","romanization":"(tone)","pronunciationHint":"mai tri — the third tone mark; on a mid consonant it gives a high tone","mnemonic":"◌๊ mai tri stacks like a small figure that tops out high. It rides mostly on mid-class letters in loan and food words, pushing the tone high.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]},{"id":"51e0f7f8-6987-502a-a7d2-e3e87c237050","text":"๋","kind":"tone_mark","romanization":"(tone)","pronunciationHint":"mai chattawa — the fourth tone mark; on a mid consonant it gives a rising tone","mnemonic":"◌๋ mai chattawa is the plus-shaped fourth mark. On a mid-class letter it lifts the syllable into a rising tone.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"6450d4bf-a0e5-5f34-aaad-6b404ea92b59","text":"โ","kind":"vowel","romanization":"o","pronunciationHint":"long \"o\" as in \"go\"","mnemonic":"โ is the long-o vowel with a tall vertical stroke, written before the consonant. Like เ and ไ, read the consonant after it first.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"5b347f02-b891-5f29-ad35-11da91e7b87c","text":"ต","kind":"consonant","romanization":"t","pronunciationHint":"t as in \"stop\" (unaspirated)","mnemonic":"ต is ต เต่า (tor tao, turtle). Picture the rounded part as a turtle shell with a small head, then read it as the plain t/dt sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"13e7c7cd-283c-5d0b-a9cc-ce5b3831e495","text":"่","kind":"tone_mark","romanization":"mai ek","pronunciationHint":"first tone mark written above the consonant","mnemonic":"่ is mai ek, the first tone mark. It is one small stroke above the consonant, so read it as a compact tone cue.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]}],"rules":[{"id":"249bdd80-afed-5c53-a3ed-d73e1d8c7948","key":"four-tone-marks","name":"◌๊ and ◌๋ Complete the Four Tone Marks","shortDescription":"With ่ and ้, Thai now has all four tone marks","explanation":"You already knew mai ek (◌่) and mai tho (◌้). Mai tri (◌๊) and mai chattawa (◌๋) are the last two, completing the full set of four tone marks.","examples":[{"text":"โต๊ะ = dtó"},{"text":"ก๋วยเตี๋ยว = gǔuai-dtǐiao"}]},{"id":"fcf91072-bab2-5a53-a329-41a6f2327060","key":"mid-class-marks","name":"These Two Marks Ride Mid Consonants","shortDescription":"◌๊ gives high tone and ◌๋ gives rising, mostly on mid class","explanation":"Mai tri and mai chattawa appear almost only on mid-class consonants, in colloquial, loan, and food words. On a mid consonant, ◌๊ makes a high tone and ◌๋ makes a rising tone.","examples":[{"text":"โต๊ะ = dtó (high)"},{"text":"จ๋า = jǎa (rising)"}]}],"drills":[{"id":"b48605e9-ca18-5279-adda-ad5f41b1105e","key":"toh-drill-01-recognize","type":"recognize","prompt":"Which mark is mai tri?","payload":{},"options":[{"text":"๊","isCorrect":true},{"text":"๋"},{"text":"่"},{"text":"้"}]},{"id":"c1bf8eee-f50f-5c3c-a81f-db76d90e7e89","key":"toh-drill-02-sound","type":"sound","prompt":"On a mid consonant, what tone does ◌๊ give?","payload":{},"options":[{"text":"high","isCorrect":true},{"text":"rising"},{"text":"low"},{"text":"falling"}]},{"id":"e9e1219b-d9ce-5780-a81d-e53d27183e57","key":"toh-drill-03-sound","type":"sound","prompt":"On a mid consonant, what tone does ◌๋ give?","payload":{},"options":[{"text":"rising","isCorrect":true},{"text":"high"},{"text":"low"},{"text":"falling"}]},{"id":"4fa5207c-d85a-583e-a7a6-b4055a8024d4","key":"toh-drill-04-match","type":"match","prompt":"What does โต๊ะ mean?","payload":{},"options":[{"text":"table","isCorrect":true},{"text":"noodles"},{"text":"island"},{"text":"child"}]},{"id":"b15f1f51-aa5d-54cb-a8ef-19ae122bffeb","key":"toh-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"table\"?","payload":{},"options":[{"text":"โต๊ะ","isCorrect":true},{"text":"โต"},{"text":"ต๊ะ"},{"text":"โตะ"}]}]}}'::jsonb, '189d63b9cfe39c5dea3aade0fc534abed54b10a5e4a0df56b7e9311458e44cc1', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('9b282be1-3778-54e0-ab8e-c466f51bff79'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'd3afacf9-e786-5727-a205-494909843fa8'::uuid, 'khao-news', 35, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"d3afacf9-e786-5727-a205-494909843fa8","slug":"khao-news","lessonOrdinal":35,"stage":10,"title":"ข่าว — The Full Tone System","anchor":{"id":"935f50f5-c6cd-5254-a0f5-053701c910d9","slug":"khao-news","text":"ข่าว","meaning":"news","pronunciation":"khàao","categoryKey":"sign","contextNote":"ข่าว (news) anchors a review of the whole tone system. Here you pull class, tone mark, and syllable type together into one picture.","segments":[{"text":"ข่าว","sound":"khàao"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"c8d1b913-736c-5dcd-a387-f779532f980e","key":"word-0e01-0e32","text":"กา","meaning":"crow","pronunciation":"gaa","categoryKey":"daily","segments":[{"text":"กา","sound":"gaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"ecee6e47-ebbb-5dae-aad2-38cfec474745","key":"word-0e02-0e32","text":"ขา","meaning":"leg","pronunciation":"khǎa","categoryKey":"daily","segments":[{"text":"ขา","sound":"khǎa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"2c6d49a5-e43b-538f-a072-d2ab0152442c","key":"word-0e04-0e32","text":"คา","meaning":"to be stuck","pronunciation":"khaa","categoryKey":"daily","segments":[{"text":"คา","sound":"khaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"20e21427-0466-5d72-a64f-723522203d0e","key":"word-0e04-0e48-0e32","text":"ค่า","meaning":"value / fee","pronunciation":"khâa","categoryKey":"sign","segments":[{"text":"ค่า","sound":"khâa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":true,"item":{"id":"69debd14-b267-511a-af79-fd9d3feaaef0","key":"word-0e04-0e49-0e32","text":"ค้า","meaning":"to trade","pronunciation":"kháa","categoryKey":"sign","segments":[{"text":"ค้า","sound":"kháa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"6a66a60f-c509-56f7-a54b-bd44a4028c40","key":"word-0e21-0e49-0e32","text":"ม้า","meaning":"horse","pronunciation":"máa","categoryKey":"daily","segments":[{"text":"ม้า","sound":"máa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"8c79ebe5-9b38-5d70-a534-b40b909e194e","key":"word-0e2b-0e21-0e32","text":"หมา","meaning":"dog","pronunciation":"mǎa","categoryKey":"daily","segments":[{"text":"หมา","sound":"mǎa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"3298e2e3-5f8b-5593-a778-1eef71986d23","key":"word-0e1b-0e32","text":"ปา","meaning":"to throw","pronunciation":"bpaa","categoryKey":"daily","segments":[{"text":"ปา","sound":"bpaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"af4560d0-63f1-5bbb-aa0a-9de6cee5cf2f","key":"word-0e1b-0e48-0e32","text":"ป่า","meaning":"forest","pronunciation":"bpàa","categoryKey":"place","segments":[{"text":"ป่า","sound":"bpàa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"48eea63d-98e9-547b-a338-20588381a18b","key":"word-0e1b-0e49-0e32","text":"ป้า","meaning":"aunt","pronunciation":"bpâa","categoryKey":"daily","segments":[{"text":"ป้า","sound":"bpâa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":false,"item":{"id":"1e49cfe0-81c3-5067-a351-078d3fb51817","key":"word-0e2b-0e19-0e49-0e32","text":"หน้า","meaning":"face / front / page","pronunciation":"nâa","categoryKey":"daily","segments":[{"text":"หน้า","sound":"nâa"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-tone-mark","title":"Tone mark","body":"Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"c40165fd-c08b-5e06-a932-28747ec7490c","text":"ค","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the \"c\" in \"cat\"","mnemonic":"ค is ค ควาย (khaw khwaai, buffalo). Picture a broad water buffalo; ค gives the same breathy kh as ข but belongs to the low class.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"13e7c7cd-283c-5d0b-a9cc-ce5b3831e495","text":"่","kind":"tone_mark","romanization":"mai ek","pronunciationHint":"first tone mark written above the consonant","mnemonic":"่ is mai ek, the first tone mark. It is one small stroke above the consonant, so read it as a compact tone cue.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]}],"rules":[{"id":"3dbb28fe-48ef-5d5b-a2a8-f405e2df2dde","key":"tone-matrix","name":"Tone Comes From Class + Mark + Syllable","shortDescription":"Consonant class, any tone mark, and live/dead together fix the tone","explanation":"Every Thai tone is decided by three things working together: the initial consonant''s class (mid, high, low), any tone mark, and whether the syllable is live (open or ending in a sonorant) or dead (ending in a stop or short vowel). Read them in that order.","examples":[{"text":"ข่าว = khàao (high + mai ek)"},{"text":"ค่า = khâa (low + mai ek)"}]},{"id":"8cee28c9-ab21-59e1-a2fb-8175c9983306","key":"class-minimal-pairs","name":"One Vowel, Three Classes, Different Tones","shortDescription":"กา, ขา, and คา differ in tone only because of class","explanation":"With the same vowel, class alone changes the tone: กา (mid) is mid, ขา (high) rises, คา (low) is mid. Add a mark and they split further — ข่า is low, ค่า is falling. Class is always the starting point.","examples":[{"text":"กา = gaa · ขา = khǎa · คา = khaa"},{"text":"ข่า = khàa · ค่า = khâa"}]}],"drills":[{"id":"37043bf4-5f12-531e-a3d8-19338ce03fe1","key":"khao-news-drill-01-sound","type":"sound","prompt":"What three things decide a Thai tone?","payload":{},"options":[{"text":"class, tone mark, and live/dead syllable","isCorrect":true},{"text":"only the tone mark"},{"text":"only the vowel length"},{"text":"the final consonant alone"}]},{"id":"87c87d98-388a-5d17-a1d3-475bacd06148","key":"khao-news-drill-02-sound","type":"sound","prompt":"Why do กา, ขา, and คา have different tones?","payload":{},"options":[{"text":"their consonants are different classes","isCorrect":true},{"text":"different vowels"},{"text":"different finals"},{"text":"different marks"}]},{"id":"ff8391d8-646d-5c9d-a6af-7b165c3879b0","key":"khao-news-drill-03-sound","type":"sound","prompt":"A syllable ending in a stop or short vowel is called…","payload":{},"options":[{"text":"dead","isCorrect":true},{"text":"live"},{"text":"high"},{"text":"rising"}]},{"id":"1a167c9d-8f1a-5b66-adcb-e6e8aac9d951","key":"khao-news-drill-04-match","type":"match","prompt":"What does ข่าว mean?","payload":{},"options":[{"text":"news","isCorrect":true},{"text":"leg"},{"text":"rice"},{"text":"value"}]},{"id":"250dfdf6-0633-5968-aecf-4cf2a2ad8670","key":"khao-news-drill-05-spot","type":"spot","prompt":"Which pair are the low-class members?","payload":{},"options":[{"text":"คา / ค่า","isCorrect":true},{"text":"ขา / ข่า"},{"text":"กา / ก่า"},{"text":"ตา / ต่า"}]}]}}'::jsonb, '59667cf269cd537526ea1ff9b86079e756f95fc49b8dafd6523e0314cc25145c', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('109eba89-9b2a-5483-ab95-e3fad86176e1'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '909aae5d-bc64-578e-a15d-949af76df637'::uuid, 'dek', 36, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"909aae5d-bc64-578e-a15d-949af76df637","slug":"dek","lessonOrdinal":36,"stage":10,"title":"เด็ก — The Vowel Shortener","anchor":{"id":"b1f339e0-0487-5fa2-a739-0a2371f9675d","slug":"dek","text":"เด็ก","meaning":"child","pronunciation":"dèk","categoryKey":"daily","contextNote":"เด็ก (child) introduces ◌็ (mai taikhu), a mark that shortens the vowel in a closed syllable without adding any sound of its own.","segments":[{"text":"เด็ก","sound":"dèk"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"ad63428c-894d-5106-a6f2-9bd844c61568","key":"word-0e40-0e1b-0e47-0e19","text":"เป็น","meaning":"to be","pronunciation":"bpen","categoryKey":"daily","segments":[{"text":"เป็น","sound":"bpen"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"f97e5aaf-f4dd-5bfa-a099-6e8dc1904513","key":"word-0e40-0e25-0e48-0e19","text":"เล่น","meaning":"to play","pronunciation":"lên","categoryKey":"daily","segments":[{"text":"เล่น","sound":"lên"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"4509c2bb-49c2-5a43-a652-5dce6b3ffbd5","key":"word-0e40-0e2b-0e47-0e19","text":"เห็น","meaning":"to see","pronunciation":"hěn","categoryKey":"daily","segments":[{"text":"เห็น","sound":"hěn"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"75e2076e-a6eb-5537-a02f-69a3b3c9b110","key":"word-0e40-0e01-0e47-0e1a","text":"เก็บ","meaning":"to keep / collect","pronunciation":"gèp","categoryKey":"daily","segments":[{"text":"เก็บ","sound":"gèp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"b7b25281-6163-5181-ad64-081fe5ddfa48","key":"word-0e40-0e22-0e47-0e19","text":"เย็น","meaning":"cool / evening","pronunciation":"yen","categoryKey":"daily","segments":[{"text":"เย็น","sound":"yen"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"ce982005-4f20-54c8-a65c-4484747410ce","key":"word-0e40-0e1c-0e47-0e14","text":"เผ็ด","meaning":"spicy","pronunciation":"phèt","categoryKey":"food","segments":[{"text":"เผ็ด","sound":"phèt"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"3f33942a-c17e-5a53-ac47-0d4add690610","key":"word-0e40-0e04-0e47-0e21","text":"เค็ม","meaning":"salty","pronunciation":"khem","categoryKey":"food","segments":[{"text":"เค็ม","sound":"khem"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"731af6ec-8e78-5f81-ac2a-09b8a336ca1a","key":"word-0e40-0e25-0e47-0e01","text":"เล็ก","meaning":"small","pronunciation":"lék","categoryKey":"daily","segments":[{"text":"เล็ก","sound":"lék"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"eb82243d-5ae5-56e1-af7d-fe36ef20101d","key":"word-0e40-0e15-0e47-0e21","text":"เต็ม","meaning":"full","pronunciation":"dtem","categoryKey":"daily","segments":[{"text":"เต็ม","sound":"dtem"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"29897452-6ecb-532d-a23c-ff62dcd4f318","key":"word-0e41-0e02-0e47-0e07","text":"แข็ง","meaning":"hard / strong","pronunciation":"khǎeng","categoryKey":"daily","segments":[{"text":"แข็ง","sound":"khǎeng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":11,"isDrillTarget":false,"item":{"id":"9204f773-1f94-5cae-a7c1-783052f24558","key":"word-0e40-0e01-0e47-0e1a-0e40-0e07-0e34-0e19","text":"เก็บเงิน","meaning":"to save money","pronunciation":"gèp ngern","categoryKey":"daily","segments":[{"text":"เก็บ","sound":"gèp"},{"text":"เงิน","sound":"ngern"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-mark","title":"Written mark","body":"This is a written symbol that isn''t a consonant, vowel, or tone mark. Thai uses a few of these — for example ๆ repeats the preceding word, and ์ silences the consonant it sits above. Each one changes how you read the syllable rather than adding a sound of its own."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"3938b960-b537-5dfd-a32e-04b2f7e4bf10","text":"็","kind":"mark","romanization":"(shortener)","pronunciationHint":"mai taikhu — it shortens the vowel and carries no sound of its own","mnemonic":"◌็ mai taikhu is a tiny hook that clips the vowel short, mostly on เ and แ before a final, as in เด็ก (dèk).","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-mark","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"d930649b-b987-5148-a7d1-8aaabef44060","text":"เ","kind":"vowel","romanization":"e","pronunciationHint":"long \"e\" as in \"they\"","mnemonic":"เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"1468f8a2-d91f-5127-ac8d-e40de6f54950","text":"ป","kind":"consonant","romanization":"bp","pronunciationHint":"a tight, unaspirated p, like the p in \"spin\" (between English b and p)","mnemonic":"ป is ป ปลา (bpor bplaa, fish). Picture a tall fish standing on its tail; ป is the unaspirated p that pairs with the dt sound of ต.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"755b5142-390b-5eff-abb9-1d737b7fc5a2","key":"taikhu-shorten","name":"◌็ Shortens the Vowel","shortDescription":"◌็ clips เ or แ short before a final consonant","explanation":"The mai taikhu mark shortens the vowel of a closed syllable, mainly with เ and แ. It adds no sound itself — it only makes the vowel quick, as in เด็ก (dèk) and เล็ก (lék).","examples":[{"text":"เด็ก = dèk"},{"text":"เล็ก = lék"}]},{"id":"ad2f90e9-b018-5e6d-aab5-2e5a6cf00271","key":"taikhu-limits","name":"◌็ Doesn''t Stack With Tone Marks","shortDescription":"◌็ cannot share the spot with a tone mark or above-vowel","explanation":"In standard Thai, ◌็ occupies the space above the consonant on its own, so it does not co-occur with a tone mark or an above-line vowel in the same syllable.","examples":[{"text":"เป็น = bpen"},{"text":"เห็น = hěn"}]}],"drills":[{"id":"53866311-cff2-5696-ae54-8a78a4974a70","key":"dek-drill-01-recognize","type":"recognize","prompt":"Which mark shortens the vowel?","payload":{},"options":[{"text":"็","isCorrect":true},{"text":"่"},{"text":"้"},{"text":"๊"}]},{"id":"8fbdc96c-affd-5826-a9ff-9ab4ace89de3","key":"dek-drill-02-sound","type":"sound","prompt":"What does ◌็ add to the sound?","payload":{},"options":[{"text":"nothing — it only shortens","isCorrect":true},{"text":"a high tone"},{"text":"an m"},{"text":"an extra vowel"}]},{"id":"f6a02c3f-b091-5454-afc0-97c1d9e57e60","key":"dek-drill-03-sound","type":"sound","prompt":"◌็ appears mostly with which vowels?","payload":{},"options":[{"text":"เ and แ","isCorrect":true},{"text":"า and ี"},{"text":"ุ and ู"},{"text":"◌ำ"}]},{"id":"61075d24-0f76-5c1a-a5f1-67e34804a1d1","key":"dek-drill-04-match","type":"match","prompt":"What does เด็ก mean?","payload":{},"options":[{"text":"child","isCorrect":true},{"text":"table"},{"text":"small"},{"text":"to see"}]},{"id":"3445f8f0-b785-5af4-ab0f-a9a2e7889433","key":"dek-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"child\"?","payload":{},"options":[{"text":"เด็ก","isCorrect":true},{"text":"เดก"},{"text":"เล็ก"},{"text":"ด็ก"}]}]}}'::jsonb, 'ed862312669a1c1f412b84b340417ba6dd2b2f6e44c0d91bc687d06f43b8ed35', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('eab1eedd-a4af-54db-a89f-ff03f02b2442'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '3dcf575d-7f9c-50e6-a9f0-da47780674d2'::uuid, 'chaa', 37, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"3dcf575d-7f9c-50e6-a9f0-da47780674d2","slug":"chaa","lessonOrdinal":37,"stage":10,"title":"ช้าๆ — The Repetition Mark","anchor":{"id":"fb5f792e-7a1a-58a8-a854-e7272e00726e","slug":"chaa","text":"ช้าๆ","meaning":"slowly / take it easy","pronunciation":"cháa-cháa","categoryKey":"daily","contextNote":"ช้าๆ (slowly) shows ◌ๆ (mai yamok), the mark that tells you to say the previous word again — for plurals, emphasis, or ''each and every''.","segments":[{"text":"ช้า","sound":"cháa"},{"text":"ๆ","sound":"cháa"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"3f4b2ae0-8292-5775-af01-99c5c60248c0","key":"word-0e40-0e14-0e47-0e01-0e46","text":"เด็กๆ","meaning":"children","pronunciation":"dèk-dèk","categoryKey":"daily","segments":[{"text":"เด็ก","sound":"dèk"},{"text":"ๆ","sound":"dèk"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"1789c73e-fa1b-5244-a140-accf112fd7c2","key":"word-0e40-0e23-0e47-0e27-0e46","text":"เร็วๆ","meaning":"quickly / hurry","pronunciation":"rew-rew","categoryKey":"daily","segments":[{"text":"เร็ว","sound":"rew"},{"text":"ๆ","sound":"rew"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"4793d4b7-8809-5ea1-ada7-22ec2c67033d","key":"word-0e07-0e48-0e32-0e22-0e46","text":"ง่ายๆ","meaning":"very easy / simple","pronunciation":"ngâai-ngâai","categoryKey":"daily","segments":[{"text":"ง่าย","sound":"ngâai"},{"text":"ๆ","sound":"ngâai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":false,"item":{"id":"e4be618d-103b-5d3a-a28d-17adcec4961f","key":"word-0e21-0e32-0e01-0e46","text":"มากๆ","meaning":"very much","pronunciation":"mâak-mâak","categoryKey":"daily","segments":[{"text":"มาก","sound":"mâak"},{"text":"ๆ","sound":"mâak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"979cba8f-73f6-55ed-a012-68e36456b83a","key":"word-0e14-0e35-0e46","text":"ดีๆ","meaning":"nicely / good ones","pronunciation":"dii-dii","categoryKey":"daily","segments":[{"text":"ดี","sound":"dii"},{"text":"ๆ","sound":"dii"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"c63bc19b-a879-51b0-a0ff-2e4fe71b29a1","key":"word-0e40-0e1a-0e32-0e46","text":"เบาๆ","meaning":"gently / softly","pronunciation":"bao-bao","categoryKey":"daily","segments":[{"text":"เบา","sound":"bao"},{"text":"ๆ","sound":"bao"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"78e475ad-ef09-5930-abbf-3a4e2cd9775c","key":"word-0e23-0e49-0e2d-0e19-0e46","text":"ร้อนๆ","meaning":"piping hot","pronunciation":"ráwn-ráwn","categoryKey":"food","segments":[{"text":"ร้อน","sound":"ráwn"},{"text":"ๆ","sound":"ráwn"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"b2ffe405-444d-575a-a88f-1d6c53ec6e50","key":"word-0e43-0e2b-0e21-0e48-0e46","text":"ใหม่ๆ","meaning":"brand new / recently","pronunciation":"mài-mài","categoryKey":"daily","segments":[{"text":"ใหม่","sound":"mài"},{"text":"ๆ","sound":"mài"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"c747fd20-6c42-5e31-a2a1-b5fb01d6b7d8","key":"word-0e40-0e25-0e47-0e01-0e46","text":"เล็กๆ","meaning":"tiny","pronunciation":"lék-lék","categoryKey":"daily","segments":[{"text":"เล็ก","sound":"lék"},{"text":"ๆ","sound":"lék"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"ae6fe58a-a1d3-5976-ab34-3ca3d7b96aa1","key":"word-0e1e-0e39-0e14-0e0a-0e49-0e32-0e46","text":"พูดช้าๆ","meaning":"speak slowly","pronunciation":"phûut cháa-cháa","categoryKey":"daily","segments":[{"text":"พูด","sound":"phûut"},{"text":"ช้า","sound":"cháa"},{"text":"ๆ","sound":"cháa"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-mark","title":"Written mark","body":"This is a written symbol that isn''t a consonant, vowel, or tone mark. Thai uses a few of these — for example ๆ repeats the preceding word, and ์ silences the consonant it sits above. Each one changes how you read the syllable rather than adding a sound of its own."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-tone-mark","title":"Tone mark","body":"Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."}],"newGraphemes":[{"id":"2a6e28e3-6f00-5ff3-ac11-656202db2c03","text":"ๆ","kind":"mark","romanization":"(repeat)","pronunciationHint":"mai yamok — read the word before it a second time","mnemonic":"◌ๆ maiyamok is written after a word with a space; it means ''say that again'', so ช้าๆ is read cháa-cháa.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-mark","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"9593d6a6-13bb-563d-a33d-b01dd74e3528","text":"ช","kind":"consonant","romanization":"ch","pronunciationHint":"ch as in \"check\"","mnemonic":"ช is ช ช้าง (chor chaang, elephant). Picture the long dropping stroke as an elephant trunk, and use ช้าง for the ch sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"56d6049c-5c20-5436-a5d0-37ea5d73fe05","text":"้","kind":"tone_mark","romanization":"mai tho","pronunciationHint":"second tone mark written above the consonant","mnemonic":"้ is mai tho, the second tone mark. It looks heavier than mai ek, a good cue that this is the second above-letter tone mark.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"d930649b-b987-5148-a7d1-8aaabef44060","text":"เ","kind":"vowel","romanization":"e","pronunciationHint":"long \"e\" as in \"they\"","mnemonic":"เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"04f42251-cb83-5c34-a52c-5d7e44315ae6","key":"yamok-repeat","name":"◌ๆ Repeats the Previous Word","shortDescription":"Read the word before ◌ๆ twice","explanation":"The mai yamok mark doubles the word in front of it. Depending on the word, the repeat can mark a plural, add emphasis, or mean ''each/every''. Read the whole word again.","examples":[{"text":"ช้าๆ = cháa-cháa"},{"text":"เด็กๆ = dèk-dèk"}]}],"drills":[{"id":"ed28fbcc-db8e-59fc-ac4d-38d1547305e2","key":"chaa-drill-01-recognize","type":"recognize","prompt":"Which mark means ''repeat the previous word''?","payload":{},"options":[{"text":"ๆ","isCorrect":true},{"text":"ฯ"},{"text":"์"},{"text":"็"}]},{"id":"cd6f936c-49ec-565a-a545-0057ab175491","key":"chaa-drill-02-sound","type":"sound","prompt":"How do you read ช้าๆ?","payload":{},"options":[{"text":"cháa-cháa","isCorrect":true},{"text":"cháa"},{"text":"cháa-yaa"},{"text":"cháang"}]},{"id":"20f37385-2bf3-5e88-a4d3-886e839418e1","key":"chaa-drill-03-sound","type":"sound","prompt":"What can ◌ๆ signal?","payload":{},"options":[{"text":"plural, emphasis, or ''each/every''","isCorrect":true},{"text":"a silent letter"},{"text":"a high tone"},{"text":"a question"}]},{"id":"a5c95b59-ab70-5854-aa24-dc89bdc20e30","key":"chaa-drill-04-match","type":"match","prompt":"What does ช้าๆ mean?","payload":{},"options":[{"text":"slowly / take it easy","isCorrect":true},{"text":"very fast"},{"text":"children"},{"text":"loudly"}]},{"id":"89ee9dcc-4527-55d4-a25d-254180627115","key":"chaa-drill-05-spot","type":"spot","prompt":"Which spelling means \"children\" (doubled)?","payload":{},"options":[{"text":"เด็กๆ","isCorrect":true},{"text":"เด็ก"},{"text":"ช้าๆ"},{"text":"ดๆ"}]}]}}'::jsonb, 'aa734f0f86d1712f511b5f171ab5c840eac443250a48ef8e252f7707253c70af', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('1b773a4b-f2e8-5c13-abf4-aa410ce9fbb5'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '975e9228-70a0-58a4-afbb-d00e81532969'::uuid, 'koh', 38, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"975e9228-70a0-58a4-afbb-d00e81532969","slug":"koh","lessonOrdinal":38,"stage":10,"title":"เกาะ — Short Diphthongs and Unwritten o","anchor":{"id":"b3d306cd-ca0f-5db3-acdd-415d8221003c","slug":"koh","text":"เกาะ","meaning":"island","pronunciation":"gàw","categoryKey":"place","contextNote":"เกาะ (island) shows the short partner of the leading vowels. This lesson gathers the short diphthongs and the unwritten short o that hides between two consonants.","segments":[{"text":"เกาะ","sound":"gàw"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"ab6b1225-a683-51e4-adf2-8cde3ccf3e07","key":"word-0e40-0e15-0e30","text":"เตะ","meaning":"to kick","pronunciation":"dtè","categoryKey":"daily","segments":[{"text":"เตะ","sound":"dtè"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"9fc3df81-a88d-5e2d-a311-db03d1bdebb9","key":"word-0e41-0e01-0e30","text":"แกะ","meaning":"sheep / to unwrap","pronunciation":"gàe","categoryKey":"daily","segments":[{"text":"แกะ","sound":"gàe"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"9531098c-7c7d-59e1-aa6e-f2b7b41671ac","key":"word-0e41-0e25-0e30","text":"และ","meaning":"and","pronunciation":"láe","categoryKey":"daily","segments":[{"text":"และ","sound":"láe"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"ff264616-ccc4-51c5-a600-f0b0bb0cd47e","key":"word-0e04-0e19","text":"คน","meaning":"person","pronunciation":"khon","categoryKey":"daily","segments":[{"text":"คน","sound":"khon"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"f368793f-0a56-5509-a9fa-a86d5d987f85","key":"word-0e19-0e01","text":"นก","meaning":"bird","pronunciation":"nók","categoryKey":"daily","segments":[{"text":"นก","sound":"nók"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"7a9c1e82-b3b5-5374-a65a-0fc757026cb8","key":"word-0e23-0e16","text":"รถ","meaning":"car / vehicle","pronunciation":"rót","categoryKey":"transport","segments":[{"text":"รถ","sound":"rót"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"0afa03f2-642d-5a71-aab6-f551d7e99fc1","key":"word-0e08-0e1a","text":"จบ","meaning":"to finish","pronunciation":"jòp","categoryKey":"daily","segments":[{"text":"จบ","sound":"jòp"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"269d9fea-2221-5032-a4c2-cfd2be2f7499","key":"word-0e1d-0e19","text":"ฝน","meaning":"rain","pronunciation":"fǒn","categoryKey":"daily","segments":[{"text":"ฝน","sound":"fǒn"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"80d07517-ec44-52c4-a8c0-32a13e8b620f","key":"word-0e2a-0e14","text":"สด","meaning":"fresh","pronunciation":"sòt","categoryKey":"food","segments":[{"text":"สด","sound":"sòt"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"dad63552-fe4a-55e4-a8e1-9e0804d5a448","key":"word-0e1c-0e21","text":"ผม","meaning":"I (male) / hair","pronunciation":"phǒm","categoryKey":"daily","segments":[{"text":"ผม","sound":"phǒm"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"be7afb92-f599-5cbe-a66c-a6ac5a86d389","text":"เ◌าะ","kind":"vowel","romanization":"aw","pronunciationHint":"short \"aw\", a clipped version of เ-า","mnemonic":"เ◌าะ ends in ◌ะ, the short marker. It is the quick, clipped cousin of the long aw, as in เกาะ (gàw).","position":"around","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"e8d95abf-de87-5098-ad39-281eb1b15dee","text":"เ◌ะ","kind":"vowel","romanization":"e","pronunciationHint":"short \"e\", a clipped version of เ","mnemonic":"เ◌ะ is the short e: the ◌ะ on the right clips the long เ short, as in เตะ (dtè).","position":"around","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"995166e9-7e6d-5c17-acae-4e9afefd86d4","text":"แ◌ะ","kind":"vowel","romanization":"ae","pronunciationHint":"short \"ae\", a clipped version of แ","mnemonic":"แ◌ะ is the short ae: ◌ะ shortens the long แ, as in แกะ (gàe).","position":"around","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"313f81af-f95a-53f2-aa21-c5faa9818f3e","text":"โ◌ะ","kind":"vowel","romanization":"o","pronunciationHint":"short \"o\", a clipped version of โ","mnemonic":"โ◌ะ is the short o: ◌ะ shortens the long โ, as in โต๊ะ (dtó).","position":"around","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"d930649b-b987-5148-a7d1-8aaabef44060","text":"เ","kind":"vowel","romanization":"e","pronunciationHint":"long \"e\" as in \"they\"","mnemonic":"เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"1684cb46-8524-51a4-ad84-8dd2fe3b46be","text":"แ","kind":"vowel","romanization":"ae","pronunciationHint":"long \"ae\" as in the vowel of \"care\"","mnemonic":"แ is a double left-side vowel. The two front posts tell your eye to look left first, then come back to the consonant for ae.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"6450d4bf-a0e5-5f34-aaad-6b404ea92b59","text":"โ","kind":"vowel","romanization":"o","pronunciationHint":"long \"o\" as in \"go\"","mnemonic":"โ is the long-o vowel with a tall vertical stroke, written before the consonant. Like เ and ไ, read the consonant after it first.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"f4bda34e-a00e-53ac-a756-196e4fd86dcb","text":"ะ","kind":"vowel","romanization":"a","pronunciationHint":"short \"a\" cut off by a quick glottal stop, like a clipped \"ah!\"","mnemonic":"ะ is the two-dot short-a written to the right of the consonant. It ends the syllable abruptly, like catching your breath after ''ah''.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"69247cdc-546e-545d-a530-14c95a2c593a","key":"short-diphthongs","name":"◌ะ Marks the Short Vowels","shortDescription":"เ-าะ, เ-ะ, แ-ะ, and โ-ะ are the short partners of the leading vowels","explanation":"Adding ◌ะ to a leading vowel makes its short version: เ-าะ (short aw), เ-ะ (short e), แ-ะ (short ae), and โ-ะ (short o). They sound clipped and are usually dead syllables.","examples":[{"text":"เกาะ = gàw"},{"text":"แกะ = gàe"}]},{"id":"00c99842-a07c-5fe8-a0f2-bfda9a3f47d1","key":"unwritten-short-o","name":"Two Consonants Alone = Short o","shortDescription":"A consonant-consonant syllable with no written vowel is a short o","explanation":"When a syllable is two consonants with no written vowel, a short ''o'' hides between them, as in คน (khon) and นก (nók). Nothing on the page marks it — you supply the o.","examples":[{"text":"คน = khon"},{"text":"นก = nók"}]}],"drills":[{"id":"f756a365-588d-5866-a695-0710c399b075","key":"koh-drill-01-recognize","type":"recognize","prompt":"Which frame is the short \"aw\"?","payload":{},"options":[{"text":"เ◌าะ","isCorrect":true},{"text":"เ◌า"},{"text":"◌ัว"},{"text":"เ◌อ"}]},{"id":"aeae279d-5565-5604-a469-e9814765d43c","key":"koh-drill-02-sound","type":"sound","prompt":"What does ◌ะ do to a leading vowel?","payload":{},"options":[{"text":"makes it short","isCorrect":true},{"text":"makes it long"},{"text":"silences it"},{"text":"raises the tone"}]},{"id":"b2ef74b9-8e21-51ff-a556-092dabba4d41","key":"koh-drill-03-sound","type":"sound","prompt":"How do you read คน (two consonants, no vowel)?","payload":{},"options":[{"text":"khon — an unwritten short o","isCorrect":true},{"text":"khaan"},{"text":"khun"},{"text":"khn with no vowel"}]},{"id":"a06b1ba1-456a-5369-ad41-fe0839328b72","key":"koh-drill-04-match","type":"match","prompt":"What does เกาะ mean?","payload":{},"options":[{"text":"island","isCorrect":true},{"text":"table"},{"text":"sheep"},{"text":"to kick"}]},{"id":"a44b52e3-13ec-5eaf-a5af-a686b626545e","key":"koh-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"island\"?","payload":{},"options":[{"text":"เกาะ","isCorrect":true},{"text":"เกา"},{"text":"เตะ"},{"text":"แกะ"}]}]}}'::jsonb, 'af4b5457d8667728ac51aae727c9c39bac18fa6c08d9571d3bec27ed9ad75ab6', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('678e6d80-062a-51a5-a893-bbddd29deb6f'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '83b7993a-6759-55b2-a99f-d03490796283'::uuid, 'numerals', 39, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"83b7993a-6759-55b2-a99f-d03490796283","slug":"numerals","lessonOrdinal":39,"stage":11,"title":"๑๐ บาท — Thai Numerals","anchor":{"id":"0766d9bf-b229-576f-ae9c-1b34d67f8580","slug":"numerals","text":"๑๐ บาท","meaning":"10 baht","pronunciation":"sìp bàat","categoryKey":"sign","contextNote":"Thai numerals still appear on temple and park entry signs, dual pricing, license plates, and banknotes. ๑๐ บาท (10 baht) is a typical price you will read.","segments":[{"text":"๑๐","sound":"sìp"},{"text":"บาท","sound":"bàat"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"dba2ac46-22a2-5e0a-a5c7-2d2960becb7c","key":"word-0e58-0020-0e1a-0e32-0e17","text":"๘ บาท","meaning":"8 baht","pronunciation":"bpàet bàat","categoryKey":"sign","segments":[{"text":"๘","sound":"bpàet"},{"text":"บาท","sound":"bàat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"e5ceb385-e109-5f85-aa75-3c1e0f54064b","key":"word-0e52-0e50-0020-0e1a-0e32-0e17","text":"๒๐ บาท","meaning":"20 baht","pronunciation":"yîi-sìp bàat","categoryKey":"sign","segments":[{"text":"๒๐","sound":"yîi-sìp"},{"text":"บาท","sound":"bàat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"350ba462-54cf-51cf-a83d-8800a79bb821","key":"word-0e55-0020-0e1a-0e32-0e17","text":"๕ บาท","meaning":"5 baht","pronunciation":"hâa bàat","categoryKey":"sign","segments":[{"text":"๕","sound":"hâa"},{"text":"บาท","sound":"bàat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"746472a0-ff55-572a-a402-fd5f36dde707","key":"word-0e51-0e50-0e50","text":"๑๐๐","meaning":"100 (one hundred)","pronunciation":"nùeng ráwy","categoryKey":"sign","segments":[{"text":"๑๐๐","sound":"nùeng ráwy"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"35146ecb-2a79-57b0-aedd-7232412f6d95","key":"word-0e59","text":"๙","meaning":"nine","pronunciation":"gâo","categoryKey":"sign","segments":[{"text":"๙","sound":"gâo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"b7460927-86f3-5b53-abc0-65a1ad38609c","key":"word-0e55-0e50-0e50","text":"๕๐๐","meaning":"500","pronunciation":"hâa-ráwy","categoryKey":"sign","segments":[{"text":"๕๐๐","sound":"hâa-ráwy"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"7b2eda16-aee1-52d6-a0b8-423817462e67","key":"word-0e51-002c-0e50-0e50-0e50","text":"๑,๐๐๐","meaning":"1,000 (one thousand)","pronunciation":"nùeng phan","categoryKey":"sign","segments":[{"text":"๑,๐๐๐","sound":"nùeng phan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"ee9372f2-33fe-51a4-aa39-5eea601b193a","key":"word-0e51-0e52-0020-0e1a-0e32-0e17","text":"๑๒ บาท","meaning":"12 baht","pronunciation":"sìp-sǎwng bàat","categoryKey":"sign","segments":[{"text":"๑๒","sound":"sìp-sǎwng"},{"text":"บาท","sound":"bàat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"8b9d4af0-33be-53ad-adea-3060385200c6","key":"word-0e23-0e32-0e04-0e32-0020-0e54-0e50-0020-0e1a-0e32-0e17","text":"ราคา ๔๐ บาท","meaning":"price 40 baht","pronunciation":"raa-khaa sìi-sìp bàat","categoryKey":"sign","segments":[{"text":"ราคา","sound":"raa-khaa"},{"text":"๔๐","sound":"sìi-sìp"},{"text":"บาท","sound":"bàat"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-numeral","title":"Thai numeral","body":"Thai has its own set of digits (๐–๙) that work exactly like 0–9. You''ll still see Arabic numerals everywhere in Thailand, but Thai numerals appear on signs, prices, documents, and license plates, so it''s worth being able to read both."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"fcb5dbae-7c0a-5974-a3c1-2523534b0b79","text":"๐","kind":"numeral","romanization":"0","pronunciationHint":"sǔun (zero)","mnemonic":"๐ is a small oval, like a 0. It is sǔun, zero.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-numeral"},"tags":[]},{"id":"1379e866-aa33-5f4f-aa27-4714cefee8d7","text":"๑","kind":"numeral","romanization":"1","pronunciationHint":"nùeng (one)","mnemonic":"๑ has a single curl on top — one loop for the number one (nùeng).","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-numeral"},"tags":[]},{"id":"dd70b46e-2d38-588d-a87c-9b0249a80bd8","text":"๒","kind":"numeral","romanization":"2","pronunciationHint":"sǎwng (two)","mnemonic":"๒ opens to the right with one belly. Watch it against ๓ — say sǎwng for two.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-numeral"},"tags":[]},{"id":"1ee8a853-0b37-5712-aa79-1012c3b808a2","text":"๓","kind":"numeral","romanization":"3","pronunciationHint":"sǎam (three)","mnemonic":"๓ has two humps, like a rounded 3. It is sǎam, three.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-numeral"},"tags":[]},{"id":"f3205fff-c7a5-54a8-a097-789e336d24f2","text":"๔","kind":"numeral","romanization":"4","pronunciationHint":"sìi (four)","mnemonic":"๔ curls twice and tucks under. It is sìi, four.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-numeral"},"tags":[]},{"id":"df876fba-b992-5e1d-a3be-0e25119a3eef","text":"๕","kind":"numeral","romanization":"5","pronunciationHint":"hâa (five)","mnemonic":"๕ looks like a little cursive g. It is hâa, five.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-numeral"},"tags":[]},{"id":"480ec029-9e5a-50d0-ac86-3a5d79407ea5","text":"๖","kind":"numeral","romanization":"6","pronunciationHint":"hòk (six)","mnemonic":"๖ has a big loop swinging up. It is hòk, six.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-numeral"},"tags":[]},{"id":"97dbbd1f-f52d-5609-a416-9231ab63e6c6","text":"๗","kind":"numeral","romanization":"7","pronunciationHint":"jèt (seven)","mnemonic":"๗ has a tail that trails to the right. It is jèt, seven.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-numeral"},"tags":[]},{"id":"53d08831-65bc-500b-acae-0dfafce8ebe8","text":"๘","kind":"numeral","romanization":"8","pronunciationHint":"bpàet (eight)","mnemonic":"๘ is an open curl, like a broken 8. It is bpàet, eight.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-numeral"},"tags":[]},{"id":"2f93e8dd-da16-573c-a6dc-c2e6baea7c09","text":"๙","kind":"numeral","romanization":"9","pronunciationHint":"gâo (nine)","mnemonic":"๙ loops around like a 9. It is gâo, nine — an auspicious number in Thailand.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-numeral"},"tags":[]}],"reviewGraphemes":[{"id":"dddb2e02-9aa3-5dde-a2ab-25524fc96559","text":"บ","kind":"consonant","romanization":"b/p","pronunciationHint":"b as in \"bat\" at the start; clipped p at the end","mnemonic":"บ is บ ใบไม้ (bor bai mai, leaf). The open bowl shape can hold a leaf, and ใบไม้ gives you the b sound at the start.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"cf8eaddc-cd8e-55ca-a652-237794f23e8b","text":"ท","kind":"consonant","romanization":"th","pronunciationHint":"th with a puff of air, like the \"t\" in \"top\" (not the th in \"the\")","mnemonic":"ท is ท ทหาร (thor thahaan, soldier). Picture a soldier standing tall; ท gives the aspirated th sound with a clear puff of air.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"891cca5d-fb57-5299-a690-bc0c940c626d","key":"thai-numerals","name":"Thai Has Its Own Digits ๐–๙","shortDescription":"๐๑๒๓๔๕๖๗๘๙ map directly to 0–9","explanation":"Thai numerals work exactly like the Arabic 0–9 you know and combine the same way, so ๑๐ is 10 and ๒๕ is 25. You read them most on official signs, banknotes, and dual pricing.","examples":[{"text":"๑๐ = 10"},{"text":"๒๕ = 25"}]},{"id":"0d899d11-26df-5fd1-ad97-eba3292507cc","key":"confusable-2-3","name":"Watch ๒ and ๓","shortDescription":"๒ (2) and ๓ (3) look alike — check the number of humps","explanation":"๒ and ๓ are the easiest Thai numerals to confuse. ๒ has a single belly, while ๓ has two humps. Slow down and count the curves before you read the price.","examples":[{"text":"๒ = 2"},{"text":"๓ = 3"}]}],"drills":[{"id":"1d2dc0b0-2021-52bb-ae04-e919488281de","key":"numerals-drill-01-recognize","type":"recognize","prompt":"Which numeral is 5?","payload":{},"options":[{"text":"๕","isCorrect":true},{"text":"๖"},{"text":"๓"},{"text":"๙"}]},{"id":"8e3b7325-55f6-558d-aa65-5687fdadb904","key":"numerals-drill-02-sound","type":"sound","prompt":"What is ๑๐?","payload":{},"options":[{"text":"10","isCorrect":true},{"text":"1"},{"text":"100"},{"text":"20"}]},{"id":"c07beb70-fc32-59f9-a431-2bb9bc95b589","key":"numerals-drill-03-recognize","type":"recognize","prompt":"Which numeral is 2?","payload":{},"options":[{"text":"๒","isCorrect":true},{"text":"๓"},{"text":"๗"},{"text":"๔"}]},{"id":"9ced029e-e293-53af-a6f2-63677a2b46b7","key":"numerals-drill-04-match","type":"match","prompt":"What does ๑๐ บาท mean?","payload":{},"options":[{"text":"10 baht","isCorrect":true},{"text":"1 baht"},{"text":"100 baht"},{"text":"10 satang"}]},{"id":"9d5f5df6-d1b6-5c9d-a1c8-5dafc3caf086","key":"numerals-drill-05-spot","type":"spot","prompt":"Which is the numeral for 9?","payload":{},"options":[{"text":"๙","isCorrect":true},{"text":"๖"},{"text":"๕"},{"text":"๘"}]}]}}'::jsonb, '7295a409bb516094115e43d4de10f48f1c4e63068888ed7bfaf2532c191e333e', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('92e0fd53-148e-55a7-abb1-7c074eee59f6'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '4e0ae282-3b97-593c-afae-1564cfe169e8'::uuid, 'krungthep', 40, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"4e0ae282-3b97-593c-afae-1564cfe169e8","slug":"krungthep","lessonOrdinal":40,"stage":11,"title":"กรุงเทพฯ — The Abbreviation Mark","anchor":{"id":"59f46d6b-4b42-5198-a4df-d94c4832cee3","slug":"krungthep","text":"กรุงเทพฯ","meaning":"Bangkok","pronunciation":"grung-thêep","categoryKey":"place","contextNote":"กรุงเทพฯ (Bangkok) ends in ฯ (paiyannoi), which stands in for the rest of the city''s ceremonial name. You read the short everyday form aloud.","segments":[{"text":"กรุง","sound":"grung"},{"text":"เทพ","sound":"thêep"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"58cd4464-541f-5c13-afb8-2999f47d4fa3","key":"word-0e2f-0e25-0e2f","text":"ฯลฯ","meaning":"etc. / and so on","pronunciation":"láe-ùen-ùen","categoryKey":"sign","segments":[{"text":"ฯลฯ","sound":"láe-ùen-ùen"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"fbec17b5-676b-59ef-a8d0-9272645698b3","key":"word-0e19-0e32-0e22-0e01-0e2f","text":"นายกฯ","meaning":"PM (Prime Minister)","pronunciation":"naa-yók","categoryKey":"sign","segments":[{"text":"นายกฯ","sound":"naa-yók"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":false,"item":{"id":"1681c4ea-7623-5891-a2a3-1e4c6e4ceb40","key":"word-0e01-0e23-0e38-0e07-0e40-0e17-06e36f82e5241e23","text":"กรุงเทพมหานคร","meaning":"Bangkok (full name)","pronunciation":"grung-thêep-má-hǎa-ná-khawn","categoryKey":"place","segments":[{"text":"กรุงเทพ","sound":"grung-thêep"},{"text":"มหา","sound":"má-hǎa"},{"text":"นคร","sound":"ná-khawn"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"96067fb2-1baa-55b8-a349-87ca9c3c72c1","key":"word-0e43-0e19-0e01-0e23-0e38-0e07-0e40-0e17-0e1e-0e2f","text":"ในกรุงเทพฯ","meaning":"in Bangkok","pronunciation":"nai grung-thêep","categoryKey":"place","segments":[{"text":"ใน","sound":"nai"},{"text":"กรุงเทพฯ","sound":"grung-thêep"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"6114dbf5-4bfe-50fb-a24c-5902574ffc47","key":"word-0e44-0e1b-0e01-0e23-0e38-0e07-0e40-0e17-0e1e-0e2f","text":"ไปกรุงเทพฯ","meaning":"to go to Bangkok","pronunciation":"bpai grung-thêep","categoryKey":"place","segments":[{"text":"ไป","sound":"bpai"},{"text":"กรุงเทพฯ","sound":"grung-thêep"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"e5ed6fd3-cd50-5c59-a3d7-50d6fb6c0374","key":"word-0e19-0e32-0e22-0e01-0e2f-0020-0e1e-0e39-0e14","text":"นายกฯ พูด","meaning":"the PM speaks","pronunciation":"naa-yók phûut","categoryKey":"sign","segments":[{"text":"นายกฯ","sound":"naa-yók"},{"text":"พูด","sound":"phûut"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-mark","title":"Written mark","body":"This is a written symbol that isn''t a consonant, vowel, or tone mark. Thai uses a few of these — for example ๆ repeats the preceding word, and ์ silences the consonant it sits above. Each one changes how you read the syllable rather than adding a sound of its own."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]}],"newGraphemes":[{"id":"54d7d08f-8ae4-5005-a2a7-d0a23aa4b3a2","text":"ฯ","kind":"mark","romanization":"(abbrev.)","pronunciationHint":"paiyannoi — it marks a shortened well-known name","mnemonic":"ฯ paiyannoi is an abbreviation mark: it stands in for the long tail of a formal name, as in กรุงเทพฯ.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-mark","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"cf8eaddc-cd8e-55ca-a652-237794f23e8b","text":"ท","kind":"consonant","romanization":"th","pronunciationHint":"th with a puff of air, like the \"t\" in \"top\" (not the th in \"the\")","mnemonic":"ท is ท ทหาร (thor thahaan, soldier). Picture a soldier standing tall; ท gives the aspirated th sound with a clear puff of air.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"0abef0b2-0c0d-5a3b-a853-11eddd2dd366","text":"พ","kind":"consonant","romanization":"ph","pronunciationHint":"ph with a puff of air, like the \"p\" in \"pin\"","mnemonic":"พ is พ พาน (phaw phaan, a footed offering tray). Picture the tall pedestal tray; พ gives the aspirated ph sound in the low class.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"2155718d-6a75-5088-a3f6-9a16940e6e60","key":"paiyannoi-abbrev","name":"ฯ Abbreviates a Long Name","shortDescription":"ฯ shortens a well-known formal name in writing","explanation":"The paiyannoi mark shortens a long, familiar name on the page. กรุงเทพฯ writes the everyday form of Bangkok''s ceremonial name. The related ฯลฯ means ''etc.''.","examples":[{"text":"กรุงเทพฯ = grung-thêep"},{"text":"ฯลฯ = etc."}]}],"drills":[{"id":"7e42769e-7d90-5042-a244-d557bc9e2099","key":"krungthep-drill-01-recognize","type":"recognize","prompt":"Which mark abbreviates a long name?","payload":{},"options":[{"text":"ฯ","isCorrect":true},{"text":"ๆ"},{"text":"์"},{"text":"๙"}]},{"id":"80dfcef8-5cef-528c-a005-8852b50e130d","key":"krungthep-drill-02-match","type":"match","prompt":"What does กรุงเทพฯ mean?","payload":{},"options":[{"text":"Bangkok","isCorrect":true},{"text":"Thailand"},{"text":"province"},{"text":"capital letter"}]},{"id":"84655cab-1ddf-55bf-ab05-3e6c972fe14b","key":"krungthep-drill-03-sound","type":"sound","prompt":"What does ฯลฯ mean?","payload":{},"options":[{"text":"etc. / and so on","isCorrect":true},{"text":"the end"},{"text":"please"},{"text":"and you"}]},{"id":"dcaa874b-d463-5642-ac5c-45bc235088c2","key":"krungthep-drill-04-sound","type":"sound","prompt":"How do you read the ฯ in กรุงเทพฯ?","payload":{},"options":[{"text":"as the shortened everyday name","isCorrect":true},{"text":"as a separate sound"},{"text":"as a number"},{"text":"as silence forever"}]},{"id":"fab03dfc-ebae-5e49-ae2b-6327d8e263e9","key":"krungthep-drill-05-spot","type":"spot","prompt":"Which spelling is \"Bangkok\"?","payload":{},"options":[{"text":"กรุงเทพฯ","isCorrect":true},{"text":"กรุงเทพ"},{"text":"เทพกรุง"},{"text":"กรุงเทพๆ"}]}]}}'::jsonb, '271cda085a5e200e571c958b351f75cf56955d7c79703a3dbc8940c3ad1b34bf', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('9dfaee4c-adfa-522d-a75d-c1a68aee7097'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '7b6fd017-a364-50db-ab0f-d2ba417b03cf'::uuid, 'chan', 41, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"7b6fd017-a364-50db-ab0f-d2ba417b03cf","slug":"chan","lessonOrdinal":41,"stage":12,"title":"ฉัน — The High-Class ch and f","anchor":{"id":"ea5c0831-1d72-5d88-a4c8-7083916caf2e","slug":"chan","text":"ฉัน","meaning":"I / me","pronunciation":"chǎn","categoryKey":"daily","contextNote":"ฉัน (I/me) is an everyday pronoun. It introduces two high-class letters: ฉ (ch) and ฝ (f), which complete the aspirate pairs.","segments":[{"text":"ฉัน","sound":"chǎn"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"269d9fea-2221-5032-a4c2-cfd2be2f7499","key":"word-0e1d-0e19","text":"ฝน","meaning":"rain","pronunciation":"fǒn","categoryKey":"daily","segments":[{"text":"ฝน","sound":"fǒn"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"79bebf06-cf61-5d3a-a2c7-397e6591bb88","key":"word-0e1d-0e32-0e01","text":"ฝาก","meaning":"to deposit / leave with","pronunciation":"fàak","categoryKey":"daily","segments":[{"text":"ฝาก","sound":"fàak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"ecc5bcb8-a054-558c-ae6d-b2379f8826ac","key":"word-0e09-0e25-0e32-0e14","text":"ฉลาด","meaning":"clever","pronunciation":"chà-làat","categoryKey":"daily","segments":[{"text":"ฉ","sound":"chà"},{"text":"ลาด","sound":"làat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"104348af-4627-51be-a8b6-ff5ac9029ac8","key":"word-0e1d-0e32","text":"ฝา","meaning":"lid / cover","pronunciation":"fǎa","categoryKey":"daily","segments":[{"text":"ฝา","sound":"fǎa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"4361754f-fd35-5d0e-a82e-96dd96394501","key":"word-0e1d-0e31-0e48-0e07","text":"ฝั่ง","meaning":"bank / side (of a river)","pronunciation":"fàng","categoryKey":"place","segments":[{"text":"ฝั่ง","sound":"fàng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"dd3eea5f-ff3b-520e-ac32-f7c342c62492","key":"word-0e1d-0e36-0e01","text":"ฝึก","meaning":"to train / practice","pronunciation":"fùek","categoryKey":"daily","segments":[{"text":"ฝึก","sound":"fùek"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"a0d9c48f-36f8-54eb-a040-53408622a311","key":"word-0e1d-0e31-0e19","text":"ฝัน","meaning":"to dream","pronunciation":"fǎn","categoryKey":"daily","segments":[{"text":"ฝัน","sound":"fǎn"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"770b3a79-0c9b-562a-a80b-56698dde827e","key":"word-0e09-0e25-0e2d-0e07","text":"ฉลอง","meaning":"to celebrate","pronunciation":"chà-lǎwng","categoryKey":"daily","segments":[{"text":"ฉ","sound":"chà"},{"text":"ลอง","sound":"lǎwng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":true,"item":{"id":"20bc7a03-1319-5e9f-a6f1-f10db0beb4ee","key":"word-0e1d-0e32-0e01-0e40-0e07-0e34-0e19","text":"ฝากเงิน","meaning":"to deposit money","pronunciation":"fàak ngern","categoryKey":"daily","segments":[{"text":"ฝาก","sound":"fàak"},{"text":"เงิน","sound":"ngern"}],"metadata":{"sourceType":"phrase"}}},{"roleKey":"practice_core","ordinalInRole":10,"isDrillTarget":false,"item":{"id":"bbe94559-1bc7-563e-a022-86ea5716e7dc","key":"word-0e1d-0e19-0e15-0e01","text":"ฝนตก","meaning":"it''s raining","pronunciation":"fǒn dtòk","categoryKey":"daily","segments":[{"text":"ฝน","sound":"fǒn"},{"text":"ตก","sound":"dtòk"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"25e2dc08-80ed-5b1f-a658-ee7c5905aae6","text":"ฉ","kind":"consonant","romanization":"ch","pronunciationHint":"ch as in \"chair\", with a puff of air","mnemonic":"ฉ is ฉ ฉิ่ง (chǎw chìng, small hand cymbals). Picture the tiny cymbals; ฉ is a high-class ch.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"9ae43c0f-f815-5d37-a9e8-a495d5a54892","text":"ฝ","kind":"consonant","romanization":"f","pronunciationHint":"f as in \"fan\"","mnemonic":"ฝ is ฝ ฝา (fǎw fǎa, a lid). Picture a pot lid; ฝ is a high-class f, the partner of low-class ฟ.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"6655bad5-f432-5868-aa67-e7247253802f","text":"ั","kind":"vowel","romanization":"a","pronunciationHint":"short \"a\" as in \"cut\"","mnemonic":"ั is the short a cap above the consonant. It sits close and quick, just like the clipped a in ผัด and ผัก.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"02613447-13c2-5348-aad7-857e5e6ae103","text":"น","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"น is น หนู (nor nuu, mouse). Picture the curl as a little mouse body and tail, and use หนู to lock in the n sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"9593d6a6-13bb-563d-a33d-b01dd74e3528","text":"ช","kind":"consonant","romanization":"ch","pronunciationHint":"ch as in \"check\"","mnemonic":"ช is ช ช้าง (chor chaang, elephant). Picture the long dropping stroke as an elephant trunk, and use ช้าง for the ch sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"27b2ee31-e73d-533a-adfd-5b8a76f0c39f","text":"ฟ","kind":"consonant","romanization":"f","pronunciationHint":"f as in \"fan\"","mnemonic":"ฟ is ฟ ฟัน (faw fan, teeth). Picture a row of teeth; ฟ gives a plain f in the low class.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"7aaad0e9-289f-57a1-a7e4-8926438a7028","key":"high-ch-f","name":"ฉ and ฝ Are High-Class","shortDescription":"ฉ is a high ch (vs low ช); ฝ is a high f (vs low ฟ)","explanation":"ฉ makes the same ch as ช and ฝ makes the same f as ฟ, but both new letters are high class. High-class consonants default to a rising tone and take only mai ek or mai tho.","examples":[{"text":"ฉัน = chǎn"},{"text":"ฝน = fǒn"}]}],"drills":[{"id":"b52f1706-4080-5edc-a4cd-fdade9b11ae8","key":"chan-drill-01-recognize","type":"recognize","prompt":"Which letter is the high-class \"ch\"?","payload":{},"options":[{"text":"ฉ","isCorrect":true},{"text":"ช"},{"text":"ซ"},{"text":"จ"}]},{"id":"3df60e1d-15dd-571d-a2c3-340891a86b27","key":"chan-drill-02-recognize","type":"recognize","prompt":"Which letter is the high-class \"f\"?","payload":{},"options":[{"text":"ฝ","isCorrect":true},{"text":"ฟ"},{"text":"พ"},{"text":"ผ"}]},{"id":"7dacdd6e-064b-5420-adbd-718d905ba824","key":"chan-drill-03-sound","type":"sound","prompt":"What is the default tone of a high-class consonant?","payload":{},"options":[{"text":"rising","isCorrect":true},{"text":"high"},{"text":"low"},{"text":"mid"}]},{"id":"168b8d0e-f4b9-5803-a0f1-1cc4f57aee1b","key":"chan-drill-04-match","type":"match","prompt":"What does ฉัน mean?","payload":{},"options":[{"text":"I / me","isCorrect":true},{"text":"rain"},{"text":"lid"},{"text":"clever"}]},{"id":"64cb9247-33ee-5b80-ab5d-699bb89acb80","key":"chan-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"I / me\"?","payload":{},"options":[{"text":"ฉัน","isCorrect":true},{"text":"ชัน"},{"text":"ฝัน"},{"text":"ฉน"}]}]}}'::jsonb, 'ff2a3272f3e9a2ba392e51e300bd3c080d06b90309b587c46d4497f8b2df1061', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('f547482d-7a39-518d-a3a7-521fe891414c'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, 'a03fce9c-2e72-5cef-a746-65946b24fa81'::uuid, 'yai', 42, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"a03fce9c-2e72-5cef-a746-65946b24fa81","slug":"yai","lessonOrdinal":42,"stage":12,"title":"ใหญ่ — Four More Low-Class Letters","anchor":{"id":"73c521fc-c4c9-5bce-a86e-515ccc4b52d0","slug":"yai","text":"ใหญ่","meaning":"big","pronunciation":"yài","categoryKey":"daily","contextNote":"ใหญ่ (big) uses ญ. This lesson adds four more low-class letters — ญ, ธ, ภ, ฮ — that duplicate sounds you know but appear across everyday and formal words.","segments":[{"text":"ใหญ่","sound":"yài"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"dbbb88ee-13e0-579a-ad3b-d4b902666c05","key":"word-0e18-0e19-0e32-0e04-0e32-0e23","text":"ธนาคาร","meaning":"bank","pronunciation":"thá-naa-khaan","categoryKey":"sign","segments":[{"text":"ธ","sound":"thá"},{"text":"นา","sound":"naa"},{"text":"คาร","sound":"khaan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"329c3498-f22a-5a10-a53f-9f943a45e574","key":"word-0e20-0e32-0e29-0e32","text":"ภาษา","meaning":"language","pronunciation":"phaa-sǎa","categoryKey":"daily","segments":[{"text":"ภา","sound":"phaa"},{"text":"ษา","sound":"sǎa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"a0177825-8b0f-5ab3-a914-8985537ce802","key":"word-0e1c-0e39-0e49-0e2b-0e0d-0e34-0e07","text":"ผู้หญิง","meaning":"woman","pronunciation":"phûu-yǐng","categoryKey":"daily","segments":[{"text":"ผู้","sound":"phûu"},{"text":"หญิง","sound":"yǐng"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"ed99b763-0253-5e85-a5a8-f15ee0aeefcb","key":"word-0e18-0e07","text":"ธง","meaning":"flag","pronunciation":"thong","categoryKey":"daily","segments":[{"text":"ธง","sound":"thong"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"165e38ec-54b1-53ea-a8d2-b28d2fd929f2","key":"word-0e20-0e32-0e1e","text":"ภาพ","meaning":"picture / image","pronunciation":"phâap","categoryKey":"daily","segments":[{"text":"ภาพ","sound":"phâap"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"77eb4e8f-0d6d-5e14-a5f2-72db349bcdbb","key":"word-0e20-0e39-0e40-0e02-0e32","text":"ภูเขา","meaning":"mountain","pronunciation":"phuu-khǎo","categoryKey":"place","segments":[{"text":"ภู","sound":"phuu"},{"text":"เขา","sound":"khǎo"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"dc4b64e6-2002-52d8-a90b-a18d555e564e","key":"word-0e1b-0e31-0e0d-0e2b-0e32","text":"ปัญหา","meaning":"problem","pronunciation":"bpan-hǎa","categoryKey":"daily","segments":[{"text":"ปัญ","sound":"bpan"},{"text":"หา","sound":"hǎa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"e6973667-a42a-5a12-a4be-8e3297829d3a","key":"word-0e0d-0e35-0e48-0e1b-0e38-0e48-0e19","text":"ญี่ปุ่น","meaning":"Japan","pronunciation":"yîi-bpùn","categoryKey":"place","segments":[{"text":"ญี่","sound":"yîi"},{"text":"ปุ่น","sound":"bpùn"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"fc735616-7a96-501d-af66-0d523b325484","key":"word-0e18-0e23-0e23-0e21-0e14-0e32","text":"ธรรมดา","meaning":"ordinary","pronunciation":"tham-má-daa","categoryKey":"daily","segments":[{"text":"ธรรม","sound":"tham-má"},{"text":"ดา","sound":"daa"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."},{"id":"letter-type-tone-mark","title":"Tone mark","body":"Tone marks are small symbols written above a consonant to override the default tone of the syllable. Thai has two common tone marks (mai ek ่ and mai tho ้). Their effect depends on the consonant class of the syllable they modify."}],"newGraphemes":[{"id":"cd8cb0f8-87c5-5145-ad3e-47325f6ccdba","text":"ญ","kind":"consonant","romanization":"y","pronunciationHint":"y as in \"yes\" at the start; an n sound as a final","mnemonic":"ญ is ญ หญิง (yaw yǐng, woman). It is a low-class y at the start and an n at the end of a syllable.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"eda04af2-dea4-5629-a5a4-b26369ba3658","text":"ธ","kind":"consonant","romanization":"th","pronunciationHint":"th with a puff of air, like ท","mnemonic":"ธ is ธ ธง (thaw thong, flag). Picture a flag; ธ is a low-class th, a partner of ท.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"20a68aca-32ed-5400-a1dd-28072315ba4f","text":"ภ","kind":"consonant","romanization":"ph","pronunciationHint":"ph with a puff of air, like พ","mnemonic":"ภ is ภ สำเภา (phaw sǎm-phao, a junk boat). Picture the sailing junk; ภ is a low-class ph, a partner of พ.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"b72cd389-7885-5b96-a519-bf5840f42a86","text":"ฮ","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hat\"","mnemonic":"ฮ is ฮ นกฮูก (haw nók-hûuk, an owl). Picture the owl; ฮ is a low-class h, the partner of high-class ห.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"54ee9c51-1ccc-59bb-a95d-2e6f8d66ecf1","text":"ใ","kind":"vowel","romanization":"ai","pronunciationHint":"the same \"ai\" sound as ไ","mnemonic":"ใ (ไม้ม้วน, mai muan) sounds identical to ไ but appears in only about 20 specific words you memorize. Note the curled-in top.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"98079396-6adf-5409-a63c-121764a3840e","text":"ห","kind":"consonant","romanization":"h","pronunciationHint":"h as in \"hello\"; often used as a leading tone helper","mnemonic":"ห is ห หีบ (hor hiip, chest). Picture the tall shape as a chest with a lid; in words like หมู, this h-letter can also guide the tone.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"13e7c7cd-283c-5d0b-a9cc-ce5b3831e495","text":"่","kind":"tone_mark","romanization":"mai ek","pronunciationHint":"first tone mark written above the consonant","mnemonic":"่ is mai ek, the first tone mark. It is one small stroke above the consonant, so read it as a compact tone cue.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-tone-mark","position":"vowel-position"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]}],"rules":[{"id":"baf45d09-b34e-5462-a6ac-391c7ad854f6","key":"four-low-duplicates","name":"Four More Low-Class Letters","shortDescription":"ญ (y/final n), ธ (th), ภ (ph), and ฮ (h) are all low class","explanation":"These four duplicate sounds you already read: ญ is a y that closes as n, ธ is a th like ท, ภ is a ph like พ, and ฮ is an h like ห. All are low class and turn up in formal and Pali/Sanskrit words.","examples":[{"text":"ใหญ่ = yài"},{"text":"ธนาคาร = thá-naa-khaan"}]}],"drills":[{"id":"c6cfda55-8e63-5aca-ae99-f3d805089ace","key":"yai-drill-01-recognize","type":"recognize","prompt":"Which letter is a low-class \"h\"?","payload":{},"options":[{"text":"ฮ","isCorrect":true},{"text":"ห"},{"text":"ธ"},{"text":"ภ"}]},{"id":"ec4ec619-8101-5bf3-a4e6-62660e1248e7","key":"yai-drill-02-sound","type":"sound","prompt":"What sound does ญ make at the end of a syllable?","payload":{},"options":[{"text":"n","isCorrect":true},{"text":"y"},{"text":"ng"},{"text":"m"}]},{"id":"b339841d-e1dc-5ee9-a5f9-8f978d2ca471","key":"yai-drill-03-sound","type":"sound","prompt":"ธ and ภ duplicate which sounds?","payload":{},"options":[{"text":"th and ph","isCorrect":true},{"text":"d and b"},{"text":"s and f"},{"text":"k and g"}]},{"id":"d0e6fc1d-b538-5e71-a85a-09e12fbee030","key":"yai-drill-04-match","type":"match","prompt":"What does ใหญ่ mean?","payload":{},"options":[{"text":"big","isCorrect":true},{"text":"small"},{"text":"bank"},{"text":"flag"}]},{"id":"fa5bb640-eea0-513a-a8ae-4a240f1949fc","key":"yai-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"big\"?","payload":{},"options":[{"text":"ใหญ่","isCorrect":true},{"text":"ใหม่"},{"text":"ใหย่"},{"text":"หญ่ใ"}]}]}}'::jsonb, '9d80faf8815ad030782c4bac7fd942c6b45f2aa3996168da5fdadba015016e9d', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('89bf3989-0dcd-5250-a47e-1fde5fad40ea'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '94c2f1fe-a488-5d78-abef-78729be22427'::uuid, 'prathet', 43, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"94c2f1fe-a488-5d78-abef-78729be22427","slug":"prathet","lessonOrdinal":43,"stage":13,"title":"ประเทศ — The s and n Duplicates","anchor":{"id":"fc785d0a-8d8b-50be-a1de-286e89480957","slug":"prathet","text":"ประเทศ","meaning":"country","pronunciation":"bprà-thêet","categoryKey":"sign","contextNote":"ประเทศ (country) ends in ศ, one of three Sanskrit-derived duplicates. ศ, ษ (both s) and ณ (n) show up in formal vocabulary and on signs.","segments":[{"text":"ประ","sound":"bprà"},{"text":"เทศ","sound":"thêet"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"4d38b225-c9e1-5a0f-a5f6-b58a013f8d81","key":"word-0e28-0e32-0e25","text":"ศาล","meaning":"court (of law)","pronunciation":"sǎan","categoryKey":"sign","segments":[{"text":"ศาล","sound":"sǎan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"329a3ee8-902b-5f10-aec7-7699414f16cd","key":"word-0e28-0e39-0e19-0e22-0e4c","text":"ศูนย์","meaning":"zero / center","pronunciation":"sǔun","categoryKey":"sign","segments":[{"text":"ศูนย์","sound":"sǔun"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"d54ac947-882b-520a-ad51-526ad593c4b2","key":"word-0e1e-0e34-0e40-0e28-0e29","text":"พิเศษ","meaning":"special","pronunciation":"phí-sèet","categoryKey":"sign","segments":[{"text":"พิ","sound":"phí"},{"text":"เศษ","sound":"sèet"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"faafd749-7b26-55fa-af7e-378c7d88f98b","key":"word-0e28-0e36-0e01-0e29-0e32","text":"ศึกษา","meaning":"education / to study","pronunciation":"sùek-sǎa","categoryKey":"sign","segments":[{"text":"ศึก","sound":"sùek"},{"text":"ษา","sound":"sǎa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"aa09ddb1-f9e2-582e-a4e2-fe10343d9b85","key":"word-0e19-0e31-0e01-0e28-0e36-0e01-0e29-0e32","text":"นักศึกษา","meaning":"university student","pronunciation":"nák-sùek-sǎa","categoryKey":"daily","segments":[{"text":"นัก","sound":"nák"},{"text":"ศึก","sound":"sùek"},{"text":"ษา","sound":"sǎa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"3bc33310-dcd4-5ae2-a589-6990f0a67108","key":"word-0e28-0e32-0e2a-0e19-0e32","text":"ศาสนา","meaning":"religion","pronunciation":"sàat-sà-nǎa","categoryKey":"daily","segments":[{"text":"ศาส","sound":"sàat"},{"text":"นา","sound":"sà-nǎa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"d7149114-c0de-5b7f-a4ad-02a00e5256fe","key":"word-0e04-0e13-0e30","text":"คณะ","meaning":"faculty / group","pronunciation":"khá-ná","categoryKey":"daily","segments":[{"text":"ค","sound":"khá"},{"text":"ณะ","sound":"ná"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"dbaf88c5-7e89-51ef-a002-edf2ee4737de","key":"word-0e1b-0e23-0e30-0e40-0e17-0e28-0e44-0e17-0e22","text":"ประเทศไทย","meaning":"Thailand","pronunciation":"bprà-thêet-thai","categoryKey":"place","segments":[{"text":"ประเทศ","sound":"bprà-thêet"},{"text":"ไทย","sound":"thai"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"45f208ad-fa0a-5ef1-a688-45d53befa404","text":"ศ","kind":"consonant","romanization":"s","pronunciationHint":"s as in \"sun\" at the start; a t sound as a final","mnemonic":"ศ is ศ ศาลา (sǎw sǎa-laa, a pavilion). It is a high-class s, common in Sanskrit-derived words.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"992ee0aa-73c0-5d68-a91c-25c3de274a95","text":"ษ","kind":"consonant","romanization":"s","pronunciationHint":"s at the start; a t sound as a final","mnemonic":"ษ is ษ ฤๅษี (sǎw ruee-sǐi, a hermit). It is another high-class s from Sanskrit spellings.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"fbdb6ea3-ac5d-5caf-a47a-16bcca75c751","text":"ณ","kind":"consonant","romanization":"n","pronunciationHint":"n as in \"no\"","mnemonic":"ณ is ณ เณร (naw neen, a novice monk). It is a low-class n, a formal partner of น.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"1468f8a2-d91f-5127-ac8d-e40de6f54950","text":"ป","kind":"consonant","romanization":"bp","pronunciationHint":"a tight, unaspirated p, like the p in \"spin\" (between English b and p)","mnemonic":"ป is ป ปลา (bpor bplaa, fish). Picture a tall fish standing on its tail; ป is the unaspirated p that pairs with the dt sound of ต.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"76e47267-9161-5fee-a1e7-f698d88554f8","text":"ร","kind":"consonant","romanization":"r","pronunciationHint":"r as in \"run\" at the start; n at the end in some words","mnemonic":"ร is ร เรือ (ror ruea, boat). Picture the main curve as a boat hull rocking forward, and use เรือ to remember the r sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"d930649b-b987-5148-a7d1-8aaabef44060","text":"เ","kind":"vowel","romanization":"e","pronunciationHint":"long \"e\" as in \"they\"","mnemonic":"เ is the long-e vowel written BEFORE the consonant, even though you say the consonant first. Spot เ, jump to the consonant after it, then add the e.","position":"left","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"cf8eaddc-cd8e-55ca-a652-237794f23e8b","text":"ท","kind":"consonant","romanization":"th","pronunciationHint":"th with a puff of air, like the \"t\" in \"top\" (not the th in \"the\")","mnemonic":"ท is ท ทหาร (thor thahaan, soldier). Picture a soldier standing tall; ท gives the aspirated th sound with a clear puff of air.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"ba0e817f-b634-5da2-a931-3fd904ab93ea","key":"duplicate-s-n","name":"ศ, ษ, and ณ Duplicate s and n","shortDescription":"ศ and ษ sound s; ณ sounds n — mostly in formal words","explanation":"These three add no new sounds: ศ and ษ are high-class s, and ณ is a low-class n. They appear mainly in Pali/Sanskrit loanwords and formal vocabulary such as ประเทศ and คุณ.","examples":[{"text":"ประเทศ = bprà-thêet"},{"text":"คุณ = khun"}]}],"drills":[{"id":"e72b29fa-c99b-53b0-ad7d-e13d41a6e9b6","key":"prathet-drill-01-sound","type":"sound","prompt":"What sound do ศ and ษ make?","payload":{},"options":[{"text":"s","isCorrect":true},{"text":"sh"},{"text":"ch"},{"text":"t only"}]},{"id":"b850c76c-9be6-5065-a3c7-e8b306dbfb1e","key":"prathet-drill-02-sound","type":"sound","prompt":"What sound does ณ make?","payload":{},"options":[{"text":"n","isCorrect":true},{"text":"ng"},{"text":"m"},{"text":"l"}]},{"id":"55ece1dd-cf3c-5ab9-a283-eb4975f81b6b","key":"prathet-drill-03-recognize","type":"recognize","prompt":"Which letter is a high-class s from Sanskrit?","payload":{},"options":[{"text":"ศ","isCorrect":true},{"text":"ณ"},{"text":"น"},{"text":"ช"}]},{"id":"82c43c00-953e-58a0-a18f-88a68150e937","key":"prathet-drill-04-match","type":"match","prompt":"What does ประเทศ mean?","payload":{},"options":[{"text":"country","isCorrect":true},{"text":"religion"},{"text":"court"},{"text":"student"}]},{"id":"2e57433e-7d9d-5838-a370-aec0637f16d6","key":"prathet-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"country\"?","payload":{},"options":[{"text":"ประเทศ","isCorrect":true},{"text":"ประเทด"},{"text":"ประเทท"},{"text":"เทศประ"}]}]}}'::jsonb, 'd1fe99600c28932d286ab5fba1e05ed5ec39e0e8436f191817794e77629ffc01', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('283cc669-18f9-5e57-a16d-0cdd50324f55'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '5cf475a5-bf3b-5c84-a6a5-db4e09025c11'::uuid, 'kila', 44, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"5cf475a5-bf3b-5c84-a6a5-db4e09025c11","slug":"kila","lessonOrdinal":44,"stage":13,"title":"กีฬา — The Rare Sanskrit Letters","anchor":{"id":"f02df751-db9e-5bbc-a06f-546288a18aef","slug":"kila","text":"กีฬา","meaning":"sport(s)","pronunciation":"gii-laa","categoryKey":"daily","contextNote":"กีฬา (sports) uses the rare ฬ. This recognition lesson gathers eight uncommon Pali/Sanskrit letters that duplicate sounds you already read.","segments":[{"text":"กี","sound":"gii"},{"text":"ฬา","sound":"laa"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"34f2bc0c-dae6-5d2c-a8b0-b0be46ed7309","key":"word-0e10-0e32-0e19","text":"ฐาน","meaning":"base / pedestal","pronunciation":"thǎan","categoryKey":"daily","segments":[{"text":"ฐาน","sound":"thǎan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"8029b11e-2e2b-581b-a4ac-dacb0ab0fd32","key":"word-0e23-0e30-0e06-0e31-0e07","text":"ระฆัง","meaning":"bell","pronunciation":"rá-khang","categoryKey":"daily","segments":[{"text":"ระ","sound":"rá"},{"text":"ฆัง","sound":"khang"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"5424aab9-c43e-5a3d-a0fd-d986c686fc4e","key":"word-0e19-0e32-0e2c-0e34-0e01-0e32","text":"นาฬิกา","meaning":"clock / watch","pronunciation":"naa-lí-gaa","categoryKey":"daily","segments":[{"text":"นา","sound":"naa"},{"text":"ฬิ","sound":"lí"},{"text":"กา","sound":"gaa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":false,"item":{"id":"7a03dff1-58e6-5b99-a0a2-8b82813553aa","key":"word-0e23-0e31-0e10-0e1a-0e32-0e25","text":"รัฐบาล","meaning":"government","pronunciation":"rát-thà-baan","categoryKey":"sign","segments":[{"text":"รัฐ","sound":"rát-thà"},{"text":"บาล","sound":"baan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"63a87bb2-a1cf-52f0-ad83-37fa225f8982","key":"word-0e21-0e32-0e15-0e23-0e10-0e32-0e19","text":"มาตรฐาน","meaning":"standard","pronunciation":"mâat-dtrà-thǎan","categoryKey":"sign","segments":[{"text":"มาตร","sound":"mâat-dtrà"},{"text":"ฐาน","sound":"thǎan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"d13c0e58-9833-54af-a7f3-dd51993e9fce","key":"word-0e1b-0e0f-0e34-0e1a-0e31-0e15-0e34","text":"ปฏิบัติ","meaning":"to practice / perform","pronunciation":"bpà-dtì-bàt","categoryKey":"daily","segments":[{"text":"ป","sound":"bpà"},{"text":"ฏิ","sound":"dtì"},{"text":"บัติ","sound":"bàt"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"209656fd-e928-5f1d-a264-a19273693b24","key":"word-0e1b-0e25-0e32-0e27-0e32-0e2c","text":"ปลาวาฬ","meaning":"whale","pronunciation":"bplaa-waan","categoryKey":"daily","segments":[{"text":"ปลา","sound":"bplaa"},{"text":"วาฬ","sound":"waan"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"bbf7a5d9-16da-5c2d-a422-2d0ac6df1f5b","key":"word-0e2a-0e19-0e32-0e21-0e01-0e35-0e2c-0e32","text":"สนามกีฬา","meaning":"stadium","pronunciation":"sà-nǎam gii-laa","categoryKey":"place","segments":[{"text":"สนาม","sound":"sà-nǎam"},{"text":"กีฬา","sound":"gii-laa"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"79c9bd2a-a5ce-5a56-a13a-4da3aa51a277","text":"ฐ","kind":"consonant","romanization":"th","pronunciationHint":"a th sound, like ถ","mnemonic":"ฐ is ฐ ฐาน (thǎw thǎan, a base/pedestal). A rare high-class th.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"91dcaa7b-ee9c-5ff6-ad11-affe2be851ee","text":"ฑ","kind":"consonant","romanization":"th","pronunciationHint":"a th sound, like ท","mnemonic":"ฑ is ฑ มณโฑ (thaw mon-thoo, a character''s name). A rare low-class th.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"3d206919-dbc2-52a0-a076-71a619f56cbc","text":"ฒ","kind":"consonant","romanization":"th","pronunciationHint":"a th sound, like ท","mnemonic":"ฒ is ฒ ผู้เฒ่า (thaw phûu-thâo, an elder). A rare low-class th.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"75317e70-ff4a-5f5f-af55-14b3f747c477","text":"ฎ","kind":"consonant","romanization":"d","pronunciationHint":"a d sound, like ด","mnemonic":"ฎ is ฎ ชฎา (daw chá-daa, a headdress). A rare mid-class d.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"7015572b-a896-55b4-aab6-06572b716d6a","text":"ฏ","kind":"consonant","romanization":"dt","pronunciationHint":"a tight t sound, like ต","mnemonic":"ฏ is ฏ ปฏัก (dtaw bpà-dtàk, a goad). A rare mid-class t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"4c5e3966-7aee-550d-a0c3-f66233a8a045","text":"ฆ","kind":"consonant","romanization":"kh","pronunciationHint":"a kh sound, like ค","mnemonic":"ฆ is ฆ ระฆัง (khaw rá-khang, a bell). A rare low-class kh.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"8b7a6f67-7592-5da4-a113-b3de46bf4d04","text":"ฬ","kind":"consonant","romanization":"l","pronunciationHint":"an l sound, like ล","mnemonic":"ฬ is ฬ จุฬา (law jù-laa, a kite). A rare low-class l, as in กีฬา.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"b5a720ea-1ec7-5c36-ad95-1e4913ccbd3e","text":"ฌ","kind":"consonant","romanization":"ch","pronunciationHint":"a ch sound, like ช","mnemonic":"ฌ is ฌ เฌอ (chaw choee, a tree). A rare low-class ch.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"reviewGraphemes":[{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"ee1f3cf4-8315-510e-a613-dfc5ec42d2f5","text":"ี","kind":"vowel","romanization":"ii","pronunciationHint":"long \"ee\" as in \"see\"","mnemonic":"ี is ิ with an extra length stroke on top. That extra stroke is your clue to hold the sound longer: short i becomes long ii.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"f9127074-00ba-5295-aac0-01022b890b89","text":"า","kind":"vowel","romanization":"aa","pronunciationHint":"long \"aa\" as in \"father\"","mnemonic":"า is the right-side long aa stroke. It stands after the consonant and stretches the syllable into the long vowel you hear in มา and กา.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"50ada581-79e7-5549-a9a8-77693569d9b8","text":"ล","kind":"consonant","romanization":"l","pronunciationHint":"l as in \"love\"","mnemonic":"ล is ล ลิง (lor ling, monkey). Let the long lower curve be the monkey''s tail, and connect ลิง to the l sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"31b3119a-0a35-555d-ae5d-fa22904efcfb","key":"rare-duplicates","name":"Eight Rare Sanskrit/Pali Letters","shortDescription":"These letters reuse sounds you know and appear only in formal words","explanation":"You do not need to produce these from memory. Recognize them by their familiar sound — ฬ is l, ฆ is kh, ฌ is ch, ฎ/ฏ are d/t, and ฐ/ฑ/ฒ are th. They live in formal, legal, and Pali/Sanskrit vocabulary.","examples":[{"text":"กีฬา = gii-laa"},{"text":"รัฐบาล = rát-thà-baan"}]}],"drills":[{"id":"29ee1500-b700-502b-ae5e-b1455fa12ef4","key":"kila-drill-01-sound","type":"sound","prompt":"What sound does ฬ make?","payload":{},"options":[{"text":"l","isCorrect":true},{"text":"n"},{"text":"r"},{"text":"th"}]},{"id":"44994749-daa9-53a1-a04c-949092f2e41a","key":"kila-drill-02-sound","type":"sound","prompt":"What sound does ฆ make?","payload":{},"options":[{"text":"kh","isCorrect":true},{"text":"ng"},{"text":"g"},{"text":"h"}]},{"id":"58fbf81f-18a8-57b7-a3a5-454b64b6dd67","key":"kila-drill-03-sound","type":"sound","prompt":"Where do these eight letters mostly appear?","payload":{},"options":[{"text":"formal Pali/Sanskrit words","isCorrect":true},{"text":"everyday slang"},{"text":"numbers"},{"text":"tone marks"}]},{"id":"90c9b880-52ca-55ec-a6ee-916654055351","key":"kila-drill-04-match","type":"match","prompt":"What does กีฬา mean?","payload":{},"options":[{"text":"sport(s)","isCorrect":true},{"text":"clock"},{"text":"bell"},{"text":"degree"}]},{"id":"ec2626fe-1584-5804-a230-b6d1842d0dd8","key":"kila-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"sport(s)\"?","payload":{},"options":[{"text":"กีฬา","isCorrect":true},{"text":"กีลา"},{"text":"กิฬา"},{"text":"ฬากี"}]}]}}'::jsonb, '42ffc42292ca9710ca7550361b1a7d307135c3ad81146be72d6f9fcde1a1163a', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('d978856e-ba0b-5377-a6d2-f475e8371810'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '5a17f704-8e6f-5e05-a52f-4edf3bd1a7cf'::uuid, 'angkrit', 45, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"5a17f704-8e6f-5e05-a52f-4edf3bd1a7cf","slug":"angkrit","lessonOrdinal":45,"stage":13,"title":"อังกฤษ — ฤ and Spelling Exceptions","anchor":{"id":"f47dd5a1-4600-5b0c-aea9-363bfe7efab7","slug":"angkrit","text":"อังกฤษ","meaning":"England / English","pronunciation":"ang-grìt","categoryKey":"sign","contextNote":"อังกฤษ (English) shows ฤ, a vowel-like letter read ri, rue, or rer by word. This lesson also gathers the leading-อ words and the silent-r spellings.","segments":[{"text":"อัง","sound":"ang"},{"text":"กฤษ","sound":"grìt"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":true,"item":{"id":"2f645dc8-4529-5fd0-a9e9-935e0bfa0b8d","key":"word-0e24-0e14-0e39","text":"ฤดู","meaning":"season","pronunciation":"rúe-duu","categoryKey":"daily","segments":[{"text":"ฤ","sound":"rúe"},{"text":"ดู","sound":"duu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":true,"item":{"id":"8d14ad3d-846d-53b0-a061-958c1b994e9e","key":"word-0e2d-0e22-0e32-0e01","text":"อยาก","meaning":"to want","pronunciation":"yàak","categoryKey":"daily","segments":[{"text":"อยาก","sound":"yàak"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":true,"item":{"id":"a2d333b2-dbed-552f-a69f-abc36961eb41","key":"word-0e2d-0e22-0e39-0e48","text":"อยู่","meaning":"to be (located)","pronunciation":"yùu","categoryKey":"daily","segments":[{"text":"อยู่","sound":"yùu"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":true,"item":{"id":"a8e3db3c-9006-569d-a46e-3d5176833f6e","key":"word-0e17-0e23-0e32-0e22","text":"ทราย","meaning":"sand","pronunciation":"saai","categoryKey":"place","segments":[{"text":"ทราย","sound":"saai"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":5,"isDrillTarget":false,"item":{"id":"e34660ca-9fba-5067-a136-d283c47aca23","key":"word-0e08-0e23-0e34-0e07","text":"จริง","meaning":"true / real","pronunciation":"jing","categoryKey":"daily","segments":[{"text":"จริง","sound":"jing"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":6,"isDrillTarget":false,"item":{"id":"e2575247-2bbe-5f93-a88e-66f1063ec552","key":"word-0e2d-0e22-0e48-0e32-0e07","text":"อย่าง","meaning":"kind / type / -ly","pronunciation":"yàang","categoryKey":"daily","segments":[{"text":"อย่าง","sound":"yàang"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":7,"isDrillTarget":false,"item":{"id":"731b6d39-1326-508d-a4e2-bb02ab448743","key":"word-0e2d-0e22-0e48-0e32","text":"อย่า","meaning":"don''t","pronunciation":"yàa","categoryKey":"daily","segments":[{"text":"อย่า","sound":"yàa"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":8,"isDrillTarget":false,"item":{"id":"2c8c4d23-e143-50fe-ad2f-9839f946df1d","key":"word-0e2a-0e23-0e49-0e32-0e07","text":"สร้าง","meaning":"to build","pronunciation":"sâang","categoryKey":"daily","segments":[{"text":"สร้าง","sound":"sâang"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":9,"isDrillTarget":false,"item":{"id":"5aa66285-91ee-5dfa-a589-cfd07ecfd896","key":"word-0e20-0e32-0e29-0e32-0e2d-0e31-0e07-0e01-0e24-0e29","text":"ภาษาอังกฤษ","meaning":"English language","pronunciation":"phaa-sǎa ang-grìt","categoryKey":"daily","segments":[{"text":"ภาษา","sound":"phaa-sǎa"},{"text":"อังกฤษ","sound":"ang-grìt"}],"metadata":{"sourceType":"phrase"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"d1fe60d4-1647-588d-a179-af64625a3b34","text":"ฤ","kind":"vowel","romanization":"rue","pronunciationHint":"read as \"ri\", \"rue\", or \"rer\" depending on the word","mnemonic":"ฤ (sara rue) bundles an r with a vowel. Its reading is lexical: ri in อังกฤษ, rue in ฤดู. Learn it word by word.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel"},"tags":[]}],"reviewGraphemes":[{"id":"d6388a97-b0cb-5594-af90-48fd4c770e0f","text":"อ","kind":"consonant","romanization":"silent carrier","pronunciationHint":"placeholder consonant used when a syllable begins with a vowel sound","mnemonic":"อ is อ อ่าง (or aang, basin). The round basin shape can hold a vowel, which fits its job as a silent carrier in อา and อาหาร.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"6655bad5-f432-5868-aa67-e7247253802f","text":"ั","kind":"vowel","romanization":"a","pronunciationHint":"short \"a\" as in \"cut\"","mnemonic":"ั is the short a cap above the consonant. It sits close and quick, just like the clipped a in ผัด and ผัก.","position":"above","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel","position":"vowel-position"},"tags":[]},{"id":"bda65912-fa0a-5328-a7d4-302245d61c3e","text":"ง","kind":"consonant","romanization":"ng","pronunciationHint":"ng as in \"singer\"; used at the start or end of a syllable","mnemonic":"ง is ง งู (ngor nguu, snake). Picture the curving body of a snake; ง makes the ng sound that English only uses at the ends of words.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"0323b564-2380-5449-aa92-cc5f6772a1a0","text":"ก","kind":"consonant","romanization":"g/k","pronunciationHint":"hard g/k sound; final ก closes like \"k\"","mnemonic":"ก is ก ไก่ (gor gai, chicken), the classic Thai alphabet anchor. Picture the hook as the chicken''s head and beak for the hard g/k sound.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"54e76aca-975b-5339-a522-a04021906f83","key":"rue-readings","name":"ฤ Reads ri / rue / rer","shortDescription":"ฤ has three possible readings, fixed per word","explanation":"ฤ stands in for an r plus a vowel, but which vowel depends on the word: ri in อังกฤษ, rue in ฤดู (season). There is no rule — memorize the reading with each word.","examples":[{"text":"อังกฤษ = ang-grìt"},{"text":"ฤดู = rúe-duu"}]},{"id":"e522d9c3-a27a-517f-ad79-42a0519d231e","key":"leading-aw-words","name":"Leading อ Makes ย Mid in Four Words","shortDescription":"อยู่, อย่า, อย่าง, อยาก — the อ is silent and shifts ย to mid class","explanation":"In exactly four common words, a silent leading อ turns the following ย into a mid-class consonant, giving a low tone: อยู่ (to be located), อย่า (don''t), อย่าง (kind/way), and อยาก (to want).","examples":[{"text":"อยู่ = yùu"},{"text":"อยาก = yàak"}]},{"id":"b57834ea-b9ea-5421-a5d8-28cf4e8abdcb","key":"silent-r-thr","name":"Silent ร and ทร = s","shortDescription":"ร is silent in จริง; ทร is read as s in ทราย","explanation":"A few spellings hide their r. In จริง the ร is silent (jing), and the pair ทร is read as s, as in ทราย (saai, sand). Treat these as fixed spellings.","examples":[{"text":"จริง = jing"},{"text":"ทราย = saai"}]}],"drills":[{"id":"8b7e8573-0b38-50f9-afe0-04c9a533a555","key":"angkrit-drill-01-sound","type":"sound","prompt":"How is ฤ read?","payload":{},"options":[{"text":"ri, rue, or rer depending on the word","isCorrect":true},{"text":"always ru"},{"text":"silent"},{"text":"as an m"}]},{"id":"af8f1085-bb69-5e19-ae29-69bf587f31f3","key":"angkrit-drill-02-sound","type":"sound","prompt":"How is ทราย read?","payload":{},"options":[{"text":"saai (ทร = s)","isCorrect":true},{"text":"traai"},{"text":"raai"},{"text":"thraai"}]},{"id":"ba849b95-0a06-5198-ae4d-75b04538f848","key":"angkrit-drill-03-sound","type":"sound","prompt":"What does the leading อ do in อยาก?","payload":{},"options":[{"text":"it is silent and makes ย mid class","isCorrect":true},{"text":"it adds an aw sound"},{"text":"it is a tone mark"},{"text":"it doubles the ย"}]},{"id":"6a5b1193-79a8-5594-a395-1d4df9cda6a1","key":"angkrit-drill-04-match","type":"match","prompt":"What does อังกฤษ mean?","payload":{},"options":[{"text":"England / English","isCorrect":true},{"text":"season"},{"text":"sand"},{"text":"to want"}]},{"id":"fa821315-1ddf-5f03-ac47-7d006d3d5cf6","key":"angkrit-drill-05-spot","type":"spot","prompt":"Which Thai spelling means \"England / English\"?","payload":{},"options":[{"text":"อังกฤษ","isCorrect":true},{"text":"อังกฤด"},{"text":"อักฤษ"},{"text":"กฤษอัง"}]}]}}'::jsonb, 'b820899e723cfde54e46b48b72e03377b99db04f28bb9778c0e633677bf5ef96', '2026-04-30T00:00:00+00:00'::timestamptz),
  ('5626619e-5360-5a2d-a97d-4cfa5ec83ef5'::uuid, '05ef7f1d-533e-5a74-afe1-17d35390fa15'::uuid, '7a7728f1-ad4d-565b-a8ce-96abcf166817'::uuid, 'khuat-archaic', 46, '{"course":{"id":"7bd9a3e7-a301-5ba5-a796-b90d39498730","slug":"thai","versionId":"92c6b63e-6aab-5f26-af3d-30738bdaaf37","displayVersion":"1.0.0"},"lesson":{"id":"7a7728f1-ad4d-565b-a8ce-96abcf166817","slug":"khuat-archaic","lessonOrdinal":46,"stage":14,"title":"ฃวด — Obsolete Glyphs (Recognition Only)","anchor":{"id":"fafa943c-7a2b-56d3-ae34-bfbea63ef035","slug":"khuat-archaic","text":"ฃวด","meaning":"bottle (archaic spelling of ขวด)","pronunciation":"khùuat","categoryKey":"daily","contextNote":"ฃวด is an old spelling of ขวด (bottle) using the obsolete ฃ. This closing lesson is recognition only: these glyphs no longer appear in modern Thai writing.","segments":[{"text":"ฃวด","sound":"khùuat"}]},"vocabulary":[{"roleKey":"practice_core","ordinalInRole":1,"isDrillTarget":false,"item":{"id":"14a37ae6-b8a3-52da-a25b-ff58da002f23","key":"word-0e24-0e45-0e29-0e35","text":"ฤๅษี","meaning":"hermit / rishi","pronunciation":"ruee-sǐi","categoryKey":"daily","segments":[{"text":"ฤๅ","sound":"ruee"},{"text":"ษี","sound":"sǐi"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":2,"isDrillTarget":false,"item":{"id":"8a92dbf1-5054-53f5-a5a4-6a75e342a6ee","key":"word-0e02-0e27-0e14","text":"ขวด","meaning":"bottle (modern spelling)","pronunciation":"khùuat","categoryKey":"daily","segments":[{"text":"ขวด","sound":"khùuat"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":3,"isDrillTarget":false,"item":{"id":"82c2d251-b647-51cf-aca6-5c0a1b320892","key":"word-0e25-0e36-0e01","text":"ลึก","meaning":"deep (modern spelling of ฦ words)","pronunciation":"lúek","categoryKey":"daily","segments":[{"text":"ลึก","sound":"lúek"}],"metadata":{"sourceType":"real"}}},{"roleKey":"practice_core","ordinalInRole":4,"isDrillTarget":false,"item":{"id":"c54be73c-10cb-5043-ab90-aa8b2bdd3c03","key":"word-0e25-0e37-0e2d","text":"ลือ","meaning":"to spread a rumor (modern ฦๅ)","pronunciation":"lue","categoryKey":"daily","segments":[{"text":"ลือ","sound":"lue"}],"metadata":{"sourceType":"real"}}}],"tips":[{"id":"sound-romanization","title":"Romanization","body":"This shows an approximate English spelling for the sound. Thai sounds don''t map perfectly to English letters, so treat this as a guide, not a rule. Listening is the best way to nail the exact sound."},{"id":"pronunciation-by-position","title":"Sound changes by position","body":"Thai consonants can sound different depending on where they appear in a syllable. The pronunciation shown here is the initial (leading) sound. When the same consonant closes a syllable, it often changes — for example, many consonants become a soft ''n'', ''m'', or stop sound at the end."},{"id":"consonant-class-tones","title":"Consonant class & tone","body":"Every Thai consonant belongs to one of three classes — low, mid, or high. The class of the opening consonant is the starting point for every tone rule in the language.","display":"modal","sections":[{"heading":"Think of it like three singers","body":"Imagine three singers — one with a naturally mid-range voice, one higher, one lower. Every Thai consonant is one of them.\n\nMid class (like ก, จ, ด): middle default tone.\nHigh class (like ข, ฉ, ถ): higher default tone.\nLow class (like ค, ง, น): lower default tone.\n\nThat \"natural voice\" is the consonant class. It sets the starting pitch for any syllable the consonant begins."},{"heading":"Why it changes the meaning of a word","body":"Two syllables can look nearly identical but mean completely different things — just because their opening consonant belongs to a different class.\n\nก (mid class) + า → กา \"crow\" → mid tone\nค (low class) + า → คา \"value / stuck\" → rising tone\n\nSame vowel, same length, different consonant class → different tone → different word."},{"heading":"Class is just the starting point","body":"Vowel length, the type of final consonant, and tone marks all layer on top of the class. But class comes first — miss it, and the rest of the tone rules won''t make sense.\n\nFor now, just learn each consonant''s class as you meet it. The tone patterns will click into place as you see more words."},{"heading":"For this card","body":"The class shown here is this letter''s class. When you see it open a real syllable, that class is your first clue about the syllable''s tone — before vowel length, finals, or marks come into play."}]},{"id":"letter-type-vowel","title":"Vowel","body":"Thai vowels are separate characters that attach to a consonant. Unlike English letters, they can appear above, below, to the left, or to the right of — or even wrapped around — their consonant. Visual order doesn''t always match reading order."},{"id":"letter-type-mark","title":"Written mark","body":"This is a written symbol that isn''t a consonant, vowel, or tone mark. Thai uses a few of these — for example ๆ repeats the preceding word, and ์ silences the consonant it sits above. Each one changes how you read the syllable rather than adding a sound of its own."},{"id":"vowel-position","title":"Vowel position","body":"Thai vowels don''t always sit where you expect. This vowel is written in a specific spot relative to its consonant — but when you read a word, you still pronounce the consonant first, then the vowel sound, regardless of visual position."}],"newGraphemes":[{"id":"9eca2c85-3646-5906-ab78-b6021420ca84","text":"ฃ","kind":"consonant","romanization":"kh","pronunciationHint":"obsolete high-class kh; modern Thai uses ข","mnemonic":"ฃ (khǎw khùuat, bottle) is obsolete. No modern words use it — ข took its place. Recognition only.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"68dc0b9d-7a4b-5ece-ad9c-9cafadbe0c14","text":"ฅ","kind":"consonant","romanization":"kh","pronunciationHint":"obsolete low-class kh; modern Thai uses ค","mnemonic":"ฅ (khaw khon, person) is obsolete. No modern words use it — ค took its place. Recognition only.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"81961b84-428a-54d1-ab21-a1ff5fb2590d","text":"ฤๅ","kind":"vowel","romanization":"ruee","pronunciationHint":"archaic long form of ฤ, read \"ruee\"","mnemonic":"ฤๅ is a rare long ฤ, seen in old literary words like ฤๅษี (ruee-sǐi, hermit). Recognition only.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel"},"tags":[]},{"id":"fc0403c2-5687-50cf-af07-c6812351422d","text":"ฦ","kind":"vowel","romanization":"lue","pronunciationHint":"obsolete lue; modern words use ลึ","mnemonic":"ฦ (lue) is obsolete. Modern words use ลึ instead (ลึก, deep). Recognition only.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel"},"tags":[]},{"id":"fc527aca-3764-523c-a8e3-331740672ce0","text":"ฦๅ","kind":"vowel","romanization":"luee","pronunciationHint":"obsolete long luee; modern words use ลือ","mnemonic":"ฦๅ (luee) is obsolete. Modern words use ลือ instead. Recognition only.","position":"standalone","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-vowel"},"tags":[]},{"id":"45c40f8f-fced-5ca7-a994-9805ac723344","text":"ๅ","kind":"mark","romanization":"(lengthener)","pronunciationHint":"lakkhangyao — lengthens ฤ or ฦ only; not a sound on its own","mnemonic":"ๅ (lakkhangyao) only stretches ฤ or ฦ into their long forms. It is never a sound by itself.","position":"right","details":{},"tipRefs":{"sound":"sound-romanization","type":"letter-type-mark","position":"vowel-position"},"tags":[]}],"reviewGraphemes":[{"id":"d9bb0ca4-5089-5ba0-aa79-1bdd09ba86ad","text":"ข","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the start of \"khaki\"","mnemonic":"ข is ข ไข่ (khor khai, egg). Picture the open curve as an eggshell; ไข่ starts with the puffed kh sound that separates ข from ก.","position":"standalone","details":{"class":"high"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"c40165fd-c08b-5e06-a932-28747ec7490c","text":"ค","kind":"consonant","romanization":"kh","pronunciationHint":"kh with a puff of air, like the \"c\" in \"cat\"","mnemonic":"ค is ค ควาย (khaw khwaai, buffalo). Picture a broad water buffalo; ค gives the same breathy kh as ข but belongs to the low class.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"5e1b543b-6be0-5279-a812-4ec61ce2b1dc","text":"ว","kind":"consonant","romanization":"w","pronunciationHint":"w as in \"water\"; can help form vowel glides","mnemonic":"ว is ว แหวน (wor waen, ring). The rounded curl looks like a ring, and แหวน gives you the w sound.","position":"standalone","details":{"class":"low"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]},{"id":"4cd66937-cf81-571b-ae18-6ae1055dd3ae","text":"ด","kind":"consonant","romanization":"d/t","pronunciationHint":"d as in \"dog\" at the start; clipped t at the end","mnemonic":"ด is ด เด็ก (dor dek, child). Picture the loop as a child''s round head beside a small body; ด starts words with d and closes as t.","position":"standalone","details":{"class":"mid"},"tipRefs":{"sound":"sound-romanization","pronunciation":"pronunciation-by-position","type":"consonant-class-tones"},"tags":[]}],"rules":[{"id":"fd9b7b30-70ed-5947-a0b8-616ac698d395","key":"archaic-recognition","name":"These Glyphs Are Obsolete","shortDescription":"ฃ, ฅ, ฦ, ฦๅ, and ฤๅ no longer appear in modern Thai","explanation":"You only need to recognize these, not decode them in daily reading. ฃ became ข and ฅ became ค; ฦ and ฦๅ were replaced by ลึ and ลือ; ฤๅ survives only in rare literary words.","examples":[{"text":"ฃวด → ขวด"},{"text":"ฅน → คน"}]}],"drills":[{"id":"9889f2a5-896c-5af6-abd7-4cab6d8f1879","key":"khuat-archaic-drill-01-sound","type":"sound","prompt":"The obsolete ฃ was replaced by which letter?","payload":{},"options":[{"text":"ข","isCorrect":true},{"text":"ค"},{"text":"ก"},{"text":"ง"}]},{"id":"35f605e8-f0a2-56bf-a8af-cdb6d2efd9c2","key":"khuat-archaic-drill-02-sound","type":"sound","prompt":"The obsolete ฅ was replaced by which letter?","payload":{},"options":[{"text":"ค","isCorrect":true},{"text":"ข"},{"text":"ก"},{"text":"จ"}]},{"id":"98aef900-c4f3-55f5-a139-f7e49622f7dd","key":"khuat-archaic-drill-03-sound","type":"sound","prompt":"Do these glyphs appear in modern Thai?","payload":{},"options":[{"text":"no — recognition only","isCorrect":true},{"text":"yes, everywhere"},{"text":"only in numbers"},{"text":"only in tone marks"}]},{"id":"b24868d5-e639-5b11-ab32-140592ad7cd8","key":"khuat-archaic-drill-04-match","type":"match","prompt":"What does the archaic ฃวด spell?","payload":{},"options":[{"text":"bottle (now ขวด)","isCorrect":true},{"text":"person (now คน)"},{"text":"hermit"},{"text":"deep"}]},{"id":"ad7a0ea5-5079-5a56-a5ce-31254eb858c6","key":"khuat-archaic-drill-05-recognize","type":"recognize","prompt":"Which pair are the obsolete kh letters?","payload":{},"options":[{"text":"ฃ and ฅ","isCorrect":true},{"text":"ข and ค"},{"text":"ก and ง"},{"text":"ฆ and ฅ"}]}]}}'::jsonb, 'e148a3a37caaa01823b456ea1fa1e779be06b9c94c08ab203c914083a4e0aa2a', '2026-04-30T00:00:00+00:00'::timestamptz);

